#include "biblia.h"

void Biblia::CarregarLucas(Biblia* b) {
    b->dados[LUCAS].nome = wxT("Lucas");

    b->dados[LUCAS].capitulos[1].versos[1] = wxT("Visto que muitos têm empreendido fazer uma narração coordenada dos fatos que entre nós se realizaram,");
    b->dados[LUCAS].capitulos[1].versos[2] = wxT("segundo no-los transmitiram os que desde o princípio foram testemunhas oculares e ministros da palavra,");
    b->dados[LUCAS].capitulos[1].versos[3] = wxT("também a mim, depois de haver investido tudo cuidadosamente desde o começo, pareceu-me bem, ó excelentíssimo Teófilo, escrever-te uma narração em ordem.");
    b->dados[LUCAS].capitulos[1].versos[4] = wxT("para que conheças plenamente a verdade das coisas em que foste instruído.");
    b->dados[LUCAS].capitulos[1].versos[5] = wxT("Houve nos dias do Rei Herodes, rei da Judéia, um sacerdote chamado Zacarias, da turma de Abias; e sua mulher era descendente de Arão, e chamava-se Isabel.");
    b->dados[LUCAS].capitulos[1].versos[6] = wxT("Ambos eram justos diante de Deus, andando irrepreensíveis em todos os mandamentos e preceitos do Senhor.");
    b->dados[LUCAS].capitulos[1].versos[7] = wxT("Mas não tinham filhos, porque Isabel era estéril, e ambos avançados em idade.");
    b->dados[LUCAS].capitulos[1].versos[8] = wxT("Ora, estando ele a exercer as funções sacerdotais perante Deus, na ordem da sua turma,");
    b->dados[LUCAS].capitulos[1].versos[9] = wxT("segundo o costume do sacerdócio, coube-lhe por sorte entrar no santuário do Senhor, para oferecer o incenso;");
    b->dados[LUCAS].capitulos[1].versos[10] = wxT("e toda a multidão do povo orava da parte de fora, à hora do incenso.");
    b->dados[LUCAS].capitulos[1].versos[11] = wxT("Apareceu-lhe, então, um anjo do Senhor, em pé à direita do altar do incenso.");
    b->dados[LUCAS].capitulos[1].versos[12] = wxT("E Zacarias, vendo-o, ficou turbado, e o temor o assaltou.");
    b->dados[LUCAS].capitulos[1].versos[13] = wxT("Mas o anjo lhe disse: Não temais, Zacarias; porque a tua oração foi ouvida, e Isabel, tua mulher, te dará à luz um filho, e lhe porás o nome de João;");
    b->dados[LUCAS].capitulos[1].versos[14] = wxT("e terás alegria e regozijo, e muitos se alegrarão com o seu nascimento;");
    b->dados[LUCAS].capitulos[1].versos[15] = wxT("porque ele será grande diante do Senhor; não beberá vinho, nem bebida forte; e será cheio do Espírito Santo já desde o ventre de sua mãe;");
    b->dados[LUCAS].capitulos[1].versos[16] = wxT("converterá muitos dos filhos de Israel ao Senhor seu Deus;");
    b->dados[LUCAS].capitulos[1].versos[17] = wxT("irá adiante dele no espírito e poder de Elias, para converter os corações dos pais aos filhos, e os rebeldes à prudência dos justos, a fim de preparar para o Senhor um povo apercebido.");
    b->dados[LUCAS].capitulos[1].versos[18] = wxT("Disse então Zacarias ao anjo: Como terei certeza disso? pois eu sou velho, e minha mulher também está avançada em idade.");
    b->dados[LUCAS].capitulos[1].versos[19] = wxT("Ao que lhe respondeu o anjo: Eu sou Gabriel, que assisto diante de Deus, e fui enviado para te falar e te dar estas boas novas;");
    b->dados[LUCAS].capitulos[1].versos[20] = wxT("e eis que ficarás mudo, e não poderás falar até o dia em que estas coisas aconteçam; porquanto não creste nas minhas palavras, que a seu tempo hão de cumprir-se.");
    b->dados[LUCAS].capitulos[1].versos[21] = wxT("O povo estava esperando Zacarias, e se admirava da sua demora no santuário.");
    b->dados[LUCAS].capitulos[1].versos[22] = wxT("Quando saiu, porém, não lhes podia falar, e perceberam que tivera uma visão no santuário. E falava-lhes por acenos, mas permanecia mudo.");
    b->dados[LUCAS].capitulos[1].versos[23] = wxT("E, terminados os dias do seu ministério, voltou para casa.");
    b->dados[LUCAS].capitulos[1].versos[24] = wxT("Depois desses dias Isabel, sua mulher, concebeu, e por cinco meses se ocultou, dizendo:");
    b->dados[LUCAS].capitulos[1].versos[25] = wxT("Assim me fez o Senhor nos dias em que atentou para mim, a fim de acabar com o meu opróbrio diante dos homens.");
    b->dados[LUCAS].capitulos[1].versos[26] = wxT("Ora, no sexto mês, foi o anjo Gabriel enviado por Deus a uma cidade da Galiléia, chamada Nazaré,");
    b->dados[LUCAS].capitulos[1].versos[27] = wxT("a uma virgem desposada com um varão cujo nome era José, da casa de Davi; e o nome da virgem era Maria.");
    b->dados[LUCAS].capitulos[1].versos[28] = wxT("E, entrando o anjo onde ela estava disse: Salve, agraciada; o Senhor é contigo.");
    b->dados[LUCAS].capitulos[1].versos[29] = wxT("Ela, porém, ao ouvir estas palavras, turbou-se muito e pôs-se a pensar que saudação seria essa.");
    b->dados[LUCAS].capitulos[1].versos[30] = wxT("Disse-lhe então o anjo: Não temas, Maria; pois achaste graça diante de Deus.");
    b->dados[LUCAS].capitulos[1].versos[31] = wxT("Eis que conceberás e darás à luz um filho, ao qual porás o nome de Jesus.");
    b->dados[LUCAS].capitulos[1].versos[32] = wxT("Este será grande e será chamado filho do Altíssimo; o Senhor Deus lhe dará o trono de Davi seu pai;");
    b->dados[LUCAS].capitulos[1].versos[33] = wxT("e reinará eternamente sobre a casa de Jacó, e o seu reino não terá fim.");
    b->dados[LUCAS].capitulos[1].versos[34] = wxT("Então Maria perguntou ao anjo: Como se fará isso, uma vez que não conheço varão?");
    b->dados[LUCAS].capitulos[1].versos[35] = wxT("Respondeu-lhe o anjo: Virá sobre ti o Espírito Santo, e o poder do Altíssimo te cobrirá com a sua sombra; por isso o que há de nascer será chamado santo, Filho de Deus.");
    b->dados[LUCAS].capitulos[1].versos[36] = wxT("Eis que também Isabel, tua parenta concebeu um filho em sua velhice; e é este o sexto mês para aquela que era chamada estéril;");
    b->dados[LUCAS].capitulos[1].versos[37] = wxT("porque para Deus nada será impossível.");
    b->dados[LUCAS].capitulos[1].versos[38] = wxT("Disse então Maria. Eis aqui a serva do Senhor; cumpra-se em mim segundo a tua palavra. E o anjo ausentou-se dela.");
    b->dados[LUCAS].capitulos[1].versos[39] = wxT("Naqueles dias levantou-se Maria, foi apressadamente à região montanhosa, a uma cidade de Judá,");
    b->dados[LUCAS].capitulos[1].versos[40] = wxT("entrou em casa de Zacarias e saudou a Isabel.");
    b->dados[LUCAS].capitulos[1].versos[41] = wxT("Ao ouvir Isabel a saudação de Maria, saltou a criancinha no seu ventre, e Isabel ficou cheia do Espírito Santo,");
    b->dados[LUCAS].capitulos[1].versos[42] = wxT("e exclamou em alta voz: Bendita és tu entre as mulheres, e bendito é o fruto do teu ventre!");
    b->dados[LUCAS].capitulos[1].versos[43] = wxT("E donde me provém isto, que venha visitar-me a mãe do meu Senhor?");
    b->dados[LUCAS].capitulos[1].versos[44] = wxT("Pois logo que me soou aos ouvidos a voz da tua saudação, a criancinha saltou de alegria dentro de mim.");
    b->dados[LUCAS].capitulos[1].versos[45] = wxT("Bem-aventurada aquela que creu que se hão de cumprir as coisas que da parte do Senhor lhe foram ditas.");
    b->dados[LUCAS].capitulos[1].versos[46] = wxT("Disse então Maria: A minha alma engrandece ao Senhor,");
    b->dados[LUCAS].capitulos[1].versos[47] = wxT("e o meu espírito exulta em Deus meu Salvador;");
    b->dados[LUCAS].capitulos[1].versos[48] = wxT("porque atentou na condição humilde de sua serva. Desde agora, pois, todas as gerações me chamarão bem-aventurada,");
    b->dados[LUCAS].capitulos[1].versos[49] = wxT("porque o Poderoso me fez grandes coisas; e santo é o seu nome.");
    b->dados[LUCAS].capitulos[1].versos[50] = wxT("E a sua misericórdia vai de geração em geração sobre os que o temem.");
    b->dados[LUCAS].capitulos[1].versos[51] = wxT("Com o seu braço manifestou poder; dissipou os que eram soberbos nos pensamentos de seus corações;");
    b->dados[LUCAS].capitulos[1].versos[52] = wxT("depôs dos tronos os poderosos, e elevou os humildes.");
    b->dados[LUCAS].capitulos[1].versos[53] = wxT("Aos famintos encheu de bens, e vazios despediu os ricos.");
    b->dados[LUCAS].capitulos[1].versos[54] = wxT("Auxiliou a Isabel, seu servo, lembrando-se de misericórdia");
    b->dados[LUCAS].capitulos[1].versos[55] = wxT("{como falou a nossos pais} para com Abraão e a sua descendência para sempre.");
    b->dados[LUCAS].capitulos[1].versos[56] = wxT("E Maria ficou com ela cerca de três meses; e depois voltou para sua casa.");
    b->dados[LUCAS].capitulos[1].versos[57] = wxT("Ora, completou-se para Isabel o tempo de dar à luz, e teve um filho.");
    b->dados[LUCAS].capitulos[1].versos[58] = wxT("Ouviram seus vizinhos e parentes que o Senhor lhe multiplicara a sua misericórdia, e se alegravam com ela.");
    b->dados[LUCAS].capitulos[1].versos[59] = wxT("Sucedeu, pois, no oitavo dia, que vieram circuncidar o menino; e queriam dar-lhe o nome de seu pai, Zacarias.");
    b->dados[LUCAS].capitulos[1].versos[60] = wxT("Respondeu, porém, sua mãe: De modo nenhum, mas será chamado João.");
    b->dados[LUCAS].capitulos[1].versos[61] = wxT("Ao que lhe disseram: Ninguém há na tua parentela que se chame por este nome.");
    b->dados[LUCAS].capitulos[1].versos[62] = wxT("E perguntaram por acenos ao pai como queria que se chamasse.");
    b->dados[LUCAS].capitulos[1].versos[63] = wxT("E pedindo ele uma tabuinha, escreveu: Seu nome é João. E todos se admiraram.");
    b->dados[LUCAS].capitulos[1].versos[64] = wxT("Imediatamente a boca se lhe abriu, e a língua se lhe soltou; louvando a Deus.");
    b->dados[LUCAS].capitulos[1].versos[65] = wxT("Então veio temor sobre todos os seus vizinhos; e em toda a região montanhosa da Judéia foram divulgadas todas estas coisas.");
    b->dados[LUCAS].capitulos[1].versos[66] = wxT("E todos os que delas souberam as guardavam no coração, dizendo: Que virá a ser, então, este menino? Pois a mão do Senhor estava com ele.");
    b->dados[LUCAS].capitulos[1].versos[67] = wxT("Zacarias, seu pai, ficou cheio do Espírito Santo e profetizou, dizendo:");
    b->dados[LUCAS].capitulos[1].versos[68] = wxT("Bendito, seja o Senhor Deus de Israel, porque visitou e remiu o seu povo,");
    b->dados[LUCAS].capitulos[1].versos[69] = wxT("e para nós fez surgir uma salvação poderosa na casa de Davi, seu servo;");
    b->dados[LUCAS].capitulos[1].versos[70] = wxT("assim como desde os tempos antigos tem anunciado pela boca dos seus santos profetas;");
    b->dados[LUCAS].capitulos[1].versos[71] = wxT("para nos livrar dos nossos inimigos e da mão de todos os que nos odeiam;");
    b->dados[LUCAS].capitulos[1].versos[72] = wxT("para usar de misericórdia com nossos pais, e lembrar-se do seu santo pacto");
    b->dados[LUCAS].capitulos[1].versos[73] = wxT("e do juramento que fez a Abrão, nosso pai,");
    b->dados[LUCAS].capitulos[1].versos[74] = wxT("de conceder-nos que, libertados da mão de nossos inimigos, o servíssemos sem temor,");
    b->dados[LUCAS].capitulos[1].versos[75] = wxT("em santidade e justiça perante ele, todos os dias da nossa vida.");
    b->dados[LUCAS].capitulos[1].versos[76] = wxT("E tu, menino, serás chamado profeta do Altíssimo, porque irás ante a face do Senhor, a preparar os seus caminhos;");
    b->dados[LUCAS].capitulos[1].versos[77] = wxT("para dar ao seu povo conhecimento da salvação, na remissão dos seus pecados,");
    b->dados[LUCAS].capitulos[1].versos[78] = wxT("graças à entranhável misericórdia do nosso Deus, pela qual nos há de visitar a aurora lá do alto,");
    b->dados[LUCAS].capitulos[1].versos[79] = wxT("para alumiar aos que jazem nas trevas e na sombra da morte, a fim de dirigir os nossos pés no caminho da paz.");
    b->dados[LUCAS].capitulos[1].versos[80] = wxT("Ora, o menino crescia, e se robustecia em espírito; e habitava nos desertos até o dia da sua manifestação a Israel.");

    b->dados[LUCAS].capitulos[2].versos[1] = wxT("Naqueles dias saiu um decreto da parte de César Augusto, para que todo o mundo fosse recenseado.");
    b->dados[LUCAS].capitulos[2].versos[2] = wxT("Este primeiro recenseamento foi feito quando Quirínio era governador da Síria.");
    b->dados[LUCAS].capitulos[2].versos[3] = wxT("E todos iam alistar-se, cada um à sua própria cidade.");
    b->dados[LUCAS].capitulos[2].versos[4] = wxT("Subiu também José, da Galiléia, da cidade de Nazaré, à cidade de Davi, chamada Belém, porque era da casa e família de Davi,");
    b->dados[LUCAS].capitulos[2].versos[5] = wxT("a fim de alistar-se com Maria, sua esposa, que estava grávida.");
    b->dados[LUCAS].capitulos[2].versos[6] = wxT("Enquanto estavam ali, chegou o tempo em que ela havia de dar à luz,");
    b->dados[LUCAS].capitulos[2].versos[7] = wxT("e teve a seu filho primogênito; envolveu-o em faixas e o deitou em uma manjedoura, porque não havia lugar para eles na estalagem.");
    b->dados[LUCAS].capitulos[2].versos[8] = wxT("Ora, havia naquela mesma região pastores que estavam no campo, e guardavam durante as vigílias da noite o seu rebanho.");
    b->dados[LUCAS].capitulos[2].versos[9] = wxT("E um anjo do Senhor apareceu-lhes, e a glória do Senhor os cercou de resplendor; pelo que se encheram de grande temor.");
    b->dados[LUCAS].capitulos[2].versos[10] = wxT("O anjo, porém, lhes disse: Não temais, porquanto vos trago novas de grande alegria que o será para todo o povo:");
    b->dados[LUCAS].capitulos[2].versos[11] = wxT("É que vos nasceu hoje, na cidade de Davi, o Salvador, que é Cristo, o Senhor.");
    b->dados[LUCAS].capitulos[2].versos[12] = wxT("E isto vos será por sinal: Achareis um menino envolto em faixas, e deitado em uma manjedoura.");
    b->dados[LUCAS].capitulos[2].versos[13] = wxT("Então, de repente, apareceu junto ao anjo grande multidão da milícia celestial, louvando a Deus e dizendo:");
    b->dados[LUCAS].capitulos[2].versos[14] = wxT("Glória a Deus nas maiores alturas, e paz na terra entre os homens de boa vontade.");
    b->dados[LUCAS].capitulos[2].versos[15] = wxT("E logo que os anjos se retiraram deles para o céu, diziam os pastores uns aos outros: Vamos já até Belém, e vejamos isso que aconteceu e que o Senhor nos deu a conhecer.");
    b->dados[LUCAS].capitulos[2].versos[16] = wxT("Foram, pois, a toda a pressa, e acharam Maria e José, e o menino deitado na manjedoura;");
    b->dados[LUCAS].capitulos[2].versos[17] = wxT("e, vendo-o, divulgaram a palavra que acerca do menino lhes fora dita;");
    b->dados[LUCAS].capitulos[2].versos[18] = wxT("e todos os que a ouviram se admiravam do que os pastores lhes diziam.");
    b->dados[LUCAS].capitulos[2].versos[19] = wxT("Maria, porém, guardava todas estas coisas, meditando-as em seu coração.");
    b->dados[LUCAS].capitulos[2].versos[20] = wxT("E voltaram os pastores, glorificando e louvando a Deus por tudo o que tinham ouvido e visto, como lhes fora dito.");
    b->dados[LUCAS].capitulos[2].versos[21] = wxT("Quando se completaram os oito dias para ser circuncidado o menino, foi-lhe dado o nome de Jesus, que pelo anjo lhe fora posto antes de ser concebido.");
    b->dados[LUCAS].capitulos[2].versos[22] = wxT("Terminados os dias da purificação, segundo a lei de Moisés, levaram-no a Jerusalém, para apresentá-lo ao Senhor");
    b->dados[LUCAS].capitulos[2].versos[23] = wxT("{conforme está escrito na lei do Senhor: Todo primogênito será consagrado ao Senhor},");
    b->dados[LUCAS].capitulos[2].versos[24] = wxT("e para oferecerem um sacrifício segundo o disposto na lei do Senhor: um par de rolas, ou dois pombinhos.");
    b->dados[LUCAS].capitulos[2].versos[25] = wxT("Ora, havia em Jerusalém um homem cujo nome era Simeão; e este homem, justo e temente a Deus, esperava a consolação de Israel; e o Espírito Santo estava sobre ele.");
    b->dados[LUCAS].capitulos[2].versos[26] = wxT("E lhe fora revelado pelo Espírito Santo que ele não morreria antes de ver o Cristo do Senhor.");
    b->dados[LUCAS].capitulos[2].versos[27] = wxT("Assim pelo Espírito foi ao templo; e quando os pais trouxeram o menino Jesus, para fazerem por ele segundo o costume da lei,");
    b->dados[LUCAS].capitulos[2].versos[28] = wxT("Simeão o tomou em seus braços, e louvou a Deus, e disse:");
    b->dados[LUCAS].capitulos[2].versos[29] = wxT("Agora, Senhor, despedes em paz o teu servo, segundo a tua palavra;");
    b->dados[LUCAS].capitulos[2].versos[30] = wxT("pois os meus olhos já viram a tua salvação,");
    b->dados[LUCAS].capitulos[2].versos[31] = wxT("a qual tu preparaste ante a face de todos os povos;");
    b->dados[LUCAS].capitulos[2].versos[32] = wxT("luz para revelação aos gentios, e para glória do teu povo Israel.");
    b->dados[LUCAS].capitulos[2].versos[33] = wxT("Enquanto isso, seu pai e sua mãe se admiravam das coisas que deles se diziam.");
    b->dados[LUCAS].capitulos[2].versos[34] = wxT("E Simeão os abençoou, e disse a Maria, mãe do menino: Eis que este é posto para queda e para levantamento de muitos em Israel, e para ser alvo de contradição,");
    b->dados[LUCAS].capitulos[2].versos[35] = wxT("sim, e uma espada traspassará a tua própria alma, para que se manifestem os pensamentos de muitos corações.");
    b->dados[LUCAS].capitulos[2].versos[36] = wxT("Havia também uma profetisa, Ana, filha de Fanuel, da tribo de Aser. Era já avançada em idade, tendo vivido com o marido sete anos desde a sua virgindade;");
    b->dados[LUCAS].capitulos[2].versos[37] = wxT("e era viúva, de quase oitenta e quatro anos. Não se afastava do templo, servindo a Deus noite e dia em jejuns e orações.");
    b->dados[LUCAS].capitulos[2].versos[38] = wxT("Chegando ela na mesma hora, deu graças a Deus, e falou a respeito do menino a todos os que esperavam a redenção de Jerusalém.");
    b->dados[LUCAS].capitulos[2].versos[39] = wxT("Assim que cumpriram tudo segundo a lei do Senhor, voltaram à Galiléia, para sua cidade de Nazaré.");
    b->dados[LUCAS].capitulos[2].versos[40] = wxT("E o menino ia crescendo e fortalecendo-se, ficando cheio de sabedoria; e a graça de Deus estava sobre ele.");
    b->dados[LUCAS].capitulos[2].versos[41] = wxT("Ora, seus pais iam todos os anos a Jerusalém, à festa da páscoa.");
    b->dados[LUCAS].capitulos[2].versos[42] = wxT("Quando Jesus completou doze anos, subiram eles segundo o costume da festa;");
    b->dados[LUCAS].capitulos[2].versos[43] = wxT("e, terminados aqueles dias, ao regressarem, ficou o menino Jesus em Jerusalém sem o saberem seus pais;");
    b->dados[LUCAS].capitulos[2].versos[44] = wxT("julgando, porém, que estivesse entre os companheiros de viagem, andaram caminho de um dia, e o procuravam entre os parentes e conhecidos;");
    b->dados[LUCAS].capitulos[2].versos[45] = wxT("e não o achando, voltaram a Jerusalém em busca dele.");
    b->dados[LUCAS].capitulos[2].versos[46] = wxT("E aconteceu que, passados três dias, o acharam no templo, sentado no meio dos doutores, ouvindo-os, e interrogando-os.");
    b->dados[LUCAS].capitulos[2].versos[47] = wxT("E todos os que o ouviam se admiravam da sua inteligência e das suas respostas.");
    b->dados[LUCAS].capitulos[2].versos[48] = wxT("Quando o viram, ficaram maravilhados, e disse-lhe sua mãe: Filho, por que procedeste assim para conosco? Eis que teu pai e eu ansiosos te procurávamos.");
    b->dados[LUCAS].capitulos[2].versos[49] = wxT("Respondeu-lhes ele: Por que me procuráveis? Não sabíeis que eu devia estar na casa de meu Pai?");
    b->dados[LUCAS].capitulos[2].versos[50] = wxT("Eles, porém, não entenderam as palavras que lhes dissera.");
    b->dados[LUCAS].capitulos[2].versos[51] = wxT("Então, descendo com eles, foi para Nazaré, e era-lhes sujeito. E sua mãe guardava todas estas coisas em seu coração.");
    b->dados[LUCAS].capitulos[2].versos[52] = wxT("E crescia Jesus em sabedoria, em estatura e em graça diante de Deus e dos homens.");

    b->dados[LUCAS].capitulos[3].versos[1] = wxT("No décimo quinto ano do reinado de Tibério César, sendo Pôncio Pilatos governador da Judéia, Herodes tetrarca da Galiléia, seu irmão Filipe tetrarca da região da Ituréia e de Traconites, e Lisânias tetrarca de Abilene,");
    b->dados[LUCAS].capitulos[3].versos[2] = wxT("sendo Anás e Caifás sumos sacerdotes, veio a palavra de Deus a João, filho de Zacarias, no deserto.");
    b->dados[LUCAS].capitulos[3].versos[3] = wxT("E ele percorreu toda a circunvizinhança do Jordão, pregando o batismo de arrependimento para remissão de pecados;");
    b->dados[LUCAS].capitulos[3].versos[4] = wxT("como está escrito no livro das palavras do profeta Isaías: Voz do que clama no deserto: Preparai o caminho do Senhor; endireitai as suas veredas.");
    b->dados[LUCAS].capitulos[3].versos[5] = wxT("Todo vale se encherá, e se abaixará todo monte e outeiro; o que é tortuoso se endireitará, e os caminhos escabrosos se aplanarão;");
    b->dados[LUCAS].capitulos[3].versos[6] = wxT("e toda a carne verá a salvação de Deus.");
    b->dados[LUCAS].capitulos[3].versos[7] = wxT("João dizia, pois, às multidões que saíam para ser batizadas por ele: Raça de víboras, quem vos ensina a fugir da ira vindoura?");
    b->dados[LUCAS].capitulos[3].versos[8] = wxT("Produzi, pois, frutos dignos de arrependimento; e não comeceis a dizer em vós mesmos: Temos por pai a Abrão; porque eu vos digo que até destas pedras Deus pode suscitar filhos a Abrão.");
    b->dados[LUCAS].capitulos[3].versos[9] = wxT("Também já está posto o machado à raiz das árvores; toda árvore, pois, que não produz bom fruto, é cortada e lançada no fogo.");
    b->dados[LUCAS].capitulos[3].versos[10] = wxT("Ao que lhe perguntavam as multidões: Que faremos, pois?");
    b->dados[LUCAS].capitulos[3].versos[11] = wxT("Respondia-lhes então: Aquele que tem duas túnicas, reparta com o que não tem nenhuma, e aquele que tem alimentos, faça o mesmo.");
    b->dados[LUCAS].capitulos[3].versos[12] = wxT("Chegaram também uns publicanos para serem batizados, e perguntaram-lhe: Mestre, que havemos nós de fazer?");
    b->dados[LUCAS].capitulos[3].versos[13] = wxT("Respondeu-lhes ele: Não cobreis além daquilo que vos foi prescrito.");
    b->dados[LUCAS].capitulos[3].versos[14] = wxT("Interrogaram-no também uns soldados: E nós, que faremos? Disse-lhes: A ninguém queirais extorquir coisa alguma; nem deis denúncia falsa; e contentai-vos com o vosso soldo.");
    b->dados[LUCAS].capitulos[3].versos[15] = wxT("Ora, estando o povo em expectativa e arrazoando todos em seus corações a respeito de João, se porventura seria ele o Cristo,");
    b->dados[LUCAS].capitulos[3].versos[16] = wxT("respondeu João a todos, dizendo: Eu, na verdade, vos batizo em água, mas vem aquele que é mais poderoso do que eu, de quem não sou digno de desatar a correia das alparcas; ele vos batizará no Espírito Santo e em fogo.");
    b->dados[LUCAS].capitulos[3].versos[17] = wxT("A sua pá ele tem na mão para limpar bem a sua eira, e recolher o trigo ao seu celeiro; mas queimará a palha em fogo inextinguível.");
    b->dados[LUCAS].capitulos[3].versos[18] = wxT("Assim pois, com muitas outras exortações ainda, anunciava o evangelho ao povo.");
    b->dados[LUCAS].capitulos[3].versos[19] = wxT("Mas o tetrarca Herodes, sendo repreendido por ele por causa de Herodias, mulher de seu irmão, e por todas as maldades que havia feito,");
    b->dados[LUCAS].capitulos[3].versos[20] = wxT("acrescentou a todas elas ainda esta, a de encerrar João no cárcere.");
    b->dados[LUCAS].capitulos[3].versos[21] = wxT("Quando todo o povo fora batizado, tendo sido Jesus também batizado, e estando ele a orar, o céu se abriu;");
    b->dados[LUCAS].capitulos[3].versos[22] = wxT("e o Espírito Santo desceu sobre ele em forma corpórea, como uma pomba; e ouviu-se do céu esta voz: Tu és o meu Filho amado; em ti me comprazo.");
    b->dados[LUCAS].capitulos[3].versos[23] = wxT("Ora, Jesus, ao começar o seu ministério, tinha cerca de trinta anos; sendo {como se cuidava} filho de José, filho de Eli;");
    b->dados[LUCAS].capitulos[3].versos[24] = wxT("Eli de Matate, Matate de Levi, Levi de Melqui, Melqui de Janai, Janai de José,");
    b->dados[LUCAS].capitulos[3].versos[25] = wxT("José de Matatias, Matatias de Amós, Amós de Naum, Naum de Esli, Esli de Nagai,");
    b->dados[LUCAS].capitulos[3].versos[26] = wxT("Nagai de Maate, Maate de Matatias, Matatias de Semei, Semei de Joseque, Joseque de Jodá,");
    b->dados[LUCAS].capitulos[3].versos[27] = wxT("Jodá de Joanã, Joanã de Resa, Resa de Zorobabel, Zorobabel de Salatiel, Salatiel de Neri,");
    b->dados[LUCAS].capitulos[3].versos[28] = wxT("Neri de Melqui, Melqui de Adi, Adi de Cosão, Cosão de Elmodã, Elmodão de Er,");
    b->dados[LUCAS].capitulos[3].versos[29] = wxT("Er de Josué, Josué de Eliézer, Eliézer de Jorim, Jorim de Matate, Matate de Levi,");
    b->dados[LUCAS].capitulos[3].versos[30] = wxT("Levi de Simeão, Simeão de Judá, Judá de José, José de Jonã, Jonã de Eliaquim,");
    b->dados[LUCAS].capitulos[3].versos[31] = wxT("Eliaquim de Meleá, Meleá de Mená, Mená de Matatá, Matatá de Natã, Natã de Davi,");
    b->dados[LUCAS].capitulos[3].versos[32] = wxT("Davi de Jessé, Jessé de Obede, Obede de Boaz, Boaz de Salá, Salá de Nasom,");
    b->dados[LUCAS].capitulos[3].versos[33] = wxT("Nasom de Aminadabe, Aminadabe de Admim, Admim de Arni, Arni de Esrom, Esrom de Farés, Farés de Judá,");
    b->dados[LUCAS].capitulos[3].versos[34] = wxT("Judá de Jacó, Jacó de Isaque, Isaque de Abraão, Abraão de Tará, Tará de Naor,");
    b->dados[LUCAS].capitulos[3].versos[35] = wxT("Naor de Seruque, Seruque de Ragaú, Ragaú de Faleque, Faleque de Eber, Eber de Salá,");
    b->dados[LUCAS].capitulos[3].versos[36] = wxT("Salá de Cainã, Cainã de Arfaxade, Arfaxade de Sem, Sem de Noé, Noé de Lameque,");
    b->dados[LUCAS].capitulos[3].versos[37] = wxT("Lameque de Matusalém, Matusalém de Enoque, Enoque de Jarede, Jarede de Maleleel, Maleleel de Cainã,");
    b->dados[LUCAS].capitulos[3].versos[38] = wxT("Cainã de Enos, Enos de Sete, Sete de Adão, e Adão de Deus.");

    b->dados[LUCAS].capitulos[4].versos[1] = wxT("Jesus, pois, cheio do Espírito Santo, voltou do Jordão; e era levado pelo Espírito no deserto,");
    b->dados[LUCAS].capitulos[4].versos[2] = wxT("durante quarenta dias, sendo tentado pelo Diabo. E naqueles dias não comeu coisa alguma; e terminados eles, teve fome.");
    b->dados[LUCAS].capitulos[4].versos[3] = wxT("Disse-lhe então o Diabo: Se tu és Filho de Deus, manda a esta pedra que se torne em pão.");
    b->dados[LUCAS].capitulos[4].versos[4] = wxT("Jesus, porém, lhe respondeu: Está escrito: Nem só de pão viverá o homem.");
    b->dados[LUCAS].capitulos[4].versos[5] = wxT("Então o Diabo, levando-o a um lugar elevado, mostrou-lhe num relance todos os reinos do mundo.");
    b->dados[LUCAS].capitulos[4].versos[6] = wxT("E disse-lhe: Dar-te-ei toda a autoridade e glória destes reinos, porque me foi entregue, e a dou a quem eu quiser;");
    b->dados[LUCAS].capitulos[4].versos[7] = wxT("se tu, me adorares, será toda tua.");
    b->dados[LUCAS].capitulos[4].versos[8] = wxT("Respondeu-lhe Jesus: Está escrito: Ao Senhor teu Deus adorarás, e só a ele servirás.");
    b->dados[LUCAS].capitulos[4].versos[9] = wxT("Então o levou a Jerusalém e o colocou sobre o pináculo do templo e lhe disse: Se tu és Filho de Deus, lança-te daqui abaixo;");
    b->dados[LUCAS].capitulos[4].versos[10] = wxT("porque está escrito: Aos seus anjos ordenará a teu respeito, que te guardem;");
    b->dados[LUCAS].capitulos[4].versos[11] = wxT("e: eles te susterão nas mãos, para que nunca tropeces em alguma pedra.");
    b->dados[LUCAS].capitulos[4].versos[12] = wxT("Respondeu-lhe Jesus: Dito está: Não tentarás o Senhor teu Deus.");
    b->dados[LUCAS].capitulos[4].versos[13] = wxT("Assim, tendo o Diabo acabado toda sorte de tentação, retirou-se dele até ocasião oportuna.");
    b->dados[LUCAS].capitulos[4].versos[14] = wxT("Então voltou Jesus para a Galiléia no poder do Espírito; e a sua fama correu por toda a circunvizinhança.");
    b->dados[LUCAS].capitulos[4].versos[15] = wxT("Ensinava nas sinagogas deles, e por todos era louvado.");
    b->dados[LUCAS].capitulos[4].versos[16] = wxT("Chegando a Nazaré, onde fora criado; entrou na sinagoga no dia de sábado, segundo o seu costume, e levantou-se para ler.");
    b->dados[LUCAS].capitulos[4].versos[17] = wxT("Foi-lhe entregue o livro do profeta Isaías; e abrindo-o, achou o lugar em que estava escrito:");
    b->dados[LUCAS].capitulos[4].versos[18] = wxT("O Espírito do Senhor está sobre mim, porquanto me ungiu para anunciar boas novas aos pobres; enviou-me para proclamar libertação aos cativos, e restauração da vista aos cegos, para pôr em liberdade os oprimidos,");
    b->dados[LUCAS].capitulos[4].versos[19] = wxT("e para proclamar o ano aceitável do Senhor.");
    b->dados[LUCAS].capitulos[4].versos[20] = wxT("E fechando o livro, devolveu-o ao assistente e sentou-se; e os olhos de todos na sinagoga estavam fitos nele.");
    b->dados[LUCAS].capitulos[4].versos[21] = wxT("Então começou a dizer-lhes: Hoje se cumpriu esta escritura aos vossos ouvidos.");
    b->dados[LUCAS].capitulos[4].versos[22] = wxT("E todos lhe davam testemunho, e se admiravam das palavras de graça que saíam da sua boca; e diziam: Este não é filho de José?");
    b->dados[LUCAS].capitulos[4].versos[23] = wxT("Disse-lhes Jesus: Sem dúvida me direis este provérbio: Médico, cura-te a ti mesmo; Tudo o que ouvimos teres feito em Cafarnaum, faze-o também aqui na tua terra.");
    b->dados[LUCAS].capitulos[4].versos[24] = wxT("E prosseguiu: Em verdade vos digo que nenhum profeta é aceito na sua terra.");
    b->dados[LUCAS].capitulos[4].versos[25] = wxT("Em verdade vos digo que muitas viúvas havia em Israel nos dias de Elias, quando céu se fechou por três anos e seis meses, de sorte que houve grande fome por toda a terra;");
    b->dados[LUCAS].capitulos[4].versos[26] = wxT("e a nenhuma delas foi enviado Elias, senão a uma viúva em Serepta de Sidom.");
    b->dados[LUCAS].capitulos[4].versos[27] = wxT("Também muitos leprosos havia em Israel no tempo do profeta Elizeu, mas nenhum deles foi purificado senão Naamã, o sírio.");
    b->dados[LUCAS].capitulos[4].versos[28] = wxT("Todos os que estavam na sinagoga, ao ouvirem estas coisas, ficaram cheios de ira.");
    b->dados[LUCAS].capitulos[4].versos[29] = wxT("e, levantando-se, expulsaram-no da cidade e o levaram até o despenhadeiro do monte em que a sua cidade estava edificada, para dali o precipitarem.");
    b->dados[LUCAS].capitulos[4].versos[30] = wxT("Ele, porém, passando pelo meio deles, seguiu o seu caminho.");
    b->dados[LUCAS].capitulos[4].versos[31] = wxT("Então desceu a Cafarnaum, cidade da Galiléia, e os ensinava no sábado.");
    b->dados[LUCAS].capitulos[4].versos[32] = wxT("e maravilharam-se da sua doutrina, porque a sua palavra era com autoridade.");
    b->dados[LUCAS].capitulos[4].versos[33] = wxT("Havia na sinagoga um homem que tinha o espírito de um demônio imundo; e gritou em alta voz:");
    b->dados[LUCAS].capitulos[4].versos[34] = wxT("Ah! que temos nós contigo, Jesus, nazareno? vieste destruir-nos? Bem sei quem é: o Santo de Deus.");
    b->dados[LUCAS].capitulos[4].versos[35] = wxT("Mas Jesus o repreendeu, dizendo: Cala-te, e sai dele. E o demônio, tendo-o lançado por terra no meio do povo, saiu dele sem lhe fazer mal algum.");
    b->dados[LUCAS].capitulos[4].versos[36] = wxT("E veio espanto sobre todos, e falavam entre si, perguntando uns aos outros: Que palavra é esta, pois com autoridade e poder ordena aos espíritos imundos, e eles saem?");
    b->dados[LUCAS].capitulos[4].versos[37] = wxT("E se divulgava a sua fama por todos os lugares da circunvizinhança.");
    b->dados[LUCAS].capitulos[4].versos[38] = wxT("Ora, levantando-se Jesus, saiu da sinagoga e entrou em casa de Simão; e estando a sogra de Simão enferma com muita febre, rogaram-lhe por ela.");
    b->dados[LUCAS].capitulos[4].versos[39] = wxT("E ele, inclinando-se para ela, repreendeu a febre, e esta a deixou. Imediatamente ela se levantou e os servia.");
    b->dados[LUCAS].capitulos[4].versos[40] = wxT("Ao pôr do sol, todos os que tinham enfermos de várias doenças lhos traziam; e ele punha as mãos sobre cada um deles e os curava.");
    b->dados[LUCAS].capitulos[4].versos[41] = wxT("Também de muitos saíam demônios, gritando e dizendo: Tu és o Filho de Deus. Ele, porém, os repreendia, e não os deixava falar; pois sabiam que ele era o Cristo.");
    b->dados[LUCAS].capitulos[4].versos[42] = wxT("Ao romper do dia saiu, e foi a um lugar deserto; e as multidões procuravam-no e, vindo a ele, queriam detê-lo, para que não se ausentasse delas.");
    b->dados[LUCAS].capitulos[4].versos[43] = wxT("Ele, porém, lhes disse: É necessário que também às outras cidades eu anuncie o evangelho do reino de Deus; porque para isso é que fui enviado.");
    b->dados[LUCAS].capitulos[4].versos[44] = wxT("E pregava nas sinagogas da Judéia.");

    b->dados[LUCAS].capitulos[5].versos[1] = wxT("Certa vez, quando a multidão apertava Jesus para ouvir a palavra de Deus, ele estava junto ao lago de Genezaré;");
    b->dados[LUCAS].capitulos[5].versos[2] = wxT("e viu dois barcos junto à praia do lago; mas os pescadores haviam descido deles, e estavam lavando as redes.");
    b->dados[LUCAS].capitulos[5].versos[3] = wxT("Entrando ele num dos barcos, que era o de Simão, pediu-lhe que o afastasse um pouco da terra; e, sentando-se, ensinava do barco as multidões.");
    b->dados[LUCAS].capitulos[5].versos[4] = wxT("Quando acabou de falar, disse a Simão: Faze-te ao largo e lançai as vossas redes para a pesca.");
    b->dados[LUCAS].capitulos[5].versos[5] = wxT("Ao que disse Simão: Mestre, trabalhamos a noite toda, e nada apanhamos; mas, sobre tua palavra, lançarei as redes.");
    b->dados[LUCAS].capitulos[5].versos[6] = wxT("Feito isto, apanharam uma grande quantidade de peixes, de modo que as redes se rompiam.");
    b->dados[LUCAS].capitulos[5].versos[7] = wxT("Acenaram então aos companheiros que estavam no outro barco, para virem ajudá-los. Eles, pois, vieram, e encheram ambos os barcos, de maneira tal que quase iam a pique.");
    b->dados[LUCAS].capitulos[5].versos[8] = wxT("Vendo isso Simão Pedro, prostrou-se aos pés de Jesus, dizendo: Retira-te de mim, Senhor, porque sou um homem pecador.");
    b->dados[LUCAS].capitulos[5].versos[9] = wxT("Pois, à vista da pesca que haviam feito, o espanto se apoderara dele e de todos os que com ele estavam,");
    b->dados[LUCAS].capitulos[5].versos[10] = wxT("bem como de Tiago e João, filhos de Zebedeu, que eram sócios de Simão. Disse Jesus a Simão: Não temas; de agora em diante serás pescador de homens.");
    b->dados[LUCAS].capitulos[5].versos[11] = wxT("E, levando eles os barcos para a terra, deixaram tudo e o seguiram.");
    b->dados[LUCAS].capitulos[5].versos[12] = wxT("Estando ele numa das cidades, apareceu um homem cheio de lepra que, vendo a Jesus, prostrou-se com o rosto em terra e suplicou-lhe: Senhor, se quiseres, bem podes tornar-me limpo.");
    b->dados[LUCAS].capitulos[5].versos[13] = wxT("Jesus, pois, estendendo a mão, tocou-lhe, dizendo: Quero; sê limpo. No mesmo instante desapareceu dele a lepra.");
    b->dados[LUCAS].capitulos[5].versos[14] = wxT("Ordenou-lhe, então, que a ninguém contasse isto. Mas vai, disse ele, mostra-te ao sacerdote e faze a oferta pela tua purificação, conforme Moisés determinou, para lhes servir de testemunho.");
    b->dados[LUCAS].capitulos[5].versos[15] = wxT("A sua fama, porém, se divulgava cada vez mais, e grandes multidões se ajuntavam para ouvi-lo e serem curadas das suas enfermidades.");
    b->dados[LUCAS].capitulos[5].versos[16] = wxT("Mas ele se retirava para os desertos, e ali orava.");
    b->dados[LUCAS].capitulos[5].versos[17] = wxT("Um dia, quando ele estava ensinando, achavam-se ali sentados fariseus e doutores da lei, que tinham vindo de todas as aldeias da Galiléia e da Judéia, e de Jerusalém; e o poder do Senhor estava com ele para curar.");
    b->dados[LUCAS].capitulos[5].versos[18] = wxT("E eis que uns homens, trazendo num leito um paralítico, procuravam introduzi-lo e pô-lo diante dele.");
    b->dados[LUCAS].capitulos[5].versos[19] = wxT("Mas, não achando por onde o pudessem introduzir por causa da multidão, subiram ao eirado e, por entre as telhas, o baixaram com o leito, para o meio de todos, diante de Jesus.");
    b->dados[LUCAS].capitulos[5].versos[20] = wxT("E vendo-lhes a fé, disse ele: Homem, são-te perdoados os teus pecados.");
    b->dados[LUCAS].capitulos[5].versos[21] = wxT("Então os escribas e os fariseus começaram a arrazoar, dizendo: Quem é este que profere blasfêmias? Quem é este que profere blasfêmias? Quem pode perdoar pecados, senão só Deus?");
    b->dados[LUCAS].capitulos[5].versos[22] = wxT("Jesus, porém, percebendo os seus pensamentos, respondeu, e disse-lhes: Por que arrazoais em vossos corações?");
    b->dados[LUCAS].capitulos[5].versos[23] = wxT("Qual é mais fácil? dizer: São-te perdoados os teus pecados; ou dizer: Levanta-te, e anda?");
    b->dados[LUCAS].capitulos[5].versos[24] = wxT("Ora, para que saibais que o Filho do homem tem sobre a terra autoridade para perdoar pecados {disse ao paralítico}, a ti te digo: Levanta-te, toma o teu leito e vai para tua casa.");
    b->dados[LUCAS].capitulos[5].versos[25] = wxT("Imediatamente se levantou diante deles, tomou o leito em que estivera deitado e foi para sua casa, glorificando a Deus.");
    b->dados[LUCAS].capitulos[5].versos[26] = wxT("E, tomados de pasmo, todos glorificavam a Deus; e diziam, cheios de temor: Hoje vimos coisas extraordinárias.");
    b->dados[LUCAS].capitulos[5].versos[27] = wxT("Depois disso saiu e, vendo um publicano chamado Levi, sentado na coletoria, disse-lhe: Segue-me.");
    b->dados[LUCAS].capitulos[5].versos[28] = wxT("Este, deixando tudo, levantou-se e o seguiu.");
    b->dados[LUCAS].capitulos[5].versos[29] = wxT("Deu-lhe então Levi um lauto banquete em sua casa; havia ali grande número de publicanos e outros que estavam com eles à mesa.");
    b->dados[LUCAS].capitulos[5].versos[30] = wxT("Murmuravam, pois, os fariseus e seus escribas contra os discípulos, perguntando: Por que comeis e bebeis com publicanos e pecadores?");
    b->dados[LUCAS].capitulos[5].versos[31] = wxT("Respondeu-lhes Jesus: Não necessitam de médico os sãos, mas sim os enfermos;");
    b->dados[LUCAS].capitulos[5].versos[32] = wxT("eu não vim chamar justos, mas pecadores, ao arrependimento.");
    b->dados[LUCAS].capitulos[5].versos[33] = wxT("Disseram-lhe eles: Os discípulos de João jejuam freqüentemente e fazem orações, como também os dos fariseus, mas os teus comem e bebem.");
    b->dados[LUCAS].capitulos[5].versos[34] = wxT("Respondeu-lhes Jesus: Podeis, porventura, fazer jejuar os convidados às núpcias enquanto o noivo está com eles?");
    b->dados[LUCAS].capitulos[5].versos[35] = wxT("Dias virão, porém, em que lhes será tirado o noivo; naqueles dias, sim hão de jejuar.");
    b->dados[LUCAS].capitulos[5].versos[36] = wxT("Propôs-lhes também uma parábola: Ninguém tira um pedaço de um vestido novo para o coser em vestido velho; do contrário, não somente rasgará o novo, mas também o pedaço do novo não condirá com o velho.");
    b->dados[LUCAS].capitulos[5].versos[37] = wxT("E ninguém deita vinho novo em odres velhos; do contrário, o vinho novo romperá os odres e se derramará, e os odres se perderão;");
    b->dados[LUCAS].capitulos[5].versos[38] = wxT("mas vinho novo deve ser deitado em odres novos.");
    b->dados[LUCAS].capitulos[5].versos[39] = wxT("E ninguém, tendo bebido o velho, quer o novo; porque diz: O velho é bom.");

    b->dados[LUCAS].capitulos[6].versos[1] = wxT("E sucedeu que, num dia de sábado, passava Jesus pelas searas; e seus discípulos iam colhendo espigas e, debulhando-as com as mãos, as comiam.");
    b->dados[LUCAS].capitulos[6].versos[2] = wxT("Alguns dos fariseus, porém, perguntaram; Por que estais fazendo o que não é lícito fazer nos sábados?");
    b->dados[LUCAS].capitulos[6].versos[3] = wxT("E Jesus, respondendo-lhes, disse: Nem ao menos tendes lido o que fez Davi quando teve fome, ele e seus companheiros?");
    b->dados[LUCAS].capitulos[6].versos[4] = wxT("Como entrou na casa de Deus, tomou os pães da proposição, dos quais não era lícito comer senão só aos sacerdotes, e deles comeu e deu também aos companheiros?");
    b->dados[LUCAS].capitulos[6].versos[5] = wxT("Também lhes disse: O Filho do homem é Senhor do sábado.");
    b->dados[LUCAS].capitulos[6].versos[6] = wxT("Ainda em outro sábado entrou na sinagoga, e pôs-se a ensinar. Estava ali um homem que tinha a mão direita atrofiada.");
    b->dados[LUCAS].capitulos[6].versos[7] = wxT("E os escribas e os fariseus observavam-no, para ver se curaria em dia de sábado, para acharem de que o acusar.");
    b->dados[LUCAS].capitulos[6].versos[8] = wxT("Mas ele, conhecendo-lhes os pensamentos, disse ao homem que tinha a mão atrofiada: Levanta-te, e fica em pé aqui no maio. E ele, levantando-se, ficou em pé.");
    b->dados[LUCAS].capitulos[6].versos[9] = wxT("Disse-lhes, então, Jesus: Eu vos pergunto: É lícito no sábado fazer bem, ou fazer mal? salvar a vida, ou tirá-la?");
    b->dados[LUCAS].capitulos[6].versos[10] = wxT("E olhando para todos em redor, disse ao homem: Estende a tua mão. Ele assim o fez, e a mão lhe foi restabelecida.");
    b->dados[LUCAS].capitulos[6].versos[11] = wxT("Mas eles se encheram de furor; e uns com os outros conferenciam sobre o que fariam a Jesus.");
    b->dados[LUCAS].capitulos[6].versos[12] = wxT("Naqueles dias retirou-se para o monte a fim de orar; e passou a noite toda em oração a Deus.");
    b->dados[LUCAS].capitulos[6].versos[13] = wxT("Depois do amanhecer, chamou seus discípulos, e escolheu doze dentre eles, aos quais deu também o nome de apóstolos:");
    b->dados[LUCAS].capitulos[6].versos[14] = wxT("Simão, ao qual também chamou Pedro, e André, seu irmão; Tiago e João; Filipe e Bartolomeu;");
    b->dados[LUCAS].capitulos[6].versos[15] = wxT("Mateus e Tomé; Tiago, filho de Alfeu, e Simão, chamado Zelote;");
    b->dados[LUCAS].capitulos[6].versos[16] = wxT("Judas, filho de Tiago; e Judas Iscariotes, que veio a ser o traidor.");
    b->dados[LUCAS].capitulos[6].versos[17] = wxT("E Jesus, descendo com eles, parou num lugar plano, onde havia não só grande número de seus discípulos, mas também grande multidão do povo, de toda a Judéia e Jerusalém, e do litoral de Tiro e de Sidom, que tinham vindo para ouvi-lo e serem curados das suas doenças;");
    b->dados[LUCAS].capitulos[6].versos[18] = wxT("e os que eram atormentados por espíritos imundos ficavam curados.");
    b->dados[LUCAS].capitulos[6].versos[19] = wxT("E toda a multidão procurava tocar-lhe; porque saía dele poder que curava a todos.");
    b->dados[LUCAS].capitulos[6].versos[20] = wxT("Então, levantando ele os olhos para os seus discípulos, dizia: Bem-aventurados vós, os pobres, porque vosso é o reino de Deus.");
    b->dados[LUCAS].capitulos[6].versos[21] = wxT("Bem-aventurados vós, que agora tendes fome, porque sereis fartos. Bem-aventurados vós, que agora chorais, porque haveis de rir.");
    b->dados[LUCAS].capitulos[6].versos[22] = wxT("Bem-aventurados sereis quando os homens vos odiarem, e quando vos expulsarem da sua companhia, e vos injuriarem, e rejeitarem o vosso nome como indigno, por causa do Filho do homem.");
    b->dados[LUCAS].capitulos[6].versos[23] = wxT("Regozijai-vos nesse dia e exultai, porque eis que é grande o vosso galardão no céu; pois assim faziam os seus pais aos profetas.");
    b->dados[LUCAS].capitulos[6].versos[24] = wxT("Mas ai de vós que sois ricos! porque já recebestes a vossa consolação.");
    b->dados[LUCAS].capitulos[6].versos[25] = wxT("Ai de vós, os que agora estais fartos! porque tereis fome. Ai de vós, os que agora rides! porque vos lamentareis e chorareis.");
    b->dados[LUCAS].capitulos[6].versos[26] = wxT("Ai de vós, quando todos os homens vos louvarem! porque assim faziam os seus pais aos falsos profetas.");
    b->dados[LUCAS].capitulos[6].versos[27] = wxT("Mas a vós que ouvis, digo: Amai a vossos inimigos, fazei bem aos que vos odeiam,");
    b->dados[LUCAS].capitulos[6].versos[28] = wxT("bendizei aos que vos maldizem, e orai pelos que vos caluniam.");
    b->dados[LUCAS].capitulos[6].versos[29] = wxT("Ao que te ferir numa face, oferece-lhe também a outra; e ao que te houver tirado a capa, não lhe negues também a túnica.");
    b->dados[LUCAS].capitulos[6].versos[30] = wxT("Dá a todo o que te pedir; e ao que tomar o que é teu, não lho reclames.");
    b->dados[LUCAS].capitulos[6].versos[31] = wxT("Assim como quereis que os homens vos façam, do mesmo modo lhes fazei vós também.");
    b->dados[LUCAS].capitulos[6].versos[32] = wxT("Se amardes aos que vos amam, que mérito há nisso? Pois também os pecadores amam aos que os amam.");
    b->dados[LUCAS].capitulos[6].versos[33] = wxT("E se fizerdes bem aos que vos fazem bem, que mérito há nisso? Também os pecadores fazem o mesmo.");
    b->dados[LUCAS].capitulos[6].versos[34] = wxT("E se emprestardes àqueles de quem esperais receber, que mérito há nisso? Também os pecadores emprestam aos pecadores, para receberem outro tanto.");
    b->dados[LUCAS].capitulos[6].versos[35] = wxT("Amai, porém a vossos inimigos, fazei bem e emprestai, nunca desanimado; e grande será a vossa recompensa, e sereis filhos do Altíssimo; porque ele é benigno até para com os integrantes e maus.");
    b->dados[LUCAS].capitulos[6].versos[36] = wxT("Sede misericordiosos, como também vosso Pai é misericordioso.");
    b->dados[LUCAS].capitulos[6].versos[37] = wxT("Não julgueis, e não sereis julgados; não condeneis, e não sereis condenados; perdoai, e sereis perdoados.");
    b->dados[LUCAS].capitulos[6].versos[38] = wxT("Dai, e ser-vos-á dado; boa medida, recalcada, sacudida e transbordando vos deitarão no regaço; porque com a mesma medida com que medis, vos medirão a vós.");
    b->dados[LUCAS].capitulos[6].versos[39] = wxT("E propôs-lhes também uma parábola: Pode porventura um cego guiar outro cego? não cairão ambos no barranco?");
    b->dados[LUCAS].capitulos[6].versos[40] = wxT("Não é o discípulo mais do que o seu mestre; mas todo o que for bem instruído será como o seu mestre.");
    b->dados[LUCAS].capitulos[6].versos[41] = wxT("Por que vês o argueiro no olho de teu irmão, e não reparas na trave que está no teu próprio olho?");
    b->dados[LUCAS].capitulos[6].versos[42] = wxT("Ou como podes dizer a teu irmão: Irmão, deixa-me tirar o argueiro que está no teu olho, não vendo tu mesmo a trave que está no teu? Hipócrita! tira primeiro a trave do teu olho; e então verás bem para tirar o argueiro que está no olho de teu irmão.");
    b->dados[LUCAS].capitulos[6].versos[43] = wxT("Porque não há árvore boa que dê mau fruto nem tampouco árvore má que dê bom fruto.");
    b->dados[LUCAS].capitulos[6].versos[44] = wxT("Porque cada árvore se conhece pelo seu próprio fruto; pois dos espinheiros não se colhem figos, nem dos abrolhos se vindimam uvas.");
    b->dados[LUCAS].capitulos[6].versos[45] = wxT("O homem bom, do bom tesouro do seu coração tira o bem; e o homem mau, do seu mau tesouro tira o mal; pois do que há em abundância no coração, disso fala a boca.");
    b->dados[LUCAS].capitulos[6].versos[46] = wxT("E por que me chamais: Senhor, Senhor, e não fazeis o que eu vos digo?");
    b->dados[LUCAS].capitulos[6].versos[47] = wxT("Todo aquele que vem a mim, e ouve as minhas palavras, e as pratica, eu vos mostrarei a quem é semelhante:");
    b->dados[LUCAS].capitulos[6].versos[48] = wxT("É semelhante ao homem que, edificando uma casa, cavou, abriu profunda vala, e pôs os alicerces sobre a rocha; e vindo a enchente, bateu com ímpeto a torrente naquela casa, e não a pôde abalar, porque tinha sido bem edificada.");
    b->dados[LUCAS].capitulos[6].versos[49] = wxT("Mas o que ouve e não pratica é semelhante a um homem que edificou uma casa sobre terra, sem alicerces, na qual bateu com ímpeto a torrente, e logo caiu; e foi grande a ruína daquela casa.");

    b->dados[LUCAS].capitulos[7].versos[1] = wxT("Quando acabou de proferir todas estas palavras aos ouvidos do povo, entrou em Cafarnaum.");
    b->dados[LUCAS].capitulos[7].versos[2] = wxT("E um servo de certo centurião, de quem era muito estimado, estava doente, quase à morte.");
    b->dados[LUCAS].capitulos[7].versos[3] = wxT("O centurião, pois, ouvindo falar de Jesus, enviou-lhes uns anciãos dos judeus, a pedir-lhe que viesse curar o seu servo.");
    b->dados[LUCAS].capitulos[7].versos[4] = wxT("E chegando eles junto de Jesus, rogavam-lhe com instância, dizendo: É digno de que lhe concedas isto;");
    b->dados[LUCAS].capitulos[7].versos[5] = wxT("porque ama à nossa nação, e ele mesmo nos edificou a sinagoga.");
    b->dados[LUCAS].capitulos[7].versos[6] = wxT("Ia, pois, Jesus com eles; mas, quando já estava perto da casa, enviou o centurião uns amigos a dizer-lhe: Senhor, não te incomodes; porque não sou digno de que entres debaixo do meu telhado;");
    b->dados[LUCAS].capitulos[7].versos[7] = wxT("por isso nem ainda me julguei digno de ir à tua presença; dize, porém, uma palavra, e seja o meu servo curado.");
    b->dados[LUCAS].capitulos[7].versos[8] = wxT("Pois também eu sou homem sujeito à autoridade, e tenho soldados às minhas ordens; e digo a este: Vai, e ele vai; e a outro: Vem, e ele vem; e ao meu servo: Faze isto, e ele o faz.");
    b->dados[LUCAS].capitulos[7].versos[9] = wxT("Jesus, ouvindo isso, admirou-se dele e, voltando-se para a multidão que o seguia, disse: Eu vos afirmo que nem mesmo em Israel encontrei tamanha fé.");
    b->dados[LUCAS].capitulos[7].versos[10] = wxT("E voltando para casa os que haviam sido enviados, encontraram o servo com saúde.");
    b->dados[LUCAS].capitulos[7].versos[11] = wxT("Pouco depois seguiu ele viagem para uma cidade chamada Naim; e iam com ele seus discípulos e uma grande multidão.");
    b->dados[LUCAS].capitulos[7].versos[12] = wxT("Quando chegou perto da porta da cidade, eis que levavam para fora um defunto, filho único de sua mãe, que era viúva; e com ela ia uma grande multidão da cidade.");
    b->dados[LUCAS].capitulos[7].versos[13] = wxT("Logo que o Senhor a viu, encheu-se de compaixão por ela, e disse-lhe: Não chores.");
    b->dados[LUCAS].capitulos[7].versos[14] = wxT("Então, chegando-se, tocou no esquife e, quando pararam os que o levavam, disse: Moço, a ti te digo: Levanta-te.");
    b->dados[LUCAS].capitulos[7].versos[15] = wxT("O que estivera morto sentou-se e começou a falar. Então Jesus o entregou à sua mãe.");
    b->dados[LUCAS].capitulos[7].versos[16] = wxT("O medo se apoderou de todos, e glorificavam a Deus, dizendo: Um grande profeta se levantou entre nós; e: Deus visitou o seu povo.");
    b->dados[LUCAS].capitulos[7].versos[17] = wxT("E correu a notícia disto por toda a Judéia e por toda a região circunvizinha.");
    b->dados[LUCAS].capitulos[7].versos[18] = wxT("Ora, os discípulos de João anunciaram-lhe todas estas coisas.");
    b->dados[LUCAS].capitulos[7].versos[19] = wxT("E João, chamando a dois deles, enviou-os ao Senhor para perguntar-lhe: És tu aquele que havia de vir, ou havemos de esperar outro?");
    b->dados[LUCAS].capitulos[7].versos[20] = wxT("Quando aqueles homens chegaram junto dele, disseram: João, o Batista, enviou-nos a perguntar-te: És tu aquele que havia de vir, ou havemos de esperar outro?");
    b->dados[LUCAS].capitulos[7].versos[21] = wxT("Naquela mesma hora, curou a muitos de doenças, de moléstias e de espíritos malignos; e deu vista a muitos cegos.");
    b->dados[LUCAS].capitulos[7].versos[22] = wxT("Então lhes respondeu: Ide, e contai a João o que tens visto e ouvido: os cegos vêem, os coxos andam, os leprosos são purificados, e os surdos ouvem; os mortos são ressuscitados, e aos pobres é anunciado o evangelho.");
    b->dados[LUCAS].capitulos[7].versos[23] = wxT("E bem-aventurado aquele que não se escandalizar de mim.");
    b->dados[LUCAS].capitulos[7].versos[24] = wxT("E, tendo-se retirado os mensageiros de João, Jesus começou a dizer às multidões a respeito de João: Que saístes a ver no deserto? um caniço agitado pelo vento?");
    b->dados[LUCAS].capitulos[7].versos[25] = wxT("Mas que saístes a ver? um homem trajado de vestes luxuosas? Eis que aqueles que trajam roupas preciosas, e vivem em delícias, estão nos paços reais.");
    b->dados[LUCAS].capitulos[7].versos[26] = wxT("Mas que saístes a ver? um profeta? Sim, vos digo, e muito mais do que profeta.");
    b->dados[LUCAS].capitulos[7].versos[27] = wxT("Este é aquele de quem está escrito: Eis aí envio ante a tua face o meu mensageiro, que há de preparar adiante de ti o teu caminho.");
    b->dados[LUCAS].capitulos[7].versos[28] = wxT("Pois eu vos digo que, entre os nascidos de mulher, não há nenhum maior do que João; mas aquele que é o menor no reino de Deus é maior do que ele.");
    b->dados[LUCAS].capitulos[7].versos[29] = wxT("E todo o povo que o ouviu, e até os publicanos, reconheceram a justiça de Deus, recebendo o batismo de João.");
    b->dados[LUCAS].capitulos[7].versos[30] = wxT("Mas os fariseus e os doutores da lei rejeitaram o conselho de Deus quando a si mesmos, não sendo batizados por ele.");
    b->dados[LUCAS].capitulos[7].versos[31] = wxT("A que, pois, compararei os homens desta geração, e a que são semelhantes?");
    b->dados[LUCAS].capitulos[7].versos[32] = wxT("São semelhantes aos meninos que, sentados nas praças, gritam uns para os outros: Tocamo-vos flauta, e não dançastes; cantamos lamentações, e não chorastes.");
    b->dados[LUCAS].capitulos[7].versos[33] = wxT("Porquanto veio João, o Batista, não comendo pão nem bebendo vinho, e dizeis: Tem demônio;");
    b->dados[LUCAS].capitulos[7].versos[34] = wxT("veio o Filho do homem, comendo e bebendo, e dizeis: Eis aí um comilão e bebedor de vinho, amigo de publicanos e pecadores.");
    b->dados[LUCAS].capitulos[7].versos[35] = wxT("Mas a sabedoria é justificada por todos os seus filhos.");
    b->dados[LUCAS].capitulos[7].versos[36] = wxT("Um dos fariseus convidou-o para comer com ele; e entrando em casa do fariseu, reclinou-se à mesa.");
    b->dados[LUCAS].capitulos[7].versos[37] = wxT("E eis que uma mulher pecadora que havia na cidade, quando soube que ele estava à mesa em casa do fariseu, trouxe um vaso de alabastro com bálsamo;");
    b->dados[LUCAS].capitulos[7].versos[38] = wxT("e estando por detrás, aos seus pés, chorando, começou a regar-lhe os pés com lágrimas e os enxugava com os cabelos da sua cabeça; e beijava-lhe os pés e ungia-os com o bálsamo.");
    b->dados[LUCAS].capitulos[7].versos[39] = wxT("Mas, ao ver isso, o fariseu que o convidara falava consigo, dizendo: Se este homem fosse profeta, saberia quem e de que qualidade é essa mulher que o toca, pois é uma pecadora.");
    b->dados[LUCAS].capitulos[7].versos[40] = wxT("E respondendo Jesus, disse-lhe: Simão, tenho uma coisa a dizer-te. Respondeu ele: Dize-a, Mestre.");
    b->dados[LUCAS].capitulos[7].versos[41] = wxT("Certo credor tinha dois devedores; um lhe devia quinhentos denários, e outro cinqüenta.");
    b->dados[LUCAS].capitulos[7].versos[42] = wxT("Não tendo eles com que pagar, perdoou a ambos. Qual deles, pois, o amará mais?");
    b->dados[LUCAS].capitulos[7].versos[43] = wxT("Respondeu Simão: Suponho que é aquele a quem mais perdoou. Replicou-lhe Jesus: Julgaste bem.");
    b->dados[LUCAS].capitulos[7].versos[44] = wxT("E, voltando-se para a mulher, disse a Simão: Vês tu esta mulher? Entrei em tua casa, e não me deste água para os pés; mas esta com suas lágrimas os regou e com seus cabelos os enxugou.");
    b->dados[LUCAS].capitulos[7].versos[45] = wxT("Não me deste ósculo; ela, porém, desde que entrei, não tem cessado de beijar-me os pés.");
    b->dados[LUCAS].capitulos[7].versos[46] = wxT("Não me ungiste a cabeça com óleo; mas esta com bálsamo ungiu-me os pés.");
    b->dados[LUCAS].capitulos[7].versos[47] = wxT("Por isso te digo: Perdoados lhe são os pecados, que são muitos; porque ela muito amou; mas aquele a quem pouco se perdoa, pouco ama.");
    b->dados[LUCAS].capitulos[7].versos[48] = wxT("E disse a ela: Perdoados são os teus pecados.");
    b->dados[LUCAS].capitulos[7].versos[49] = wxT("Mas os que estavam com ele à mesa começaram a dizer entre si: Quem é este que até perdoa pecados?");
    b->dados[LUCAS].capitulos[7].versos[50] = wxT("Jesus, porém, disse à mulher: A tua fé te salvou; vai-te em paz.");

    b->dados[LUCAS].capitulos[8].versos[1] = wxT("Logo depois disso, andava Jesus de cidade em cidade, e de aldeia em aldeia, pregando e anunciando o evangelho do reino de Deus; e iam com ele os doze,");
    b->dados[LUCAS].capitulos[8].versos[2] = wxT("bem como algumas mulheres que haviam sido curadas de espíritos malignos e de enfermidades: Maria, chamada Madalena, da qual tinham saído sete demônios.");
    b->dados[LUCAS].capitulos[8].versos[3] = wxT("Joana, mulher de Cuza, procurador de Herodes, Susana, e muitas outras que os serviam com os seus bens.");
    b->dados[LUCAS].capitulos[8].versos[4] = wxT("Ora, ajuntando-se uma grande multidão, e vindo ter com ele gente de todas as cidades, disse Jesus por parábola:");
    b->dados[LUCAS].capitulos[8].versos[5] = wxT("Saiu o semeador a semear a sua semente. E quando semeava, uma parte da semente caiu à beira do caminho; e foi pisada, e as aves do céu a comeram.");
    b->dados[LUCAS].capitulos[8].versos[6] = wxT("Outra caiu sobre pedra; e, nascida, secou-se porque não havia umidade.");
    b->dados[LUCAS].capitulos[8].versos[7] = wxT("E outra caiu no meio dos espinhos; e crescendo com ela os espinhos, sufocaram-na.");
    b->dados[LUCAS].capitulos[8].versos[8] = wxT("Mas outra caiu em boa terra; e, nascida, produziu fruto, cem por um. Dizendo ele estas coisas, clamava: Quem tem ouvidos para ouvir, ouça.");
    b->dados[LUCAS].capitulos[8].versos[9] = wxT("Perguntaram-lhe então seus discípulos o que significava essa parábola.");
    b->dados[LUCAS].capitulos[8].versos[10] = wxT("Respondeu ele: A vós é dado conhecer os mistérios do reino de Deus; mas aos outros se fala por parábolas; para que vendo, não vejam, e ouvindo, não entendam.");
    b->dados[LUCAS].capitulos[8].versos[11] = wxT("É, pois, esta a parábola: A semente é a palavra de Deus.");
    b->dados[LUCAS].capitulos[8].versos[12] = wxT("Os que estão à beira do caminho são os que ouvem; mas logo vem o Diabo e tira-lhe do coração a palavra, para que não suceda que, crendo, sejam salvos.");
    b->dados[LUCAS].capitulos[8].versos[13] = wxT("Os que estão sobre a pedra são os que, ouvindo a palavra, a recebem com alegria; mas estes não têm raiz, apenas crêem por algum tempo, mas na hora da provação se desviam.");
    b->dados[LUCAS].capitulos[8].versos[14] = wxT("A parte que caiu entre os espinhos são os que ouviram e, indo seu caminho, são sufocados pelos cuidados, riquezas, e deleites desta vida e não dão fruto com perfeição.");
    b->dados[LUCAS].capitulos[8].versos[15] = wxT("Mas a que caiu em boa terra são os que, ouvindo a palavra com coração reto e bom, a retêm e dão fruto com perseverança.");
    b->dados[LUCAS].capitulos[8].versos[16] = wxT("Ninguém, pois, acende uma candeia e a cobre com algum vaso, ou a põe debaixo da cama; mas põe-na no velador, para que os que entram vejam a luz.");
    b->dados[LUCAS].capitulos[8].versos[17] = wxT("Porque não há coisa encoberta que não haja de manifestar-se, nem coisa secreta que não haja de saber-se e vir à luz.");
    b->dados[LUCAS].capitulos[8].versos[18] = wxT("Vede, pois, como ouvis; porque a qualquer que tiver lhe será dado, e a qualquer que não tiver, até o que parece ter lhe será tirado.");
    b->dados[LUCAS].capitulos[8].versos[19] = wxT("Vieram, então, ter com ele sua mãe e seus irmãos, e não podiam aproximar-se dele por causa da multidão.");
    b->dados[LUCAS].capitulos[8].versos[20] = wxT("Foi-lhe dito: Tua mãe e teus irmãos estão lá fora, e querem ver-te.");
    b->dados[LUCAS].capitulos[8].versos[21] = wxT("Ele, porém, lhes respondeu: Minha mãe e meus irmãos são estes que ouvem a palavra de Deus e a observam.");
    b->dados[LUCAS].capitulos[8].versos[22] = wxT("Ora, aconteceu certo dia que entrou num barco com seus discípulos, e disse-lhes: Passemos à outra margem do lago. E partiram.");
    b->dados[LUCAS].capitulos[8].versos[23] = wxT("Enquanto navegavam, ele adormeceu; e desceu uma tempestade de vento sobre o lago; e o barco se enchia de água, de sorte que perigavam.");
    b->dados[LUCAS].capitulos[8].versos[24] = wxT("Chegando-se a ele, o despertaram, dizendo: Mestre, Mestre, estamos perecendo. E ele, levantando-se, repreendeu o vento e a fúria da água; e cessaram, e fez-se bonança.");
    b->dados[LUCAS].capitulos[8].versos[25] = wxT("Então lhes perguntou: Onde está a vossa fé? Eles, atemorizados, admiraram-se, dizendo uns aos outros: Quem, pois, é este, que até aos ventos e à água manda, e lhe obedecem?");
    b->dados[LUCAS].capitulos[8].versos[26] = wxT("Apontaram à terra dos gerasenos, que está defronte da Galiléia.");
    b->dados[LUCAS].capitulos[8].versos[27] = wxT("Logo que saltou em terra, saiu-lhe ao encontro um homem da cidade, possesso de demônios, que havia muito tempo não vestia roupa, nem morava em casa, mas nos sepulcros.");
    b->dados[LUCAS].capitulos[8].versos[28] = wxT("Quando ele viu a Jesus, gritou, prostrou-se diante dele, e com grande voz exclamou: Que tenho eu contigo, Jesus, Filho do Deus Altíssimo? Rogo-te que não me atormentes.");
    b->dados[LUCAS].capitulos[8].versos[29] = wxT("Porque Jesus ordenara ao espírito imundo que saísse do homem. Pois já havia muito tempo que se apoderara dele; e guardavam-no preso com grilhões e cadeias; mas ele, quebrando as prisões, era impelido pelo demônio para os desertos.");
    b->dados[LUCAS].capitulos[8].versos[30] = wxT("Perguntou-lhe Jesus: Qual é o teu nome? Respondeu ele: Legião; porque tinham entrado nele muitos demônios.");
    b->dados[LUCAS].capitulos[8].versos[31] = wxT("E rogavam-lhe que não os mandasse para o abismo.");
    b->dados[LUCAS].capitulos[8].versos[32] = wxT("Ora, andava ali pastando no monte uma grande manada de porcos; rogaram-lhe, pois que lhes permitisse entrar neles, e lho permitiu.");
    b->dados[LUCAS].capitulos[8].versos[33] = wxT("E tendo os demônios saído do homem, entraram nos porcos; e a manada precipitou-se pelo despenhadeiro no lago, e afogou-se.");
    b->dados[LUCAS].capitulos[8].versos[34] = wxT("Quando os pastores viram o que acontecera, fugiram, e foram anunciá-lo na cidade e nos campos.");
    b->dados[LUCAS].capitulos[8].versos[35] = wxT("Saíram, pois, a ver o que tinha acontecido, e foram ter com Jesus, a cujos pés acharam sentado, vestido e em perfeito juízo, o homem de quem havia saído os demônios; e se atemorizaram.");
    b->dados[LUCAS].capitulos[8].versos[36] = wxT("Os que tinham visto aquilo contaram-lhes como fora curado o endemoninhado.");
    b->dados[LUCAS].capitulos[8].versos[37] = wxT("Então todo o povo da região dos gerasenos rogou-lhe que se retirasse deles; porque estavam possuídos de grande medo. Pelo que ele entrou no barco, e voltou.");
    b->dados[LUCAS].capitulos[8].versos[38] = wxT("Pedia-lhe, porém, o homem de quem haviam saído os demônios que o deixasse estar com ele; mas Jesus o despediu, dizendo:");
    b->dados[LUCAS].capitulos[8].versos[39] = wxT("Volta para tua casa, e conta tudo quanto Deus te fez. E ele se retirou, publicando por toda a cidade tudo quanto Jesus lhe fizera.");
    b->dados[LUCAS].capitulos[8].versos[40] = wxT("Quando Jesus voltou, a multidão o recebeu; porque todos o estavam esperando.");
    b->dados[LUCAS].capitulos[8].versos[41] = wxT("E eis que veio um homem chamado Jairo, que era chefe da sinagoga; e prostrando-se aos pés de Jesus, rogava-lhe que fosse a sua casa;");
    b->dados[LUCAS].capitulos[8].versos[42] = wxT("porque tinha uma filha única, de cerca de doze anos, que estava à morte. Enquanto, pois, ele ia, apertavam-no as multidões.");
    b->dados[LUCAS].capitulos[8].versos[43] = wxT("E certa mulher, que tinha uma hemorragia havia doze anos {e gastara com os médicos todos os seus haveres} e por ninguém pudera ser curada,");
    b->dados[LUCAS].capitulos[8].versos[44] = wxT("chegando-se por detrás, tocou-lhe a orla do manto, e imediatamente cessou a sua hemorragia.");
    b->dados[LUCAS].capitulos[8].versos[45] = wxT("Perguntou Jesus: Quem é que me tocou? Como todos negassem, disse-lhe Pedro: Mestre, as multidões te apertam e te oprimem.");
    b->dados[LUCAS].capitulos[8].versos[46] = wxT("Mas disse Jesus: Alguém me tocou; pois percebi que de mim saiu poder.");
    b->dados[LUCAS].capitulos[8].versos[47] = wxT("Então, vendo a mulher que não passara despercebida, aproximou-se tremendo e, prostrando-se diante dele, declarou-lhe perante todo o povo a causa por que lhe havia tocado, e como fora imediatamente curada.");
    b->dados[LUCAS].capitulos[8].versos[48] = wxT("Disse-lhe ele: Filha, a tua fé te salvou; vai-te em paz.");
    b->dados[LUCAS].capitulos[8].versos[49] = wxT("Enquanto ainda falava, veio alguém da casa do chefe da sinagoga dizendo: A tua filha já está morta; não incomodes mais o Mestre.");
    b->dados[LUCAS].capitulos[8].versos[50] = wxT("Jesus, porém, ouvindo-o, respondeu-lhe: Não temas: crê somente, e será salva.");
    b->dados[LUCAS].capitulos[8].versos[51] = wxT("Tendo chegado à casa, a ninguém deixou entrar com ele, senão a Pedro, João, Tiago, e o pai e a mãe da menina.");
    b->dados[LUCAS].capitulos[8].versos[52] = wxT("E todos choravam e pranteavam; ele, porém, disse: Não choreis; ela não está morta, mas dorme.");
    b->dados[LUCAS].capitulos[8].versos[53] = wxT("E riam-se dele, sabendo que ela estava morta.");
    b->dados[LUCAS].capitulos[8].versos[54] = wxT("Então ele, tomando-lhe a mão, exclamou: Menina, levanta-te.");
    b->dados[LUCAS].capitulos[8].versos[55] = wxT("E o seu espírito voltou, e ela se levantou imediatamente; e Jesus mandou que lhe desse de comer.");
    b->dados[LUCAS].capitulos[8].versos[56] = wxT("E seus pais ficaram maravilhados; e ele mandou-lhes que a ninguém contassem o que havia sucedido.");

    b->dados[LUCAS].capitulos[9].versos[1] = wxT("Reunindo os doze, deu-lhes poder e autoridade sobre todos os demônios, e para curarem doenças;");
    b->dados[LUCAS].capitulos[9].versos[2] = wxT("e enviou-os a pregar o reino de Deus, e fazer curas,");
    b->dados[LUCAS].capitulos[9].versos[3] = wxT("dizendo-lhes: Nada leveis para o caminho, nem bordão, nem alforje, nem pão, nem dinheiro; nem tenhais duas túnicas.");
    b->dados[LUCAS].capitulos[9].versos[4] = wxT("Em qualquer casa em que entrardes, nela ficai, e dali partireis.");
    b->dados[LUCAS].capitulos[9].versos[5] = wxT("Mas, onde quer que não vos receberem, saindo daquela cidade, sacudi o pó dos vossos pés, em testemunho contra eles.");
    b->dados[LUCAS].capitulos[9].versos[6] = wxT("Saindo, pois, os discípulos percorreram as aldeias, anunciando o evangelho e fazendo curas por toda parte.");
    b->dados[LUCAS].capitulos[9].versos[7] = wxT("Ora, o tetrarca Herodes soube de tudo o que se passava, e ficou muito perplexo, porque diziam uns: João ressuscitou dos mortos;");
    b->dados[LUCAS].capitulos[9].versos[8] = wxT("outros: Elias apareceu; e outros: Um dos antigos profetas se levantou.");
    b->dados[LUCAS].capitulos[9].versos[9] = wxT("Herodes, porém, disse: A João eu mandei degolar; quem é, pois, este a respeito de quem ouço tais coisas? E procurava vê-lo.");
    b->dados[LUCAS].capitulos[9].versos[10] = wxT("Quando os apóstolos voltaram, contaram-lhe tudo o que havia feito. E ele, levando-os consigo, retirou-se à parte para uma cidade chamada Betsaida.");
    b->dados[LUCAS].capitulos[9].versos[11] = wxT("Mas as multidões, percebendo isto, seguiram-no; e ele as recebeu, e falava-lhes do reino de Deus, e sarava os que necessitavam de cura.");
    b->dados[LUCAS].capitulos[9].versos[12] = wxT("Ora, quando o dia começava a declinar, aproximando-se os doze, disseram-lhe: Despede a multidão, para que, indo às aldeias e aos sítios em redor, se hospedem, e achem o que comer; porque aqui estamos em lugar deserto.");
    b->dados[LUCAS].capitulos[9].versos[13] = wxT("Mas ele lhes disse: Dai-lhes vós de comer. Responderam eles: Não temos senão cinco pães e dois peixes; salvo se nós formos comprar comida para todo este povo.");
    b->dados[LUCAS].capitulos[9].versos[14] = wxT("Pois eram cerca de cinco mil homens. Então disse a seus discípulos: Fazei-os reclinar-se em grupos de cerca de cinqüenta cada um.");
    b->dados[LUCAS].capitulos[9].versos[15] = wxT("Assim o fizeram, mandando que todos se reclinassem.");
    b->dados[LUCAS].capitulos[9].versos[16] = wxT("E tomando Jesus os cinco pães e os dois peixes, e olhando para o céu, os abençoou e partiu, e os entregava aos seus discípulos para os porem diante da multidão.");
    b->dados[LUCAS].capitulos[9].versos[17] = wxT("Todos, pois, comeram e se fartaram; e foram levantados, do que lhes sobejou, doze cestos de pedaços.");
    b->dados[LUCAS].capitulos[9].versos[18] = wxT("Enquanto ele estava orando à parte achavam-se com ele somente seus discípulos; e perguntou-lhes: Quem dizem as multidões que eu sou?");
    b->dados[LUCAS].capitulos[9].versos[19] = wxT("Responderam eles: Uns dizem: João, o Batista; outros: Elias; e ainda outros, que um dos antigos profetas se levantou.");
    b->dados[LUCAS].capitulos[9].versos[20] = wxT("Então lhes perguntou: Mas vós, quem dizeis que eu sou? Respondendo Pedro, disse: O Cristo de Deus.");
    b->dados[LUCAS].capitulos[9].versos[21] = wxT("Jesus, porém, advertindo-os, mandou que não contassem isso a ninguém;");
    b->dados[LUCAS].capitulos[9].versos[22] = wxT("e disse-lhes: É necessário que o Filho do homem padeça muitas coisas, que seja rejeitado pelos anciãos, pelos principais sacerdotes e escribas, que seja morto, e que ao terceiro dia ressuscite.");
    b->dados[LUCAS].capitulos[9].versos[23] = wxT("Em seguida dizia a todos: Se alguém quer vir após mim, negue-se a si mesmo, tome cada dia a sua cruz, e siga-me.");
    b->dados[LUCAS].capitulos[9].versos[24] = wxT("Pois quem quiser salvar a sua vida, perdê-la-á; mas quem perder a sua vida por amor de mim, esse a salvará.");
    b->dados[LUCAS].capitulos[9].versos[25] = wxT("Pois, que aproveita ao homem ganhar o mundo inteiro, e perder-se, ou prejudicar-se a si mesmo?");
    b->dados[LUCAS].capitulos[9].versos[26] = wxT("Porque, quem se envergonhar de mim e das minhas palavras, dele se envergonhará o Filho do homem, quando vier na sua glória, e na do Pai e dos santos anjos.");
    b->dados[LUCAS].capitulos[9].versos[27] = wxT("Mas em verdade vos digo: Alguns há, dos que estão aqui, que de modo nenhum provarão a morte até que vejam o reino de Deus.");
    b->dados[LUCAS].capitulos[9].versos[28] = wxT("Cerca de oito dias depois de ter proferido essas palavras, tomou Jesus consigo a Pedro, a João e a Tiago, e subiu ao monte para orar.");
    b->dados[LUCAS].capitulos[9].versos[29] = wxT("Enquanto ele orava, mudou-se a aparência do seu rosto, e a sua roupa tornou-se branca e resplandecente.");
    b->dados[LUCAS].capitulos[9].versos[30] = wxT("E eis que estavam falando com ele dois varões, que eram Moisés e Elias,");
    b->dados[LUCAS].capitulos[9].versos[31] = wxT("os quais apareceram com glória, e falavam da sua partida que estava para cumprir-se em Jerusalém.");
    b->dados[LUCAS].capitulos[9].versos[32] = wxT("Ora, Pedro e os que estavam com ele se haviam deixado vencer pelo sono; despertando, porém, viram a sua glória e os dois varões que estavam com ele.");
    b->dados[LUCAS].capitulos[9].versos[33] = wxT("E, quando estes se apartavam dele, disse Pedro a Jesus: Mestre, bom é estarmos nós aqui: façamos, pois, três cabanas, uma para ti, uma para Moisés, e uma para Elias, não sabendo o que dizia.");
    b->dados[LUCAS].capitulos[9].versos[34] = wxT("Enquanto ele ainda falava, veio uma nuvem que os cobriu; e se atemorizaram ao entrarem na nuvem.");
    b->dados[LUCAS].capitulos[9].versos[35] = wxT("E da nuvem saiu uma voz que dizia: Este é o meu Filho, o meu eleito; a ele ouvi.");
    b->dados[LUCAS].capitulos[9].versos[36] = wxT("Ao soar esta voz, Jesus foi achado sozinho; e eles calaram-se, e por aqueles dias não contaram a ninguém nada do que tinham visto.");
    b->dados[LUCAS].capitulos[9].versos[37] = wxT("No dia seguinte, quando desceram do monte, veio-lhe ao encontro uma grande multidão.");
    b->dados[LUCAS].capitulos[9].versos[38] = wxT("E eis que um homem dentre a multidão clamou, dizendo: Mestre, peço-te que olhes para meu filho, porque é o único que tenho;");
    b->dados[LUCAS].capitulos[9].versos[39] = wxT("pois um espírito se apodera dele, fazendo-o gritar subitamente, convulsiona-o até escumar e, mesmo depois de o ter quebrantado, dificilmente o larga.");
    b->dados[LUCAS].capitulos[9].versos[40] = wxT("E roguei aos teus discípulos que o expulsassem, mas não puderam.");
    b->dados[LUCAS].capitulos[9].versos[41] = wxT("Respondeu Jesus: ó geração incrédula e perversa! até quando estarei convosco e vos sofrerei? Traze-me cá o teu filho.");
    b->dados[LUCAS].capitulos[9].versos[42] = wxT("Ainda quando ele vinha chegando, o demônio o derribou e o convulsionou; mas Jesus repreendeu o espírito imundo, curou o menino e o entregou a seu pai.");
    b->dados[LUCAS].capitulos[9].versos[43] = wxT("E todos se maravilhavam da majestade de Deus. E admirando-se todos de tudo o que Jesus fazia, disse ele a seus discípulos:");
    b->dados[LUCAS].capitulos[9].versos[44] = wxT("Ponde vós estas palavras em vossos ouvidos; pois o Filho do homem está para ser entregue nas mãos dos homens.");
    b->dados[LUCAS].capitulos[9].versos[45] = wxT("Eles, porém, não entendiam essa palavra, cujo sentido lhes era encoberto para que não o compreendessem; e temiam interrogá-lo a esse respeito.");
    b->dados[LUCAS].capitulos[9].versos[46] = wxT("E suscitou-se entre eles uma discussão sobre qual deles seria o maior.");
    b->dados[LUCAS].capitulos[9].versos[47] = wxT("Mas Jesus, percebendo o pensamento de seus corações, tomou uma criança, pô-la junto de si,");
    b->dados[LUCAS].capitulos[9].versos[48] = wxT("e disse-lhes: Qualquer que receber esta criança em meu nome, a mim me recebe; e qualquer que me receber a mim, recebe aquele que me enviou; pois aquele que entre vós todos é o menor, esse é grande.");
    b->dados[LUCAS].capitulos[9].versos[49] = wxT("Disse-lhe João: Mestre, vimos um homem que em teu nome expulsava demônios; e lho proibimos, porque não segue conosco.");
    b->dados[LUCAS].capitulos[9].versos[50] = wxT("Respondeu-lhe Jesus: Não lho proibais; porque quem não é contra vós é por vós.");
    b->dados[LUCAS].capitulos[9].versos[51] = wxT("Ora, quando se completavam os dias para a sua assunção, manifestou o firme propósito de ir a Jerusalém.");
    b->dados[LUCAS].capitulos[9].versos[52] = wxT("Enviou, pois, mensageiros adiante de si. Indo eles, entraram numa aldeia de samaritanos para lhe prepararem pousada.");
    b->dados[LUCAS].capitulos[9].versos[53] = wxT("Mas não o receberam, porque viajava em direção a Jerusalém.");
    b->dados[LUCAS].capitulos[9].versos[54] = wxT("Vendo isto os discípulos Tiago e João, disseram: Senhor, queres que mandemos descer fogo do céu para os consumir {como Elias também fez?}");
    b->dados[LUCAS].capitulos[9].versos[55] = wxT("Ele porém, voltando-se, repreendeu-os, {e disse: Vós não sabeis de que espírito sois.}");
    b->dados[LUCAS].capitulos[9].versos[56] = wxT("{Pois o Filho do Homem não veio para destruir as vidas dos homens, mas para salvá-las.} E foram para outra aldeia.");
    b->dados[LUCAS].capitulos[9].versos[57] = wxT("Quando iam pelo caminho, disse-lhe um homem: Seguir-te-ei para onde quer que fores.");
    b->dados[LUCAS].capitulos[9].versos[58] = wxT("Respondeu-lhe Jesus: As raposas têm covis, e as aves do céu têm ninhos; mas o Filho do homem não tem onde reclinar a cabeça.");
    b->dados[LUCAS].capitulos[9].versos[59] = wxT("E a outro disse: Segue-me. Ao que este respondeu: Permite-me ir primeiro sepultar meu pai.");
    b->dados[LUCAS].capitulos[9].versos[60] = wxT("Replicou-lhe Jesus: Deixa os mortos sepultar os seus próprios mortos; tu, porém, vai e anuncia o reino de Deus.");
    b->dados[LUCAS].capitulos[9].versos[61] = wxT("Disse também outro: Senhor, eu te seguirei, mas deixa-me despedir primeiro dos que estão em minha casa.");
    b->dados[LUCAS].capitulos[9].versos[62] = wxT("Jesus, porém, lhe respondeu: Ninguém que lança mão do arado e olha para trás é apto para o reino de Deus.");

    b->dados[LUCAS].capitulos[10].versos[1] = wxT("Depois disso designou o Senhor outros setenta, e os enviou adiante de si, de dois em dois, a todas as cidades e lugares aonde ele havia de ir.");
    b->dados[LUCAS].capitulos[10].versos[2] = wxT("E dizia-lhes: Na verdade, a seara é grande, mas os trabalhadores são poucos; rogai, pois, ao Senhor da seara que mande trabalhadores para a sua seara.");
    b->dados[LUCAS].capitulos[10].versos[3] = wxT("Ide; eis que vos envio como cordeiros ao meio de lobos.");
    b->dados[LUCAS].capitulos[10].versos[4] = wxT("Não leveis bolsa, nem alforge, nem alparcas; e a ninguém saudeis pelo caminho.");
    b->dados[LUCAS].capitulos[10].versos[5] = wxT("Em qualquer casa em que entrardes, dizei primeiro: Paz seja com esta casa.");
    b->dados[LUCAS].capitulos[10].versos[6] = wxT("E se ali houver um filho da paz, repousará sobre ele a vossa paz; e se não, voltará para vós.");
    b->dados[LUCAS].capitulos[10].versos[7] = wxT("Ficai nessa casa, comendo e bebendo do que eles tiverem; pois digno é o trabalhador do seu salário. Não andeis de casa em casa.");
    b->dados[LUCAS].capitulos[10].versos[8] = wxT("Também, em qualquer cidade em que entrardes, e vos receberem, comei do que puserem diante de vós.");
    b->dados[LUCAS].capitulos[10].versos[9] = wxT("Curai os enfermos que nela houver, e dizer-lhes: É chegado a vós o reino de Deus.");
    b->dados[LUCAS].capitulos[10].versos[10] = wxT("Mas em qualquer cidade em que entrardes, e vos não receberem, saindo pelas ruas, dizei:");
    b->dados[LUCAS].capitulos[10].versos[11] = wxT("Até o pó da vossa cidade, que se nos pegou aos pés, sacudimos contra vós. Contudo, sabei isto: que o reino de Deus é chegado.");
    b->dados[LUCAS].capitulos[10].versos[12] = wxT("Digo-vos que naquele dia haverá menos rigor para Sodoma, do que para aquela cidade.");
    b->dados[LUCAS].capitulos[10].versos[13] = wxT("Ai de ti, Corazim! ai de ti, Betsaida! Porque, se em Tiro e em Sidom se tivessem operado os milagres que em vós se operaram, há muito, sentadas em cilício e cinza, elas se teriam arrependido.");
    b->dados[LUCAS].capitulos[10].versos[14] = wxT("Contudo, para Tiro e Sidom haverá menos rigor no juízo do que para vós.");
    b->dados[LUCAS].capitulos[10].versos[15] = wxT("E tu, Cafarnaum, porventura serás elevada até o céu? até o inferno descerás.");
    b->dados[LUCAS].capitulos[10].versos[16] = wxT("Quem vos ouve, a mim me ouve; e quem vos rejeita, a mim me rejeita; e quem a mim me rejeita, rejeita aquele que me enviou.");
    b->dados[LUCAS].capitulos[10].versos[17] = wxT("Voltaram depois os setenta com alegria, dizendo: Senhor, em teu nome, até os demônios se nos submetem.");
    b->dados[LUCAS].capitulos[10].versos[18] = wxT("Respondeu-lhes ele: Eu via Satanás, como raio, cair do céu.");
    b->dados[LUCAS].capitulos[10].versos[19] = wxT("Eis que vos dei autoridade para pisar serpentes e escorpiões, e sobre todo o poder do inimigo; e nada vos fará dano algum.");
    b->dados[LUCAS].capitulos[10].versos[20] = wxT("Contudo, não vos alegreis porque se vos submetem os espíritos; alegrai-vos antes por estarem os vossos nomes escritos nos céus.");
    b->dados[LUCAS].capitulos[10].versos[21] = wxT("Naquela mesma hora exultou Jesus no Espírito Santo, e disse: Graças te dou, ó Pai, Senhor do céu e da terra, porque ocultaste estas coisas aos sábios e entendidos, e as revelaste aos pequeninos; sim, ó Pai, porque assim foi do teu agrado.");
    b->dados[LUCAS].capitulos[10].versos[22] = wxT("Todas as coisas me foram entregues por meu Pai; e ninguém conhece quem é o Filho senão o Pai, nem quem é o Pai senão o Filho, e aquele a quem o Filho o quiser revelar.");
    b->dados[LUCAS].capitulos[10].versos[23] = wxT("E voltando-se para os discípulos, disse-lhes em particular: Bem-aventurados os olhos que vêem o que vós vedes.");
    b->dados[LUCAS].capitulos[10].versos[24] = wxT("Pois vos digo que muitos profetas e reis desejaram ver o que vós vedes, e não o viram; e ouvir o que ouvis, e não o ouviram.");
    b->dados[LUCAS].capitulos[10].versos[25] = wxT("E eis que se levantou certo doutor da lei e, para o experimentar, disse: Mestre, que farei para herdar a vida eterna?");
    b->dados[LUCAS].capitulos[10].versos[26] = wxT("Perguntou-lhe Jesus: Que está escrito na lei? Como lês tu?");
    b->dados[LUCAS].capitulos[10].versos[27] = wxT("Respondeu-lhe ele: Amarás ao Senhor teu Deus de todo o teu coração, de toda a tua alma, de todas as tuas forças e de todo o teu entendimento, e ao teu próximo como a ti mesmo.");
    b->dados[LUCAS].capitulos[10].versos[28] = wxT("Tornou-lhe Jesus: Respondeste bem; faze isso, e viverás.");
    b->dados[LUCAS].capitulos[10].versos[29] = wxT("Ele, porém, querendo justificar-se, perguntou a Jesus: E quem é o meu próximo?");
    b->dados[LUCAS].capitulos[10].versos[30] = wxT("Jesus, prosseguindo, disse: Um homem descia de Jerusalém a Jericó, e caiu nas mãos de salteadores, os quais o despojaram e espancando-o, se retiraram, deixando-o meio morto.");
    b->dados[LUCAS].capitulos[10].versos[31] = wxT("Casualmente, descia pelo mesmo caminho certo sacerdote; e vendo-o, passou de largo.");
    b->dados[LUCAS].capitulos[10].versos[32] = wxT("De igual modo também um levita chegou àquele lugar, viu-o, e passou de largo.");
    b->dados[LUCAS].capitulos[10].versos[33] = wxT("Mas um samaritano, que ia de viagem, chegou perto dele e, vendo-o, encheu-se de compaixão;");
    b->dados[LUCAS].capitulos[10].versos[34] = wxT("e aproximando-se, atou-lhe as feridas, deitando nelas azeite e vinho; e pondo-o sobre a sua cavalgadura, levou-o para uma estalagem e cuidou dele.");
    b->dados[LUCAS].capitulos[10].versos[35] = wxT("No dia seguinte tirou dois denários, deu-os ao hospedeiro e disse-lhe: Cuida dele; e tudo o que gastares a mais, eu to pagarei quando voltar.");
    b->dados[LUCAS].capitulos[10].versos[36] = wxT("Qual, pois, destes três te parece ter sido o próximo daquele que caiu nas mãos dos salteadores?");
    b->dados[LUCAS].capitulos[10].versos[37] = wxT("Respondeu o doutor da lei: Aquele que usou de misericórdia para com ele. Disse-lhe, pois, Jesus: Vai, e faze tu o mesmo.");
    b->dados[LUCAS].capitulos[10].versos[38] = wxT("Ora, quando iam de caminho, entrou Jesus numa aldeia; e certa mulher, por nome Marta, o recebeu em sua casa.");
    b->dados[LUCAS].capitulos[10].versos[39] = wxT("Tinha esta uma irmã chamada Maria, a qual, sentando-se aos pés do Senhor, ouvia a sua palavra.");
    b->dados[LUCAS].capitulos[10].versos[40] = wxT("Marta, porém, andava preocupada com muito serviço; e aproximando-se, disse: Senhor, não se te dá que minha irmã me tenha deixado a servir sozinha? Dize-lhe, pois, que me ajude.");
    b->dados[LUCAS].capitulos[10].versos[41] = wxT("Respondeu-lhe o Senhor: Marta, Marta, estás ansiosa e perturbada com muitas coisas;");
    b->dados[LUCAS].capitulos[10].versos[42] = wxT("entretanto poucas são necessárias, ou mesmo uma só; e Maria escolheu a boa parte, a qual não lhe será tirada.");

    b->dados[LUCAS].capitulos[11].versos[1] = wxT("Estava Jesus em certo lugar orando e, quando acabou, disse-lhe um dos seus discípulos: Senhor, ensina-nos a orar, como também João ensinou aos seus discípulos.");
    b->dados[LUCAS].capitulos[11].versos[2] = wxT("Ao que ele lhes disse: Quando orardes, dizei: Pai, santificado seja o teu nome; venha o teu reino;");
    b->dados[LUCAS].capitulos[11].versos[3] = wxT("dá-nos cada dia o nosso pão cotidiano;");
    b->dados[LUCAS].capitulos[11].versos[4] = wxT("e perdoa-nos os nossos pecados, pois também nós perdoamos a todo aquele que nos deve; e não nos deixes entrar em tentação, {mas livra-nos do mal.}");
    b->dados[LUCAS].capitulos[11].versos[5] = wxT("Disse-lhes também: Se um de vós tiver um amigo, e se for procurá-lo à meia-noite e lhe disser: Amigo, empresta-me três pães,");
    b->dados[LUCAS].capitulos[11].versos[6] = wxT("pois que um amigo meu, estando em viagem, chegou a minha casa, e não tenho o que lhe oferecer;");
    b->dados[LUCAS].capitulos[11].versos[7] = wxT("e se ele, de dentro, responder: Não me incomodes; já está a porta fechada, e os meus filhos estão comigo na cama; não posso levantar-me para te atender;");
    b->dados[LUCAS].capitulos[11].versos[8] = wxT("digo-vos que, ainda que se levante para lhos dar por ser seu amigo, todavia, por causa da sua importunação, se levantará e lhe dará quantos pães ele precisar.");
    b->dados[LUCAS].capitulos[11].versos[9] = wxT("Pelo que eu vos digo: Pedi, e dar-se-vos-á; buscai e achareis; batei, e abrir-se-vos-á;");
    b->dados[LUCAS].capitulos[11].versos[10] = wxT("pois todo o que pede, recebe; e quem busca acha; e ao que bate, abrir-se-lhe-á.");
    b->dados[LUCAS].capitulos[11].versos[11] = wxT("E qual o pai dentre vós que, se o filho lhe pedir pão, lhe dará uma pedra? Ou, se lhe pedir peixe, lhe dará por peixe uma serpente?");
    b->dados[LUCAS].capitulos[11].versos[12] = wxT("Ou, se pedir um ovo, lhe dará um escorpião?");
    b->dados[LUCAS].capitulos[11].versos[13] = wxT("Se vós, pois, sendo maus, sabeis dar boas dádivas aos vossos filhos, quanto mais dará o Pai celestial o Espírito Santo àqueles que lho pedirem?");
    b->dados[LUCAS].capitulos[11].versos[14] = wxT("Estava Jesus expulsando um demônio, que era mudo; e aconteceu que, saindo o demônio, o mudo falou; e as multidões se admiraram.");
    b->dados[LUCAS].capitulos[11].versos[15] = wxT("Mas alguns deles disseram: É por Belzebu, o príncipe dos demônios, que ele expulsa os demônios.");
    b->dados[LUCAS].capitulos[11].versos[16] = wxT("E outros, experimentando-o, lhe pediam um sinal do céu.");
    b->dados[LUCAS].capitulos[11].versos[17] = wxT("Ele, porém, conhecendo-lhes os pensamentos, disse-lhes: Todo reino dividido contra si mesmo será assolado, e casa sobre casa cairá.");
    b->dados[LUCAS].capitulos[11].versos[18] = wxT("Ora, pois, se Satanás está dividido contra si mesmo, como subsistirá o seu reino? Pois dizeis que eu expulso dos demônios por Belzebu.");
    b->dados[LUCAS].capitulos[11].versos[19] = wxT("E, se eu expulso os demônios por Belzebu, por quem os expulsam os vossos filhos? Por isso eles mesmos serão os vossos juizes.");
    b->dados[LUCAS].capitulos[11].versos[20] = wxT("Mas, se é pelo dedo de Deus que eu expulso os demônios, logo é chegado a vós o reino de Deus.");
    b->dados[LUCAS].capitulos[11].versos[21] = wxT("Quando o valente guarda, armado, a sua casa, em segurança estão os seus bens;");
    b->dados[LUCAS].capitulos[11].versos[22] = wxT("mas, sobrevindo outro mais valente do que ele, e vencendo-o, tira-lhe toda a armadura em que confiava, e reparte os seus despojos.");
    b->dados[LUCAS].capitulos[11].versos[23] = wxT("Quem não é comigo, é contra mim; e quem comigo não ajunta, espalha.");
    b->dados[LUCAS].capitulos[11].versos[24] = wxT("Ora, havendo o espírito imundo saindo do homem, anda por lugares áridos, buscando repouso; e não o encontrando, diz: Voltarei para minha casa, donde saí.");
    b->dados[LUCAS].capitulos[11].versos[25] = wxT("E chegando, acha-a varrida e adornada.");
    b->dados[LUCAS].capitulos[11].versos[26] = wxT("Então vai, e leva consigo outros sete espíritos piores do que ele e, entrando, habitam ali; e o último estado desse homem vem a ser pior do que o primeiro.");
    b->dados[LUCAS].capitulos[11].versos[27] = wxT("Ora, enquanto ele dizia estas coisas, certa mulher dentre a multidão levantou a voz e lhe disse: Bem-aventurado o ventre que te trouxe e os peitos em que te amamentaste.");
    b->dados[LUCAS].capitulos[11].versos[28] = wxT("Mas ele respondeu: Antes bem-aventurados os que ouvem a palavra de Deus, e a observam.");
    b->dados[LUCAS].capitulos[11].versos[29] = wxT("Como afluíssem as multidões, começou ele a dizer: Geração perversa é esta; ela pede um sinal; e nenhum sinal se lhe dará, senão o de Jonas;");
    b->dados[LUCAS].capitulos[11].versos[30] = wxT("porquanto, assim como Jonas foi sinal para os ninivitas, também o Filho do homem o será para esta geração.");
    b->dados[LUCAS].capitulos[11].versos[31] = wxT("A rainha do sul se levantará no juízo com os homens desta geração, e os condenará; porque veio dos confins da terra para ouvir a sabedoria de Salomão; e eis, aqui quem é maior do que Salomão.");
    b->dados[LUCAS].capitulos[11].versos[32] = wxT("Os homens de Nínive se levantarão no juízo com esta geração, e a condenarão; porque se arrependeram com a pregação de Jonas; e eis aqui quem é maior do que Jonas.");
    b->dados[LUCAS].capitulos[11].versos[33] = wxT("Ninguém, depois de acender uma candeia, a põe em lugar oculto, nem debaixo do alqueire, mas no velador, para que os que entram vejam a luz.");
    b->dados[LUCAS].capitulos[11].versos[34] = wxT("A candeia do corpo são os olhos. Quando, pois, os teus olhos forem bons, todo o teu corpo será luminoso; mas, quando forem maus, o teu corpo será tenebroso.");
    b->dados[LUCAS].capitulos[11].versos[35] = wxT("Vê, então, que a luz que há em ti não sejam trevas.");
    b->dados[LUCAS].capitulos[11].versos[36] = wxT("Se, pois, todo o teu corpo estiver iluminado, sem ter parte alguma em trevas, será inteiramente luminoso, como quando a candeia te alumia com o seu resplendor.");
    b->dados[LUCAS].capitulos[11].versos[37] = wxT("Acabando Jesus de falar, um fariseu o convidou para almoçar com ele; e havendo Jesus entrado, reclinou-se à mesa.");
    b->dados[LUCAS].capitulos[11].versos[38] = wxT("O fariseu admirou-se, vendo que ele não se lavara antes de almoçar.");
    b->dados[LUCAS].capitulos[11].versos[39] = wxT("Ao que o Senhor lhe disse: Ora vós, os fariseus, limpais o exterior do corpo e do prato; mas o vosso interior do copo e do prato; mas o vosso interior está cheio de rapina e maldade.");
    b->dados[LUCAS].capitulos[11].versos[40] = wxT("Loucos! quem fez o exterior, não fez também o inferior?");
    b->dados[LUCAS].capitulos[11].versos[41] = wxT("Dai, porém, de esmola o que está dentro do copo e do prato, e eis que todas as coisas vos serão limpas.");
    b->dados[LUCAS].capitulos[11].versos[42] = wxT("Mas ai de vós, fariseus! porque dais o dízimo da hortelã, e da arruda, e de toda hortaliça, e desprezais a justiça e o amor de Deus. Ora, estas coisas importava fazer, sem deixar aquelas.");
    b->dados[LUCAS].capitulos[11].versos[43] = wxT("Ai de vós, fariseus! porque gostais dos primeiros assentos nas sinagogas, e das saudações nas praças.");
    b->dados[LUCAS].capitulos[11].versos[44] = wxT("Ai de vós! porque sois como as sepulturas que não aparecem, sobre as quais andam os homens sem o saberem.");
    b->dados[LUCAS].capitulos[11].versos[45] = wxT("Disse-lhe, então, um dos doutores da lei: Mestre, quando dizes isso, também nos afrontas a nós.");
    b->dados[LUCAS].capitulos[11].versos[46] = wxT("Ele, porém, respondeu: Ai de vós também, doutores da lei! porque carregais os homens com fardos difíceis de suportar, e vós mesmos nem ainda com um dos vossos dedos tocais nesses fardos.");
    b->dados[LUCAS].capitulos[11].versos[47] = wxT("Ai de vós! porque edificais os túmulos dos profetas, e vossos pais os mataram.");
    b->dados[LUCAS].capitulos[11].versos[48] = wxT("Assim sois testemunhas e aprovais as obras de vossos pais; porquanto eles os mataram, e vós lhes edificais os túmulos.");
    b->dados[LUCAS].capitulos[11].versos[49] = wxT("Por isso diz também a sabedoria de Deus: Profetas e apóstolos lhes mandarei; e eles matarão uns, e perseguirão outros;");
    b->dados[LUCAS].capitulos[11].versos[50] = wxT("para que a esta geração se peçam contas do sangue de todos os profetas que, desde a fundação do mundo, foi derramado;");
    b->dados[LUCAS].capitulos[11].versos[51] = wxT("desde o sangue de Abel, até o sangue de Zacarias, que foi morto entre o altar e o santuário; sim, eu vos digo, a esta geração se pedirão contas.");
    b->dados[LUCAS].capitulos[11].versos[52] = wxT("Ai de vós, doutores da lei! porque tirastes a chave da ciência; vós mesmos não entrastes, e impedistes aos que entravam.");
    b->dados[LUCAS].capitulos[11].versos[53] = wxT("Ao sair ele dali, começaram os escribas e os fariseus a apertá-lo fortemente, e a interrogá-lo acerca de muitas coisas,");
    b->dados[LUCAS].capitulos[11].versos[54] = wxT("armando-lhe ciladas, a fim de o apanharem em alguma coisa que dissesse.");

    b->dados[LUCAS].capitulos[12].versos[1] = wxT("Ajuntando-se entretanto muitos milhares de pessoas, de sorte que se atropelavam uns aos outros, começou Jesus a dizer primeiro aos seus discípulos: Acautelai-vos do fermento dos fariseus, que é a hipocrisia.");
    b->dados[LUCAS].capitulos[12].versos[2] = wxT("Mas nada há encoberto, que não haja de ser descoberto; nem oculto, que não haja de ser conhecido.");
    b->dados[LUCAS].capitulos[12].versos[3] = wxT("Porquanto tudo o que em trevas dissestes, à luz será ouvido; e o que falaste ao ouvido no gabinete, dos eirados será apregoado.");
    b->dados[LUCAS].capitulos[12].versos[4] = wxT("Digo-vos, amigos meus: Não temais os que matam o corpo, e depois disso nada mais podem fazer.");
    b->dados[LUCAS].capitulos[12].versos[5] = wxT("Mas eu vos mostrarei a quem é que deveis temer; temei aquele que, depois de matar, tem poder para lançar no inferno; sim, digo, a esse temei.");
    b->dados[LUCAS].capitulos[12].versos[6] = wxT("Não se vendem cinco passarinhos por dois asses? E nenhum deles está esquecido diante de Deus.");
    b->dados[LUCAS].capitulos[12].versos[7] = wxT("Mas até os cabelos da vossa cabeça estão todos contados. Não temais, pois mais valeis vós do que muitos passarinhos.");
    b->dados[LUCAS].capitulos[12].versos[8] = wxT("E digo-vos que todo aquele que me confessar diante dos homens, também o Filho do homem o confessará diante dos anjos de Deus;");
    b->dados[LUCAS].capitulos[12].versos[9] = wxT("mas quem me negar diante dos homens, será negado diante dos anjos de Deus.");
    b->dados[LUCAS].capitulos[12].versos[10] = wxT("E a todo aquele que proferir uma palavra contra o Filho do homem, isso lhe será perdoado; mas ao que blasfemar contra o Espírito Santo, não lhe será perdoado.");
    b->dados[LUCAS].capitulos[12].versos[11] = wxT("Quando, pois, vos levarem às sinagogas, aos magistrados e às autoridades, não estejais solícitos de como ou do que haveis de responder, nem do que haveis de dizer.");
    b->dados[LUCAS].capitulos[12].versos[12] = wxT("Porque o Espírito Santo vos ensinará na mesma hora o que deveis dizer.");
    b->dados[LUCAS].capitulos[12].versos[13] = wxT("Disse-lhe alguém dentre a multidão: Mestre, dize a meu irmão que reparte comigo a herança.");
    b->dados[LUCAS].capitulos[12].versos[14] = wxT("Mas ele lhe respondeu: Homem, quem me constituiu a mim juiz ou repartidor entre vós?");
    b->dados[LUCAS].capitulos[12].versos[15] = wxT("E disse ao povo: Acautelai-vos e guardai-vos de toda espécie de cobiça; porque a vida do homem não consiste na abundância das coisas que possui.");
    b->dados[LUCAS].capitulos[12].versos[16] = wxT("Propôs-lhes então uma parábola, dizendo: O campo de um homem rico produzira com abundância;");
    b->dados[LUCAS].capitulos[12].versos[17] = wxT("e ele arrazoava consigo, dizendo: Que farei? Pois não tenho onde recolher os meus frutos.");
    b->dados[LUCAS].capitulos[12].versos[18] = wxT("Disse então: Farei isto: derribarei os meus celeiros e edificarei outros maiores, e ali recolherei todos os meus cereais e os meus bens;");
    b->dados[LUCAS].capitulos[12].versos[19] = wxT("e direi à minha alma: Alma, tens em depósito muitos bens para muitos anos; descansa, come, bebe, regala-te.");
    b->dados[LUCAS].capitulos[12].versos[20] = wxT("Mas Deus lhe disse: Insensato, esta noite te pedirão a tua alma; e o que tens preparado, para quem será?");
    b->dados[LUCAS].capitulos[12].versos[21] = wxT("Assim é aquele que para si ajunta tesouros, e não é rico para com Deus.");
    b->dados[LUCAS].capitulos[12].versos[22] = wxT("E disse aos seus discípulos: Por isso vos digo: Não estejais ansiosos quanto à vossa vida, pelo que haveis de comer, nem quanto ao corpo, pelo que haveis de vestir.");
    b->dados[LUCAS].capitulos[12].versos[23] = wxT("Pois a vida é mais do que o alimento, e o corpo mais do que o vestuário.");
    b->dados[LUCAS].capitulos[12].versos[24] = wxT("Considerai os corvos, que não semeiam nem ceifam; não têm despensa nem celeiro; contudo, Deus os alimenta. Quanto mais não valeis vós do que as aves!");
    b->dados[LUCAS].capitulos[12].versos[25] = wxT("Ora, qual de vós, por mais ansioso que esteja, pode acrescentar um côvado à sua estatura?");
    b->dados[LUCAS].capitulos[12].versos[26] = wxT("Porquanto, se não podeis fazer nem as coisas mínimas, por que estais ansiosos pelas outras?");
    b->dados[LUCAS].capitulos[12].versos[27] = wxT("Considerai os lírios, como crescem; não trabalham, nem fiam; contudo vos digo que nem mesmo Salomão, em toda a sua glória, se vestiu como um deles.");
    b->dados[LUCAS].capitulos[12].versos[28] = wxT("Se, pois, Deus assim veste a erva que hoje está no campo e amanhã é lançada no forno, quanto mais vós, homens de pouca fé?");
    b->dados[LUCAS].capitulos[12].versos[29] = wxT("Não procureis, pois, o que haveis de comer, ou o que haveis de beber, e não andeis preocupados.");
    b->dados[LUCAS].capitulos[12].versos[30] = wxT("Porque a todas estas coisas os povos do mundo procuram; mas vosso Pai sabe que precisais delas.");
    b->dados[LUCAS].capitulos[12].versos[31] = wxT("Buscai antes o seu reino, e estas coisas vos serão acrescentadas.");
    b->dados[LUCAS].capitulos[12].versos[32] = wxT("Não temas, ó pequeno rebanho! porque a vosso Pai agradou dar-vos o reino.");
    b->dados[LUCAS].capitulos[12].versos[33] = wxT("Vendei o que possuís, e dai esmolas. Fazei para vós bolsas que não envelheçam; tesouro nos céus que jamais acabe, aonde não chega ladrão e a traça não rói.");
    b->dados[LUCAS].capitulos[12].versos[34] = wxT("Porque, onde estiver o vosso tesouro, aí estará também o vosso coração.");
    b->dados[LUCAS].capitulos[12].versos[35] = wxT("Estejam cingidos os vossos lombos e acesas as vossas candeias;");
    b->dados[LUCAS].capitulos[12].versos[36] = wxT("e sede semelhantes a homens que esperam o seu senhor, quando houver de voltar das bodas, para que, quando vier e bater, logo possam abrir-lhe.");
    b->dados[LUCAS].capitulos[12].versos[37] = wxT("Bem-aventurados aqueles servos, aos quais o senhor, quando vier, achar vigiando! Em verdade vos digo que se cingirá, e os fará reclinar-se à mesa e, chegando-se, os servirá.");
    b->dados[LUCAS].capitulos[12].versos[38] = wxT("Quer venha na segunda vigília, quer na terceira, bem-aventurados serão eles, se assim os achar.");
    b->dados[LUCAS].capitulos[12].versos[39] = wxT("Sabei, porém, isto: se o dono da casa soubesse a que hora havia de vir o ladrão, vigiaria e não deixaria minar a sua casa.");
    b->dados[LUCAS].capitulos[12].versos[40] = wxT("Estai vós também apercebidos; porque, numa hora em que não penseis, virá o Filho do homem.");
    b->dados[LUCAS].capitulos[12].versos[41] = wxT("Então Pedro perguntou: Senhor, dizes essa parábola a nós, ou também a todos?");
    b->dados[LUCAS].capitulos[12].versos[42] = wxT("Respondeu o Senhor: Qual é, pois, o mordomo fiel e prudente, que o Senhor porá sobre os seus servos, para lhes dar a tempo a ração?");
    b->dados[LUCAS].capitulos[12].versos[43] = wxT("Bem-aventurado aquele servo a quem o seu senhor, quando vier, achar fazendo assim.");
    b->dados[LUCAS].capitulos[12].versos[44] = wxT("Em verdade vos digo que o porá sobre todos os seus bens.");
    b->dados[LUCAS].capitulos[12].versos[45] = wxT("Mas, se aquele servo disser em teu coração: O meu senhor tarda em vir; e começar a espancar os criados e as criadas, e a comer, a beber e a embriagar-se,");
    b->dados[LUCAS].capitulos[12].versos[46] = wxT("virá o senhor desse servo num dia em que não o espera, e numa hora de que não sabe, e cortá-lo-á pelo meio, e lhe dará a sua parte com os infiéis.");
    b->dados[LUCAS].capitulos[12].versos[47] = wxT("O servo que soube a vontade do seu senhor, e não se aprontou, nem fez conforme a sua vontade, será castigado com muitos açoites;");
    b->dados[LUCAS].capitulos[12].versos[48] = wxT("mas o que não a soube, e fez coisas que mereciam castigo, com poucos açoites será castigado. Daquele a quem muito é dado, muito se lhe requererá; e a quem muito é confiado, mais ainda se lhe pedirá.");
    b->dados[LUCAS].capitulos[12].versos[49] = wxT("Vim lançar fogo à terra; e que mais quero, se já está aceso?");
    b->dados[LUCAS].capitulos[12].versos[50] = wxT("Há um batismo em que hei de ser batizado; e como me angustio até que venha a cumprir-se!");
    b->dados[LUCAS].capitulos[12].versos[51] = wxT("Cuidais vós que vim trazer paz à terra? Não, eu vos digo, mas antes dissensão:");
    b->dados[LUCAS].capitulos[12].versos[52] = wxT("pois daqui em diante estarão cinco pessoas numa casa divididas, três contra duas, e duas contra três;");
    b->dados[LUCAS].capitulos[12].versos[53] = wxT("estarão divididos: pai contra filho, e filho contra pai; mãe contra filha, e filha contra mãe; sogra contra nora, e nora contra sogra.");
    b->dados[LUCAS].capitulos[12].versos[54] = wxT("Dizia também às multidões: Quando vedes subir uma nuvem do ocidente, logo dizeis: Lá vem chuva; e assim sucede;");
    b->dados[LUCAS].capitulos[12].versos[55] = wxT("e quando vedes soprar o vento sul dizeis; Haverá calor; e assim sucede.");
    b->dados[LUCAS].capitulos[12].versos[56] = wxT("Hipócritas, sabeis discernir a face da terra e do céu; como não sabeis então discernir este tempo?");
    b->dados[LUCAS].capitulos[12].versos[57] = wxT("E por que não julgais também por vós mesmos o que é justo?");
    b->dados[LUCAS].capitulos[12].versos[58] = wxT("Quando, pois, vais com o teu adversário ao magistrado, procura fazer as pazes com ele no caminho; para que não suceda que ele te arraste ao juiz, e o juiz te entregue ao meirinho, e o meirinho te lance na prisão");
    b->dados[LUCAS].capitulos[12].versos[59] = wxT("Digo-te que não sairás dali enquanto não pagares o derradeiro lepto.");

    b->dados[LUCAS].capitulos[13].versos[1] = wxT("Ora, naquele mesmo tempo estavam presentes alguns que lhe falavam dos galileus cujo sangue Pilatos misturara com os sacrifícios deles.");
    b->dados[LUCAS].capitulos[13].versos[2] = wxT("Respondeu-lhes Jesus: Pensais vós que esses foram maiores pecadores do que todos os galileus, por terem padecido tais coisas?");
    b->dados[LUCAS].capitulos[13].versos[3] = wxT("Não, eu vos digo; antes, se não vos arrependerdes, todos de igual modo perecereis.");
    b->dados[LUCAS].capitulos[13].versos[4] = wxT("Ou pensais que aqueles dezoito, sobre os quais caiu a torre de Siloé e os matou, foram mais culpados do que todos os outros habitantes de Jerusalém?");
    b->dados[LUCAS].capitulos[13].versos[5] = wxT("Não, eu vos digo; antes, se não vos arrependerdes, todos de igual modo perecereis.");
    b->dados[LUCAS].capitulos[13].versos[6] = wxT("E passou a narrar esta parábola: Certo homem tinha uma figueira plantada na sua vinha; e indo procurar fruto nela, e não o achou.");
    b->dados[LUCAS].capitulos[13].versos[7] = wxT("Disse então ao viticultor: Eis que há três anos venho procurar fruto nesta figueira, e não o acho; corta-a; para que ocupa ela ainda a terra inutilmente?");
    b->dados[LUCAS].capitulos[13].versos[8] = wxT("Respondeu-lhe ele: Senhor, deixa-a este ano ainda, até que eu cave em derredor, e lhe deite estrume;");
    b->dados[LUCAS].capitulos[13].versos[9] = wxT("e se no futuro der fruto, bem; mas, se não, cortá-la-ás.");
    b->dados[LUCAS].capitulos[13].versos[10] = wxT("Jesus estava ensinando numa das sinagogas no sábado.");
    b->dados[LUCAS].capitulos[13].versos[11] = wxT("E estava ali uma mulher que tinha um espírito de enfermidade havia já dezoito anos; e andava encurvada, e não podia de modo algum endireitar-se.");
    b->dados[LUCAS].capitulos[13].versos[12] = wxT("Vendo-a Jesus, chamou-a, e disse-lhe: Mulher, estás livre da tua enfermidade;");
    b->dados[LUCAS].capitulos[13].versos[13] = wxT("e impôs-lhe as mãos e imediatamente ela se endireitou, e glorificava a Deus.");
    b->dados[LUCAS].capitulos[13].versos[14] = wxT("Então o chefe da sinagoga, indignado porque Jesus curara no sábado, tomando a palavra disse à multidão: Seis dias há em que se deve trabalhar; vinde, pois, neles para serdes curados, e não no dia de sábado.");
    b->dados[LUCAS].capitulos[13].versos[15] = wxT("Respondeu-lhe, porém, o Senhor: Hipócritas, no sábado não desprende da manjedoura cada um de vós o seu boi, ou jumento, para o levar a beber?");
    b->dados[LUCAS].capitulos[13].versos[16] = wxT("E não devia ser solta desta prisão, no dia de sábado, esta que é filha de Abraão, a qual há dezoito anos Satanás tinha presa?");
    b->dados[LUCAS].capitulos[13].versos[17] = wxT("E dizendo ele essas coisas, todos os seus adversário ficavam envergonhados; e todo o povo se alegrava por todas as coisas gloriosas que eram feitas por ele.");
    b->dados[LUCAS].capitulos[13].versos[18] = wxT("Ele, pois, dizia: A que é semelhante o reino de Deus, e a que o compararei?");
    b->dados[LUCAS].capitulos[13].versos[19] = wxT("É semelhante a um grão de mostarda que um homem tomou e lançou na sua horta; cresceu, e fez-se árvore, e em seus ramos se aninharam as aves do céu.");
    b->dados[LUCAS].capitulos[13].versos[20] = wxT("E disse outra vez: A que compararei o reino de Deus?");
    b->dados[LUCAS].capitulos[13].versos[21] = wxT("É semelhante ao fermento que uma mulher tomou e misturou com três medidas de farinha, até ficar toda ela levedada.");
    b->dados[LUCAS].capitulos[13].versos[22] = wxT("Assim percorria Jesus as cidades e as aldeias, ensinando, e caminhando para Jerusalém.");
    b->dados[LUCAS].capitulos[13].versos[23] = wxT("E alguém lhe perguntou: Senhor, são poucos os que se salvam? Ao que ele lhes respondeu:");
    b->dados[LUCAS].capitulos[13].versos[24] = wxT("Porfiai por entrar pela porta estreita; porque eu vos digo que muitos procurarão entrar, e não poderão.");
    b->dados[LUCAS].capitulos[13].versos[25] = wxT("Quando o dono da casa se tiver levantado e cerrado a porta, e vós começardes, de fora, a bater à porta, dizendo: Senhor, abre-nos; e ele vos responder: Não sei donde vós sois;");
    b->dados[LUCAS].capitulos[13].versos[26] = wxT("então começareis a dizer: Comemos e bebemos na tua presença, e tu ensinaste nas nossas ruas;");
    b->dados[LUCAS].capitulos[13].versos[27] = wxT("e ele vos responderá: Não sei donde sois; apartai-vos de mim, vós todos os que praticais a iniqüidade.");
    b->dados[LUCAS].capitulos[13].versos[28] = wxT("Ali haverá choro e ranger de dentes quando virdes Abraão, Isaque, Jacó e todos os profetas no reino de Deus, e vós lançados fora.");
    b->dados[LUCAS].capitulos[13].versos[29] = wxT("Muitos virão do oriente e do ocidente, do norte e do sul, e reclinar-se-ão à mesa no reino de Deus.");
    b->dados[LUCAS].capitulos[13].versos[30] = wxT("Pois há últimos que serão primeiros, e primeiros que serão últimos.");
    b->dados[LUCAS].capitulos[13].versos[31] = wxT("Naquela mesma hora chegaram alguns fariseus que lhe disseram: Sai, e retira-te daqui, porque Herodes quer matar-te.");
    b->dados[LUCAS].capitulos[13].versos[32] = wxT("Respondeu-lhes Jesus: Ide e dizei a essa raposa: Eis que vou expulsando demônios e fazendo curas, hoje e amanhã, e no terceiro dia serei consumado.");
    b->dados[LUCAS].capitulos[13].versos[33] = wxT("Importa, contudo, caminhar hoje, amanhã, e no dia seguinte; porque não convém que morra um profeta fora de Jerusalém.");
    b->dados[LUCAS].capitulos[13].versos[34] = wxT("Jerusalém, Jerusalém, que matas os profetas, e apedrejas os que a ti são enviados! Quantas vezes quis eu ajuntar os teus filhos, como a galinha ajunta a sua ninhada debaixo das asas, e não quiseste!");
    b->dados[LUCAS].capitulos[13].versos[35] = wxT("Eis aí, abandonada vos é a vossa casa. E eu vos digo que não me vereis até que venha o tempo em que digais: Bendito aquele que vem em nome do Senhor.");

    b->dados[LUCAS].capitulos[14].versos[1] = wxT("Tendo Jesus entrado, num sábado, em casa de um dos chefes dos fariseus para comer pão, eles o estavam observando.");
    b->dados[LUCAS].capitulos[14].versos[2] = wxT("Achava-se ali diante dele certo homem hidrópico.");
    b->dados[LUCAS].capitulos[14].versos[3] = wxT("E Jesus, tomando a palavra, falou aos doutores da lei e aos fariseus, e perguntou: É lícito curar no sábado, ou não?");
    b->dados[LUCAS].capitulos[14].versos[4] = wxT("Eles, porém, ficaram calados. E Jesus, pegando no homem, o curou, e o despediu.");
    b->dados[LUCAS].capitulos[14].versos[5] = wxT("Então lhes perguntou: Qual de vós, se lhe cair num poço um filho, ou um boi, não o tirará logo, mesmo em dia de sábado?");
    b->dados[LUCAS].capitulos[14].versos[6] = wxT("A isto nada puderam responder.");
    b->dados[LUCAS].capitulos[14].versos[7] = wxT("Ao notar como os convidados escolhiam os primeiros lugares, propôs-lhes esta parábola:");
    b->dados[LUCAS].capitulos[14].versos[8] = wxT("Quando por alguém fores convidado às bodas, não te reclines no primeiro lugar; não aconteça que esteja convidado outro mais digno do que tu;");
    b->dados[LUCAS].capitulos[14].versos[9] = wxT("e vindo o que te convidou a ti e a ele, te diga: Dá o lugar a este; e então, com vergonha, tenhas de tomar o último lugar.");
    b->dados[LUCAS].capitulos[14].versos[10] = wxT("Mas, quando fores convidado, vai e reclina-te no último lugar, para que, quando vier o que te convidou, te diga: Amigo, sobe mais para cima. Então terás honra diante de todos os que estiverem contigo à mesa.");
    b->dados[LUCAS].capitulos[14].versos[11] = wxT("Porque todo o que a si mesmo se exaltar será humilhado, e aquele que a si mesmo se humilhar será exaltado.");
    b->dados[LUCAS].capitulos[14].versos[12] = wxT("Disse também ao que o havia convidado: Quando deres um jantar, ou uma ceia, não convides teus amigos, nem teus irmãos, nem teus parentes, nem os vizinhos ricos, para que não suceda que também eles te tornem a convidar, e te seja isso retribuído.");
    b->dados[LUCAS].capitulos[14].versos[13] = wxT("Mas quando deres um banquete, convida os pobres, os aleijados, os mancos e os cegos;");
    b->dados[LUCAS].capitulos[14].versos[14] = wxT("e serás bem-aventurado; porque eles não têm com que te retribuir; pois retribuído te será na ressurreição dos justos.");
    b->dados[LUCAS].capitulos[14].versos[15] = wxT("Ao ouvir isso um dos que estavam com ele à mesa, disse-lhe: Bem-aventurado aquele que comer pão no reino de Deus.");
    b->dados[LUCAS].capitulos[14].versos[16] = wxT("Jesus, porém, lhe disse: Certo homem dava uma grande ceia, e convidou a muitos.");
    b->dados[LUCAS].capitulos[14].versos[17] = wxT("E à hora da ceia mandou o seu servo dizer aos convidados: vinde, porque tudo já está preparado.");
    b->dados[LUCAS].capitulos[14].versos[18] = wxT("Mas todos à uma começaram a escusar-se. Disse-lhe o primeiro: Comprei um campo, e preciso ir vê-lo; rogo-te que me dês por escusado.");
    b->dados[LUCAS].capitulos[14].versos[19] = wxT("Outro disse: Comprei cinco juntas de bois, e vou experimentá-los; rogo-te que me dês por escusado.");
    b->dados[LUCAS].capitulos[14].versos[20] = wxT("Ainda outro disse: Casei-me e portanto não posso ir.");
    b->dados[LUCAS].capitulos[14].versos[21] = wxT("Voltou o servo e contou tudo isto a seu senhor: Então o dono da casa, indignado, disse a seu servo: Sai depressa para as ruas e becos da cidade e traze aqui os pobres, os aleijados, os cegos e os coxos.");
    b->dados[LUCAS].capitulos[14].versos[22] = wxT("Depois disse o servo: Senhor, feito está como o ordenaste, e ainda há lugar.");
    b->dados[LUCAS].capitulos[14].versos[23] = wxT("Respondeu o senhor ao servo: Sai pelos caminhos e valados, e obriga-os a entrar, para que a minha casa se encha.");
    b->dados[LUCAS].capitulos[14].versos[24] = wxT("Pois eu vos digo que nenhum daqueles homens que foram convidados provará a minha ceia.");
    b->dados[LUCAS].capitulos[14].versos[25] = wxT("Ora, iam com ele grandes multidões; e, voltando-se, disse-lhes:");
    b->dados[LUCAS].capitulos[14].versos[26] = wxT("Se alguém vier a mim, e não aborrecer a pai e mãe, a mulher e filhos, a irmãos e irmãs, e ainda também à própria vida, não pode ser meu discípulo.");
    b->dados[LUCAS].capitulos[14].versos[27] = wxT("Quem não leva a sua cruz e não me segue, não pode ser meu discípulo.");
    b->dados[LUCAS].capitulos[14].versos[28] = wxT("Pois qual de vós, querendo edificar uma torre, não se senta primeiro a calcular as despesas, para ver se tem com que a acabar?");
    b->dados[LUCAS].capitulos[14].versos[29] = wxT("Para não acontecer que, depois de haver posto os alicerces, e não a podendo acabar, todos os que a virem comecem a zombar dele,");
    b->dados[LUCAS].capitulos[14].versos[30] = wxT("dizendo: Este homem começou a edificar e não pode acabar.");
    b->dados[LUCAS].capitulos[14].versos[31] = wxT("Ou qual é o rei que, indo entrar em guerra contra outro rei, não se senta primeiro a consultar se com dez mil pode sair ao encontro do que vem contra ele com vinte mil?");
    b->dados[LUCAS].capitulos[14].versos[32] = wxT("No caso contrário, enquanto o outro ainda está longe, manda embaixadores, e pede condições de paz.");
    b->dados[LUCAS].capitulos[14].versos[33] = wxT("Assim, pois, todo aquele dentre vós que não renuncia a tudo quanto possui, não pode ser meu discípulo.");
    b->dados[LUCAS].capitulos[14].versos[34] = wxT("Bom é o sal; mas se o sal se tornar insípido, com que se há de restaurar-lhe o sabor?");
    b->dados[LUCAS].capitulos[14].versos[35] = wxT("Não presta nem para terra, nem para adubo; lançam-no fora. Quem tem ouvidos para ouvir, ouça.");

    b->dados[LUCAS].capitulos[15].versos[1] = wxT("Ora, chegavam-se a ele todos os publicanos e pecadores para o ouvir.");
    b->dados[LUCAS].capitulos[15].versos[2] = wxT("E os fariseus e os escribas murmuravam, dizendo: Este recebe pecadores, e come com eles.");
    b->dados[LUCAS].capitulos[15].versos[3] = wxT("Então ele lhes propôs esta parábola:");
    b->dados[LUCAS].capitulos[15].versos[4] = wxT("Qual de vós é o homem que, possuindo cem ovelhas, e perdendo uma delas, não deixa as noventa e nove no deserto, e não vai após a perdida até que a encontre?");
    b->dados[LUCAS].capitulos[15].versos[5] = wxT("E achando-a, põe-na sobre os ombros, cheio de júbilo;");
    b->dados[LUCAS].capitulos[15].versos[6] = wxT("e chegando a casa, reúne os amigos e vizinhos e lhes diz: Alegrai-vos comigo, porque achei a minha ovelha que se havia perdido.");
    b->dados[LUCAS].capitulos[15].versos[7] = wxT("Digo-vos que assim haverá maior alegria no céu por um pecador que se arrepende, do que por noventa e nove justos que não necessitam de arrependimento.");
    b->dados[LUCAS].capitulos[15].versos[8] = wxT("Ou qual é a mulher que, tendo dez dracmas e perdendo uma dracma, não acende a candeia, e não varre a casa, buscando com diligência até encontrá-la?");
    b->dados[LUCAS].capitulos[15].versos[9] = wxT("E achando-a, reúne as amigas e vizinhas, dizendo: Alegrai-vos comigo, porque achei a dracma que eu havia perdido.");
    b->dados[LUCAS].capitulos[15].versos[10] = wxT("Assim, digo-vos, há alegria na presença dos anjos de Deus por um só pecador que se arrepende.");
    b->dados[LUCAS].capitulos[15].versos[11] = wxT("Disse-lhe mais: Certo homem tinha dois filhos.");
    b->dados[LUCAS].capitulos[15].versos[12] = wxT("O mais moço deles disse ao pai: Pai, dá-me a parte dos bens que me toca. Repartiu-lhes, pois, os seus haveres.");
    b->dados[LUCAS].capitulos[15].versos[13] = wxT("Poucos dias depois, o filho mais moço ajuntando tudo, partiu para um país distante, e ali desperdiçou os seus bens, vivendo dissolutamente.");
    b->dados[LUCAS].capitulos[15].versos[14] = wxT("E, havendo ele dissipado tudo, houve naquela terra uma grande fome, e começou a passar necessidades.");
    b->dados[LUCAS].capitulos[15].versos[15] = wxT("Então foi encontrar-se a um dos cidadãos daquele país, o qual o mandou para os seus campos a apascentar porcos.");
    b->dados[LUCAS].capitulos[15].versos[16] = wxT("E desejava encher o estômago com as alfarrobas que os porcos comiam; e ninguém lhe dava nada.");
    b->dados[LUCAS].capitulos[15].versos[17] = wxT("Caindo, porém, em si, disse: Quantos empregados de meu pai têm abundância de pão, e eu aqui pereço de fome!");
    b->dados[LUCAS].capitulos[15].versos[18] = wxT("Levantar-me-ei, irei ter com meu pai e dir-lhe-ei: Pai, pequei contra o céu e diante de ti;");
    b->dados[LUCAS].capitulos[15].versos[19] = wxT("já não sou digno de ser chamado teu filho; trata-me como um dos teus empregados.");
    b->dados[LUCAS].capitulos[15].versos[20] = wxT("Levantou-se, pois, e foi para seu pai. Estando ele ainda longe, seu pai o viu, encheu-se de compaixão e, correndo, lançou-se-lhe ao pescoço e o beijou.");
    b->dados[LUCAS].capitulos[15].versos[21] = wxT("Disse-lhe o filho: Pai, pequei conta o céu e diante de ti; já não sou digno de ser chamado teu filho.");
    b->dados[LUCAS].capitulos[15].versos[22] = wxT("Mas o pai disse aos seus servos: Trazei depressa a melhor roupa, e vesti-lha, e ponde-lhe um anel no dedo e alparcas nos pés;");
    b->dados[LUCAS].capitulos[15].versos[23] = wxT("trazei também o bezerro, cevado e matai-o; comamos, e regozijemo-nos,");
    b->dados[LUCAS].capitulos[15].versos[24] = wxT("porque este meu filho estava morto, e reviveu; tinha-se perdido, e foi achado. E começaram a regozijar-se.");
    b->dados[LUCAS].capitulos[15].versos[25] = wxT("Ora, o seu filho mais velho estava no campo; e quando voltava, ao aproximar-se de casa, ouviu a música e as danças;");
    b->dados[LUCAS].capitulos[15].versos[26] = wxT("e chegando um dos servos, perguntou-lhe que era aquilo.");
    b->dados[LUCAS].capitulos[15].versos[27] = wxT("Respondeu-lhe este: Chegou teu irmão; e teu pai matou o bezerro cevado, porque o recebeu são e salvo.");
    b->dados[LUCAS].capitulos[15].versos[28] = wxT("Mas ele se indignou e não queria entrar. Saiu então o pai e instava com ele.");
    b->dados[LUCAS].capitulos[15].versos[29] = wxT("Ele, porém, respondeu ao pai: Eis que há tantos anos te sirvo, e nunca transgredi um mandamento teu; contudo nunca me deste um cabrito para eu me regozijar com meus amigos;");
    b->dados[LUCAS].capitulos[15].versos[30] = wxT("vindo, porém, este teu filho, que desperdiçou os teus bens com as meretrizes, mataste-lhe o bezerro cevado.");
    b->dados[LUCAS].capitulos[15].versos[31] = wxT("Replicou-lhe o pai: Filho, tu sempre estás comigo, e tudo o que é meu é teu;");
    b->dados[LUCAS].capitulos[15].versos[32] = wxT("era justo, porém, regozijarmo-nos e alegramo-nos, porque este teu irmão estava morto, e reviveu; tinha-se perdido, e foi achado.");

    b->dados[LUCAS].capitulos[16].versos[1] = wxT("Dizia Jesus também aos seus discípulos: Havia certo homem rico, que tinha um mordomo; e este foi acusado perante ele de estar dissipando os seus bens.");
    b->dados[LUCAS].capitulos[16].versos[2] = wxT("Chamou-o, então, e lhe disse: Que é isso que ouço dizer de ti? Presta contas da tua mordomia; porque já não podes mais ser meu mordomo.");
    b->dados[LUCAS].capitulos[16].versos[3] = wxT("Disse, pois, o mordomo consigo: Que hei de fazer, já que o meu senhor me tira a mordomia? Para cavar, não tenho forças; de mendigar, tenho vergonha.");
    b->dados[LUCAS].capitulos[16].versos[4] = wxT("Agora sei o que vou fazer, para que, quando for desapossado da mordomia, me recebam em suas casas.");
    b->dados[LUCAS].capitulos[16].versos[5] = wxT("E chamando a si cada um dos devedores do seu senhor, perguntou ao primeiro: Quanto deves ao meu senhor?");
    b->dados[LUCAS].capitulos[16].versos[6] = wxT("Respondeu ele: Cem cados de azeite. Disse-lhe então: Toma a tua conta, senta-te depressa e escreve cinqüenta.");
    b->dados[LUCAS].capitulos[16].versos[7] = wxT("Perguntou depois a outro: E tu, quanto deves? Respondeu ele: Cem coros de trigo. E disse-lhe: Toma a tua conta e escreve oitenta.");
    b->dados[LUCAS].capitulos[16].versos[8] = wxT("E louvou aquele senhor ao injusto mordomo por haver procedido com sagacidade; porque os filhos deste mundo são mais sagazes para com a sua geração do que os filhos da luz.");
    b->dados[LUCAS].capitulos[16].versos[9] = wxT("Eu vos digo ainda: Granjeai amigos por meio das riquezas da injustiça; para que, quando estas vos faltarem, vos recebam eles nos tabernáculos eternos.");
    b->dados[LUCAS].capitulos[16].versos[10] = wxT("Quem é fiel no pouco, também é fiel no muito; quem é injusto no pouco, também é injusto no muito.");
    b->dados[LUCAS].capitulos[16].versos[11] = wxT("Se, pois, nas riquezas injustas não fostes fiéis, quem vos confiará as verdadeiras?");
    b->dados[LUCAS].capitulos[16].versos[12] = wxT("E se no alheio não fostes fiéis, quem vos dará o que é vosso?");
    b->dados[LUCAS].capitulos[16].versos[13] = wxT("Nenhum servo pode servir dois senhores; porque ou há de odiar a um e amar ao outro, o há de odiar a um e amar ao outro, o há de dedicar-se a um e desprezar o outro. Não podeis servir a Deus e às riquezas.");
    b->dados[LUCAS].capitulos[16].versos[14] = wxT("Os fariseus, que eram gananciosos, ouviam todas essas coisas e zombavam dele.");
    b->dados[LUCAS].capitulos[16].versos[15] = wxT("E ele lhes disse: Vós sois os que vos justificais a vós mesmos diante dos homens, mas Deus conhece os vossos corações; porque o que entre os homens é elevado, perante Deus é abominação.");
    b->dados[LUCAS].capitulos[16].versos[16] = wxT("A lei e os profetas vigoraram até João; desde então é anunciado o evangelho do reino de Deus, e todo homem forceja por entrar nele.");
    b->dados[LUCAS].capitulos[16].versos[17] = wxT("É, porém, mais fácil passar o céu e a terra do que cair um til da lei.");
    b->dados[LUCAS].capitulos[16].versos[18] = wxT("Todo aquele que repudia sua mulher e casa com outra, comete adultério; e quem casa com a que foi repudiada pelo marido, também comete adultério.");
    b->dados[LUCAS].capitulos[16].versos[19] = wxT("Ora, havia um homem rico que se vestia de púrpura e de linho finíssimo, e todos os dias se regalava esplendidamente.");
    b->dados[LUCAS].capitulos[16].versos[20] = wxT("Ao seu portão fora deitado um mendigo, chamado Lázaro, todo coberto de úlceras;");
    b->dados[LUCAS].capitulos[16].versos[21] = wxT("o qual desejava alimentar-se com as migalhas que caíam da mesa do rico; e os próprios cães vinham lamber-lhe as úlceras.");
    b->dados[LUCAS].capitulos[16].versos[22] = wxT("Veio a morrer o mendigo, e foi levado pelos anjos para o seio de Abraão; morreu também o rico, e foi sepultado.");
    b->dados[LUCAS].capitulos[16].versos[23] = wxT("No inferno, ergueu os olhos, estando em tormentos, e viu ao longe a Abraão, e a Lázaro no seu seio.");
    b->dados[LUCAS].capitulos[16].versos[24] = wxT("E, clamando, disse: Pai Abraão, tem misericórdia de mim, e envia-me Lázaro, para que molhe na água a ponta do dedo e me refresque a língua, porque estou atormentado nesta chama.");
    b->dados[LUCAS].capitulos[16].versos[25] = wxT("Disse, porém, Abraão: Filho, lembra-te de que em tua vida recebeste os teus bens, e Lázaro de igual modo os males; agora, porém, ele aqui é consolado, e tu atormentado.");
    b->dados[LUCAS].capitulos[16].versos[26] = wxT("E além disso, entre nós e vós está posto um grande abismo, de sorte que os que quisessem passar daqui para vós não poderiam, nem os de lá passar para nós.");
    b->dados[LUCAS].capitulos[16].versos[27] = wxT("Disse ele então: Rogo-te, pois, ó pai, que o mandes à casa de meu pai,");
    b->dados[LUCAS].capitulos[16].versos[28] = wxT("porque tenho cinco irmãos; para que lhes dê testemunho, a fim de que não venham eles também para este lugar de tormento.");
    b->dados[LUCAS].capitulos[16].versos[29] = wxT("Disse-lhe Abraão: Têm Moisés e os profetas; ouçam-nos.");
    b->dados[LUCAS].capitulos[16].versos[30] = wxT("Respondeu ele: Não! pai Abraão; mas, se alguém dentre os mortos for ter com eles, hão de se arrepender.");
    b->dados[LUCAS].capitulos[16].versos[31] = wxT("Abraão, porém, lhe disse: Se não ouvem a Moisés e aos profetas, tampouco acreditarão, ainda que ressuscite alguém dentre os mortos.");

    b->dados[LUCAS].capitulos[17].versos[1] = wxT("Disse Jesus a seus discípulos: É impossível que não venham tropeços, mas ai daquele por quem vierem!");
    b->dados[LUCAS].capitulos[17].versos[2] = wxT("Melhor lhe fora que se lhe pendurasse ao pescoço uma pedra de moinho e fosse lançado ao mar, do que fazer tropeçar um destes pequeninos.");
    b->dados[LUCAS].capitulos[17].versos[3] = wxT("Tende cuidado de vós mesmos; se teu irmão pecar, repreende-o; e se ele se arrepender, perdoa-lhe.");
    b->dados[LUCAS].capitulos[17].versos[4] = wxT("Mesmo se pecar contra ti sete vezes no dia, e sete vezes vier ter contigo, dizendo: Arrependo-me; tu lhe perdoarás.");
    b->dados[LUCAS].capitulos[17].versos[5] = wxT("Disseram então os apóstolos ao Senhor: Aumenta-nos a fé.");
    b->dados[LUCAS].capitulos[17].versos[6] = wxT("Respondeu o Senhor: Se tivésseis fé como um grão de mostarda, diríeis a esta amoreira: Desarraiga-te, e planta-te no mar; e ela vos obedeceria.");
    b->dados[LUCAS].capitulos[17].versos[7] = wxT("Qual de vós, tendo um servo a lavrar ou a apascentar gado, lhe dirá, ao voltar ele do campo: chega-te já, e reclina-te à mesa?");
    b->dados[LUCAS].capitulos[17].versos[8] = wxT("Não lhe dirá antes: Prepara-me a ceia, e cinge-te, e serve-me, até que eu tenha comido e bebido, e depois comerás tu e beberás?");
    b->dados[LUCAS].capitulos[17].versos[9] = wxT("Porventura agradecerá ao servo, porque este fez o que lhe foi mandado?");
    b->dados[LUCAS].capitulos[17].versos[10] = wxT("Assim também vós, quando fizerdes tudo o que vos for mandado, dizei: Somos servos inúteis; fizemos somente o que devíamos fazer.");
    b->dados[LUCAS].capitulos[17].versos[11] = wxT("E aconteceu que, indo ele a Jerusalém, passava pela divisa entre a Samária e a Galiléia.");
    b->dados[LUCAS].capitulos[17].versos[12] = wxT("Ao entrar em certa aldeia, saíram-lhe ao encontro dez leprosos, os quais pararam de longe,");
    b->dados[LUCAS].capitulos[17].versos[13] = wxT("e levantaram a voz, dizendo: Jesus, Mestre, tem compaixão de nós!");
    b->dados[LUCAS].capitulos[17].versos[14] = wxT("Ele, logo que os viu, disse-lhes: Ide, e mostrai-vos aos sacerdotes. E aconteceu que, enquanto iam, ficaram limpos.");
    b->dados[LUCAS].capitulos[17].versos[15] = wxT("Um deles, vendo que fora curado, voltou glorificando a Deus em alta voz;");
    b->dados[LUCAS].capitulos[17].versos[16] = wxT("e prostrou-se com o rosto em terra aos pés de Jesus, dando-lhe graças; e este era samaritano.");
    b->dados[LUCAS].capitulos[17].versos[17] = wxT("Perguntou, pois, Jesus: Não foram limpos os dez? E os nove, onde estão?");
    b->dados[LUCAS].capitulos[17].versos[18] = wxT("Não se achou quem voltasse para dar glória a Deus, senão este estrangeiro?");
    b->dados[LUCAS].capitulos[17].versos[19] = wxT("E disse-lhe: Levanta-te, e vai; a tua fé te salvou.");
    b->dados[LUCAS].capitulos[17].versos[20] = wxT("Sendo Jesus interrogado pelos fariseus sobre quando viria o reino de Deus, respondeu-lhes: O reino de Deus não vem com aparência exterior;");
    b->dados[LUCAS].capitulos[17].versos[21] = wxT("nem dirão: Ei-lo aqui! ou: Ei-lo ali! pois o reino de Deus está dentro de vós.");
    b->dados[LUCAS].capitulos[17].versos[22] = wxT("Então disse aos discípulos: Dias virão em que desejareis ver um dos dias do Filho do homem, e não o vereis.");
    b->dados[LUCAS].capitulos[17].versos[23] = wxT("Dir-vos-ão: Ei-lo ali! ou: Ei-lo aqui! não vades, nem os sigais;");
    b->dados[LUCAS].capitulos[17].versos[24] = wxT("pois, assim como o relâmpago, fuzilando em uma extremidade do céu, ilumina até a outra extremidade, assim será também o Filho do homem no seu dia.");
    b->dados[LUCAS].capitulos[17].versos[25] = wxT("Mas primeiro é necessário que ele padeça muitas coisas, e que seja rejeitado por esta geração.");
    b->dados[LUCAS].capitulos[17].versos[26] = wxT("Como aconteceu nos dias de Noé, assim também será nos dias do Filho do homem.");
    b->dados[LUCAS].capitulos[17].versos[27] = wxT("Comiam, bebiam, casavam e davam-se em casamento, até o dia em que Noé entrou na arca, e veio o dilúvio e os destruiu a todos.");
    b->dados[LUCAS].capitulos[17].versos[28] = wxT("Como também da mesma forma aconteceu nos dias de Ló: comiam, bebiam, compravam, vendiam, plantavam e edificavam;");
    b->dados[LUCAS].capitulos[17].versos[29] = wxT("mas no dia em que Ló saiu de Sodoma choveu do céu fogo e enxofre, e os destruiu a todos;");
    b->dados[LUCAS].capitulos[17].versos[30] = wxT("assim será no dia em que o Filho do homem se há de manifestar.");
    b->dados[LUCAS].capitulos[17].versos[31] = wxT("Naquele dia, quem estiver no eirado, tendo os seus bens em casa, não desça para tirá-los; e, da mesma sorte, o que estiver no campo, não volte para trás.");
    b->dados[LUCAS].capitulos[17].versos[32] = wxT("Lembrai-vos da mulher de Ló.");
    b->dados[LUCAS].capitulos[17].versos[33] = wxT("Qualquer que procurar preservar a sua vida, perdê-la-á, e qualquer que a perder, conservá-la-á.");
    b->dados[LUCAS].capitulos[17].versos[34] = wxT("Digo-vos: Naquela noite estarão dois numa cama; um será tomado, e o outro será deixado.");
    b->dados[LUCAS].capitulos[17].versos[35] = wxT("Duas mulheres estarão juntas moendo; uma será tomada, e a outra será deixada.");
    b->dados[LUCAS].capitulos[17].versos[36] = wxT("{Dois homens estarão no campo; um será tomado, e o outro será deixado.}");
    b->dados[LUCAS].capitulos[17].versos[37] = wxT("Perguntaram-lhe: Onde, Senhor? E respondeu-lhes: Onde estiver o corpo, aí se ajuntarão também os abutres.");

    b->dados[LUCAS].capitulos[18].versos[1] = wxT("Contou-lhes também uma parábola sobre o dever de orar sempre, e nunca desfalecer.");
    b->dados[LUCAS].capitulos[18].versos[2] = wxT("dizendo: Havia em certa cidade um juiz que não temia a Deus, nem respeitava os homens.");
    b->dados[LUCAS].capitulos[18].versos[3] = wxT("Havia também naquela mesma cidade uma viúva que ia ter com ele, dizendo: Faze-me justiça contra o meu adversário.");
    b->dados[LUCAS].capitulos[18].versos[4] = wxT("E por algum tempo não quis atendê-la; mas depois disse consigo: Ainda que não temo a Deus, nem respeito os homens,");
    b->dados[LUCAS].capitulos[18].versos[5] = wxT("todavia, como esta viúva me incomoda, hei de fazer-lhe justiça, para que ela não continue a vir molestar-me.");
    b->dados[LUCAS].capitulos[18].versos[6] = wxT("Prosseguiu o Senhor: Ouvi o que diz esse juiz injusto.");
    b->dados[LUCAS].capitulos[18].versos[7] = wxT("E não fará Deus justiça aos seus escolhidos, que dia e noite clamam a ele, já que é longânimo para com eles?");
    b->dados[LUCAS].capitulos[18].versos[8] = wxT("Digo-vos que depressa lhes fará justiça. Contudo quando vier o Filho do homem, porventura achará fé na terra?");
    b->dados[LUCAS].capitulos[18].versos[9] = wxT("Propôs também esta parábola a uns que confiavam em si mesmos, crendo que eram justos, e desprezavam os outros:");
    b->dados[LUCAS].capitulos[18].versos[10] = wxT("Dois homens subiram ao templo para orar; um fariseu, e o outro publicano.");
    b->dados[LUCAS].capitulos[18].versos[11] = wxT("O fariseu, de pé, assim orava consigo mesmo: ó Deus, graças te dou que não sou como os demais homens, roubadores, injustos, adúlteros, nem ainda com este publicano.");
    b->dados[LUCAS].capitulos[18].versos[12] = wxT("Jejuo duas vezes na semana, e dou o dízimo de tudo quanto ganho.");
    b->dados[LUCAS].capitulos[18].versos[13] = wxT("Mas o publicano, estando em pé de longe, nem ainda queria levantar os olhos ao céu, mas batia no peito, dizendo: ó Deus, sê propício a mim, o pecador!");
    b->dados[LUCAS].capitulos[18].versos[14] = wxT("Digo-vos que este desceu justificado para sua casa, e não aquele; porque todo o que a si mesmo se exaltar será humilhado; mas o que a si mesmo se humilhar será exaltado.");
    b->dados[LUCAS].capitulos[18].versos[15] = wxT("Traziam-lhe também as crianças, para que as tocasse; mas os discípulos, vendo isso, os repreendiam.");
    b->dados[LUCAS].capitulos[18].versos[16] = wxT("Jesus, porém, chamando-as para si, disse: Deixai vir a mim as crianças, e não as impeçais, porque de tais é o reino de Deus.");
    b->dados[LUCAS].capitulos[18].versos[17] = wxT("Em verdade vos digo que, qualquer que não receber o reino de Deus como criança, de modo algum entrará nele.");
    b->dados[LUCAS].capitulos[18].versos[18] = wxT("E perguntou-lhe um dos principais: Bom Mestre, que hei de fazer para herdar a vida eterna?");
    b->dados[LUCAS].capitulos[18].versos[19] = wxT("Respondeu-lhe Jesus: Por que me chamas bom? Ninguém é bom, senão um, que é Deus.");
    b->dados[LUCAS].capitulos[18].versos[20] = wxT("Sabes os mandamentos: Não adulterarás; não matarás; não furtarás; não dirás falso testemunho; honra a teu pai e a tua mãe.");
    b->dados[LUCAS].capitulos[18].versos[21] = wxT("Replicou o homem: Tudo isso tenho guardado desde a minha juventude.");
    b->dados[LUCAS].capitulos[18].versos[22] = wxT("Quando Jesus ouviu isso, disse-lhe: Ainda te falta uma coisa; vende tudo quanto tens e reparte-o pelos pobres, e terás um tesouro no céu; e vem, segue-me.");
    b->dados[LUCAS].capitulos[18].versos[23] = wxT("Mas, ouvindo ele isso, encheu-se de tristeza; porque era muito rico.");
    b->dados[LUCAS].capitulos[18].versos[24] = wxT("E Jesus, vendo-o assim, disse: Quão dificilmente entrarão no reino de Deus os que têm riquezas!");
    b->dados[LUCAS].capitulos[18].versos[25] = wxT("Pois é mais fácil um camelo passar pelo fundo duma agulha, do que entrar um rico no reino de Deus.");
    b->dados[LUCAS].capitulos[18].versos[26] = wxT("Então os que ouviram isso disseram: Quem pode, então, ser salvo?");
    b->dados[LUCAS].capitulos[18].versos[27] = wxT("Respondeu-lhes: As coisas que são impossíveis aos homens são possíveis a Deus.");
    b->dados[LUCAS].capitulos[18].versos[28] = wxT("Disse-lhe Pedro: Eis que nós deixamos tudo, e te seguimos.");
    b->dados[LUCAS].capitulos[18].versos[29] = wxT("Respondeu-lhes Jesus: Em verdade vos digo que ninguém há que tenha deixado casa, ou mulher, ou irmãos, ou pais, ou filhos, por amor do reino de Deus,");
    b->dados[LUCAS].capitulos[18].versos[30] = wxT("que não haja de receber no presente muito mais, e no mundo vindouro a vida eterna.");
    b->dados[LUCAS].capitulos[18].versos[31] = wxT("Tomando Jesus consigo os doze, disse-lhes: Eis que subimos a Jerusalém e se cumprirá no filho do homem tudo o que pelos profetas foi escrito;");
    b->dados[LUCAS].capitulos[18].versos[32] = wxT("pois será entregue aos gentios, e escarnecido, injuriado e cuspido;");
    b->dados[LUCAS].capitulos[18].versos[33] = wxT("e depois de o açoitarem, o matarão; e ao terceiro dia ressurgirá.");
    b->dados[LUCAS].capitulos[18].versos[34] = wxT("Mas eles não entenderam nada disso; essas palavras lhes eram obscuras, e não percebiam o que lhes dizia.");
    b->dados[LUCAS].capitulos[18].versos[35] = wxT("Ora, quando ele ia chegando a Jericó, estava um cego sentado junto do caminho, mendigando.");
    b->dados[LUCAS].capitulos[18].versos[36] = wxT("Este, pois, ouvindo passar a multidão, perguntou que era aquilo.");
    b->dados[LUCAS].capitulos[18].versos[37] = wxT("Disseram-lhe que Jesus, o nazareno, ia passando.");
    b->dados[LUCAS].capitulos[18].versos[38] = wxT("Então ele se pôs a clamar, dizendo: Jesus, Filho de Davi, tem compaixão de mim!");
    b->dados[LUCAS].capitulos[18].versos[39] = wxT("E os que iam à frente repreendiam-no, para que se calasse; ele, porém, clamava ainda mais: Filho de Davi, tem compaixão de mim!");
    b->dados[LUCAS].capitulos[18].versos[40] = wxT("Parou, pois, Jesus, e mandou que lho trouxessem. Tendo ele chegado, perguntou-lhe:");
    b->dados[LUCAS].capitulos[18].versos[41] = wxT("Que queres que te faça? Respondeu ele: Senhor, que eu veja.");
    b->dados[LUCAS].capitulos[18].versos[42] = wxT("Disse-lhe Jesus: Vê; a tua fé te salvou.");
    b->dados[LUCAS].capitulos[18].versos[43] = wxT("Imediatamente recuperou a vista, e o foi seguindo, gloficando a Deus. E todo o povo, vendo isso, dava louvores a Deus.");

    b->dados[LUCAS].capitulos[19].versos[1] = wxT("Tendo Jesus entrado em Jericó, ia atravessando a cidade.");
    b->dados[LUCAS].capitulos[19].versos[2] = wxT("Havia ali um homem chamado Zaqueu, o qual era chefe de publicanos e era rico.");
    b->dados[LUCAS].capitulos[19].versos[3] = wxT("Este procurava ver quem era Jesus, e não podia, por causa da multidão, porque era de pequena estatura.");
    b->dados[LUCAS].capitulos[19].versos[4] = wxT("E correndo adiante, subiu a um sicômoro a fim de vê-lo, porque havia de passar por ali.");
    b->dados[LUCAS].capitulos[19].versos[5] = wxT("Quando Jesus chegou àquele lugar, olhou para cima e disse-lhe: Zaqueu, desce depressa; porque importa que eu fique hoje em tua casa.");
    b->dados[LUCAS].capitulos[19].versos[6] = wxT("Desceu, pois, a toda a pressa, e o recebeu com alegria.");
    b->dados[LUCAS].capitulos[19].versos[7] = wxT("Ao verem isso, todos murmuravam, dizendo: Entrou para ser hóspede de um homem pecador.");
    b->dados[LUCAS].capitulos[19].versos[8] = wxT("Zaqueu, porém, levantando-se, disse ao Senhor: Eis aqui, Senhor, dou aos pobres metade dos meus bens; e se em alguma coisa tenho defraudado alguém, eu lho restituo quadruplicado.");
    b->dados[LUCAS].capitulos[19].versos[9] = wxT("Disse-lhe Jesus: Hoje veio a salvação a esta casa, porquanto também este é filho de Abraão.");
    b->dados[LUCAS].capitulos[19].versos[10] = wxT("Porque o Filho do homem veio buscar e salvar o que se havia perdido.");
    b->dados[LUCAS].capitulos[19].versos[11] = wxT("Ouvindo eles isso, prosseguiu Jesus, e contou uma parábola, visto estar ele perto de Jerusalém, e pensarem eles que o reino de Deus se havia de manifestar imediatamente.");
    b->dados[LUCAS].capitulos[19].versos[12] = wxT("Disse pois: Certo homem nobre partiu para uma terra longínqua, a fim de tomar posse de um reino e depois voltar.");
    b->dados[LUCAS].capitulos[19].versos[13] = wxT("E chamando dez servos seus, deu-lhes dez minas, e disse-lhes: Negociai até que eu venha.");
    b->dados[LUCAS].capitulos[19].versos[14] = wxT("Mas os seus concidadãos odiavam-no, e enviaram após ele uma embaixada, dizendo: Não queremos que este homem reine sobre nós.");
    b->dados[LUCAS].capitulos[19].versos[15] = wxT("E sucedeu que, ao voltar ele, depois de ter tomado posse do reino, mandou chamar aqueles servos a quem entregara o dinheiro, a fim de saber como cada um havia negociado.");
    b->dados[LUCAS].capitulos[19].versos[16] = wxT("Apresentou-se, pois, o primeiro, e disse: Senhor, a tua mina rendeu dez minas.");
    b->dados[LUCAS].capitulos[19].versos[17] = wxT("Respondeu-lhe o senhor: Bem está, servo bom! porque no mínimo foste fiel, sobre dez cidades terás autoridade.");
    b->dados[LUCAS].capitulos[19].versos[18] = wxT("Veio o segundo, dizendo: Senhor, a tua mina rendeu cinco minas.");
    b->dados[LUCAS].capitulos[19].versos[19] = wxT("A este também respondeu: Sê tu também sobre cinco cidades.");
    b->dados[LUCAS].capitulos[19].versos[20] = wxT("E veio outro, dizendo: Senhor, eis aqui a tua mina, que guardei num lenço;");
    b->dados[LUCAS].capitulos[19].versos[21] = wxT("pois tinha medo de ti, porque és homem severo; tomas o que não puseste, e ceifas o que não semeaste.");
    b->dados[LUCAS].capitulos[19].versos[22] = wxT("Disse-lhe o Senhor: Servo mau! pela tua boca te julgarei; sabias que eu sou homem severo, que tomo o que não pus, e ceifo o que não semeei;");
    b->dados[LUCAS].capitulos[19].versos[23] = wxT("por que, pois, não puseste o meu dinheiro no barco? então vindo eu, o teria retirado com os juros.");
    b->dados[LUCAS].capitulos[19].versos[24] = wxT("E disse aos que estavam ali: Tirai-lhe a mina, e dai-a ao que tem as dez minas.");
    b->dados[LUCAS].capitulos[19].versos[25] = wxT("Responderam-lhe eles: Senhor, ele tem dez minas.");
    b->dados[LUCAS].capitulos[19].versos[26] = wxT("Pois eu vos digo que a todo o que tem, dar-se-lhe-á; mas ao que não tem, até aquilo que tem ser-lhe-á tirado.");
    b->dados[LUCAS].capitulos[19].versos[27] = wxT("Quanto, porém, àqueles meus inimigos que não quiseram que eu reinasse sobre eles, trazei-os aqui, e matai-os diante de mim.");
    b->dados[LUCAS].capitulos[19].versos[28] = wxT("Tendo Jesus assim falado, ia caminhando adiante deles, subindo para Jerusalém.");
    b->dados[LUCAS].capitulos[19].versos[29] = wxT("Ao aproximar-se de Betfagé e de Betânia, junto do monte que se chama das Oliveiras, enviou dois dos discípulos,");
    b->dados[LUCAS].capitulos[19].versos[30] = wxT("dizendo-lhes: Ide à aldeia que está defronte, e aí, ao entrar, achareis preso um jumentinho em que ninguém jamais montou; desprendei-o e trazei-o.");
    b->dados[LUCAS].capitulos[19].versos[31] = wxT("Se alguém vos perguntar: Por que o desprendeis? respondereis assim: O Senhor precisa dele.");
    b->dados[LUCAS].capitulos[19].versos[32] = wxT("Partiram, pois, os que tinham sido enviados, e acharam conforme lhes dissera.");
    b->dados[LUCAS].capitulos[19].versos[33] = wxT("Enquanto desprendiam o jumentinho, os seus donos lhes perguntaram: Por que desprendeis o jumentinho?");
    b->dados[LUCAS].capitulos[19].versos[34] = wxT("Responderam eles: O Senhor precisa dele.");
    b->dados[LUCAS].capitulos[19].versos[35] = wxT("Trouxeram-no, pois, a Jesus e, lançando os seus mantos sobre o jumentinho, fizeram que Jesus montasse.");
    b->dados[LUCAS].capitulos[19].versos[36] = wxT("E, enquanto ele ia passando, outros estendiam no caminho os seus mantos.");
    b->dados[LUCAS].capitulos[19].versos[37] = wxT("Quando já ia chegando à descida do Monte das Oliveiras, toda a multidão dos discípulos, regozijando-se, começou a louvar a Deus em alta voz, por todos os milagres que tinha visto,");
    b->dados[LUCAS].capitulos[19].versos[38] = wxT("dizendo: Bendito o Rei que vem em nome do Senhor; paz no céu, e glória nas alturas.");
    b->dados[LUCAS].capitulos[19].versos[39] = wxT("Nisso, disseram-lhe alguns dos fariseus dentre a multidão: Mestre, repreende os teus discípulos.");
    b->dados[LUCAS].capitulos[19].versos[40] = wxT("Ao que ele respondeu: Digo-vos que, se estes se calarem, as pedras clamarão.");
    b->dados[LUCAS].capitulos[19].versos[41] = wxT("E quando chegou perto e viu a cidade, chorou sobre ela,");
    b->dados[LUCAS].capitulos[19].versos[42] = wxT("dizendo: Ah! se tu conhecesses, ao menos neste dia, o que te poderia trazer a paz! mas agora isso está encoberto aos teus olhos.");
    b->dados[LUCAS].capitulos[19].versos[43] = wxT("Porque dias virão sobre ti em que os teus inimigos te cercarão de trincheiras, e te sitiarão, e te apertarão de todos os lados,");
    b->dados[LUCAS].capitulos[19].versos[44] = wxT("e te derribarão, a ti e aos teus filhos que dentro de ti estiverem; e não deixarão em ti pedra sobre pedra, porque não conheceste o tempo da tua visitação.");
    b->dados[LUCAS].capitulos[19].versos[45] = wxT("Então, entrando ele no templo, começou a expulsar os que ali vendiam,");
    b->dados[LUCAS].capitulos[19].versos[46] = wxT("dizendo-lhes: Está escrito: A minha casa será casa de oração; vós, porém, a fizestes covil de salteadores.");
    b->dados[LUCAS].capitulos[19].versos[47] = wxT("E todos os dias ensinava no templo; mas os principais sacerdotes, os escribas, e os principais do povo procuravam matá-lo;");
    b->dados[LUCAS].capitulos[19].versos[48] = wxT("mas não achavam meio de o fazer; porque todo o povo ficava enlevado ao ouvi-lo.");

    b->dados[LUCAS].capitulos[20].versos[1] = wxT("Num desses dias, quando Jesus ensinava o povo no templo, e anunciava o evangelho, sobrevieram os principais sacerdotes e os escribas, com os anciãos.");
    b->dados[LUCAS].capitulos[20].versos[2] = wxT("e falaram-lhe deste modo: Dize-nos, com que autoridade fazes tu estas coisas? Ou, quem é o que te deu esta autoridade?");
    b->dados[LUCAS].capitulos[20].versos[3] = wxT("Respondeu-lhes ele: Eu também vos farei uma pergunta; dizei-me, pois:");
    b->dados[LUCAS].capitulos[20].versos[4] = wxT("O batismo de João era do céu ou dos homens?");
    b->dados[LUCAS].capitulos[20].versos[5] = wxT("Ao que eles arrazoavam entre si: Se dissermos: do céu, ele dirá: Por que não crestes?");
    b->dados[LUCAS].capitulos[20].versos[6] = wxT("Mas, se dissermos: Dos homens, todo o povo nos apedrejará; pois está convencido de que João era profeta.");
    b->dados[LUCAS].capitulos[20].versos[7] = wxT("Responderam, pois, que não sabiam donde era.");
    b->dados[LUCAS].capitulos[20].versos[8] = wxT("Replicou-lhes Jesus: Nem eu vos digo com que autoridade faço estas coisas.");
    b->dados[LUCAS].capitulos[20].versos[9] = wxT("Começou então a dizer ao povo esta parábola: Um homem plantou uma vinha, arrendou-a a uns lavradores, e ausentou-se do país por muito tempo.");
    b->dados[LUCAS].capitulos[20].versos[10] = wxT("No tempo próprio mandou um servo aos lavradores, para que lhe dessem dos frutos da vinha; mas os lavradores, espancando-o, mandaram-no embora de mãos vazias.");
    b->dados[LUCAS].capitulos[20].versos[11] = wxT("Tornou a mandar outro servo; mas eles espancaram também a este e, afrontando-o, mandaram-no embora de mãos vazias.");
    b->dados[LUCAS].capitulos[20].versos[12] = wxT("E mandou ainda um terceiro; mas feriram também a este e lançaram-no fora.");
    b->dados[LUCAS].capitulos[20].versos[13] = wxT("Disse então o senhor da vinha: Que farei? Mandarei o meu filho amado; a ele talvez respeitarão.");
    b->dados[LUCAS].capitulos[20].versos[14] = wxT("Mas quando os lavradores o viram, arrazoaram entre si, dizendo: Este é o herdeiro; matemo-lo, para que a herança seja nossa.");
    b->dados[LUCAS].capitulos[20].versos[15] = wxT("E lançando-o fora da vinha, o mataram. Que lhes fará, pois, o senhor da vinha?");
    b->dados[LUCAS].capitulos[20].versos[16] = wxT("Virá e destruirá esses lavradores, e dará a vinha a outros. Ouvindo eles isso, disseram: Tal não aconteça!");
    b->dados[LUCAS].capitulos[20].versos[17] = wxT("Mas Jesus, olhando para eles, disse: Pois, que quer dizer isto que está escrito: A pedra que os edificadores rejeitaram, essa foi posta como pedra angular?");
    b->dados[LUCAS].capitulos[20].versos[18] = wxT("Todo o que cair sobre esta pedra será despedaçado; mas aquele sobre quem ela cair será reduzido a pó.");
    b->dados[LUCAS].capitulos[20].versos[19] = wxT("Ainda na mesma hora os escribas e os principais sacerdotes, percebendo que contra eles proferira essa parábola, procuraram deitar-lhe as mãos, mas temeram o povo.");
    b->dados[LUCAS].capitulos[20].versos[20] = wxT("E, aguardando oportunidade, mandaram espias, os quais se fingiam justos, para o apanharem em alguma palavra, e o entregarem à jurisdição e à autoridade do governador.");
    b->dados[LUCAS].capitulos[20].versos[21] = wxT("Estes, pois, o interrogaram, dizendo: Mestre, sabemos que falas e ensinas retamente, e que não consideras a aparência da pessoa, mas ensinas segundo a verdade o caminho de Deus;");
    b->dados[LUCAS].capitulos[20].versos[22] = wxT("é-nos lícito dar tributo a César, ou não?");
    b->dados[LUCAS].capitulos[20].versos[23] = wxT("Mas Jesus, percebendo a astúcia deles, disse-lhes:");
    b->dados[LUCAS].capitulos[20].versos[24] = wxT("Mostrai-me um denário. De quem é a imagem e a inscrição que ele tem? Responderam: De César.");
    b->dados[LUCAS].capitulos[20].versos[25] = wxT("Disse-lhes então: Dai, pois, a César o que é de César, e a Deus o que é de Deus.");
    b->dados[LUCAS].capitulos[20].versos[26] = wxT("E não puderam apanhá-lo em palavra alguma diante do povo; e admirados da sua resposta, calaram-se.");
    b->dados[LUCAS].capitulos[20].versos[27] = wxT("Chegaram então alguns dos saduceus, que dizem não haver ressurreição, e perguntaram-lhe:");
    b->dados[LUCAS].capitulos[20].versos[28] = wxT("Mestre, Moisés nos deixou escrito que se morrer alguém, tendo mulher mas não tendo filhos, o irmão dele case com a viúva, e suscite descendência ao irmão.");
    b->dados[LUCAS].capitulos[20].versos[29] = wxT("Havia, pois, sete irmãos. O primeiro casou-se e morreu sem filhos;");
    b->dados[LUCAS].capitulos[20].versos[30] = wxT("então o segundo, e depois o terceiro, casaram com a viúva;");
    b->dados[LUCAS].capitulos[20].versos[31] = wxT("e assim todos os sete, e morreram, sem deixar filhos.");
    b->dados[LUCAS].capitulos[20].versos[32] = wxT("Depois morreu também a mulher.");
    b->dados[LUCAS].capitulos[20].versos[33] = wxT("Portanto, na ressurreição, de qual deles será ela esposa, pois os sete por esposa a tiveram?");
    b->dados[LUCAS].capitulos[20].versos[34] = wxT("Respondeu-lhes Jesus: Os filhos deste mundo casaram-se e dão-se em casamento;");
    b->dados[LUCAS].capitulos[20].versos[35] = wxT("mas os que são julgados dignos de alcançar o mundo vindouro, e a ressurreição dentre os mortos, nem se casam nem se dão em casamento;");
    b->dados[LUCAS].capitulos[20].versos[36] = wxT("porque já não podem mais morrer; pois são iguais aos anjos, e são filhos de Deus, sendo filhos da ressurreição.");
    b->dados[LUCAS].capitulos[20].versos[37] = wxT("Mas que os mortos hão de ressurgir, o próprio Moisés o mostrou, na passagem a respeito da sarça, quando chama ao Senhor; Deus de Abraão, e Deus de Isaque, e Deus de Jacó.");
    b->dados[LUCAS].capitulos[20].versos[38] = wxT("Ora, ele não é Deus de mortos, mas de vivos; porque para ele todos vivem.");
    b->dados[LUCAS].capitulos[20].versos[39] = wxT("Responderam alguns dos escribas: Mestre, disseste bem.");
    b->dados[LUCAS].capitulos[20].versos[40] = wxT("Não ousavam, pois, perguntar-lhe mais coisa alguma.");
    b->dados[LUCAS].capitulos[20].versos[41] = wxT("Jesus, porém, lhes perguntou: Como dizem que o Cristo é filho de Davi?");
    b->dados[LUCAS].capitulos[20].versos[42] = wxT("Pois o próprio Davi diz no livro dos Salmos: Disse o Senhor ao meu Senhor: Assenta-te à minha direita,");
    b->dados[LUCAS].capitulos[20].versos[43] = wxT("até que eu ponha os teus inimigos por escabelo dos teus pés.");
    b->dados[LUCAS].capitulos[20].versos[44] = wxT("Logo Davi lhe chama Senhor como, pois, é ele seu filho?");
    b->dados[LUCAS].capitulos[20].versos[45] = wxT("Enquanto todo o povo o ouvia, disse Jesus aos seus discípulos:");
    b->dados[LUCAS].capitulos[20].versos[46] = wxT("Guardai-vos dos escribas, que querem andar com vestes compridas, e gostam das saudações nas praças, dos primeiros assentos nas sinagogas, e dos primeiros lugares nos banquetes;");
    b->dados[LUCAS].capitulos[20].versos[47] = wxT("que devoram as casas das viúvas, fazendo, por pretexto, longas orações; estes hão de receber maior condenação.");

    b->dados[LUCAS].capitulos[21].versos[1] = wxT("Jesus, levantando os olhos, viu os ricos deitarem as suas ofertas no cofre;");
    b->dados[LUCAS].capitulos[21].versos[2] = wxT("viu também uma pobre viúva lançar ali dois leptos;");
    b->dados[LUCAS].capitulos[21].versos[3] = wxT("e disse: Em verdade vos digo que esta pobre viúva deu mais do que todos;");
    b->dados[LUCAS].capitulos[21].versos[4] = wxT("porque todos aqueles deram daquilo que lhes sobrava; mas esta, da sua pobreza, deu tudo o que tinha para o seu sustento.");
    b->dados[LUCAS].capitulos[21].versos[5] = wxT("E falando-lhe alguns a respeito do templo, como estava ornado de formosas pedras e dádivas, disse ele:");
    b->dados[LUCAS].capitulos[21].versos[6] = wxT("Quanto a isto que vedes, dias virão em que não se deixará aqui pedra sobre pedra, que não seja derribada.");
    b->dados[LUCAS].capitulos[21].versos[7] = wxT("Perguntaram-lhe então: Mestre, quando, pois, sucederão estas coisas? E que sinal haverá, quando elas estiverem para se cumprir?");
    b->dados[LUCAS].capitulos[21].versos[8] = wxT("Respondeu então ele: Acautelai-vos; não sejais enganados; porque virão muitos em meu nome, dizendo: Sou eu; e: O tempo é chegado; não vades após eles.");
    b->dados[LUCAS].capitulos[21].versos[9] = wxT("Quando ouvirdes de guerras e tumultos, não vos assusteis; pois é necessário que primeiro aconteçam essas coisas; mas o fim não será logo.");
    b->dados[LUCAS].capitulos[21].versos[10] = wxT("Então lhes disse: Levantar-se-á nação contra nação, e reino contra reino;");
    b->dados[LUCAS].capitulos[21].versos[11] = wxT("e haverá em vários lugares grandes terremotos, e pestes e fomes; haverá também coisas espantosas, e grandes sinais do céu.");
    b->dados[LUCAS].capitulos[21].versos[12] = wxT("Mas antes de todas essas coisas vos hão de prender e perseguir, entregando-vos às sinagogas e aos cárceres, e conduzindo-vos à presença de reis e governadores, por causa do meu nome.");
    b->dados[LUCAS].capitulos[21].versos[13] = wxT("Isso vos acontecerá para que deis testemunho.");
    b->dados[LUCAS].capitulos[21].versos[14] = wxT("Proponde, pois, em vossos corações não premeditar como haveis de fazer a vossa defesa;");
    b->dados[LUCAS].capitulos[21].versos[15] = wxT("porque eu vos darei boca e sabedoria, a que nenhum dos vossos adversário poderá resistir nem contradizer.");
    b->dados[LUCAS].capitulos[21].versos[16] = wxT("E até pelos pais, e irmãos, e parentes, e amigos sereis entregues; e matarão alguns de vós;");
    b->dados[LUCAS].capitulos[21].versos[17] = wxT("e sereis odiados de todos por causa do meu nome.");
    b->dados[LUCAS].capitulos[21].versos[18] = wxT("Mas não se perderá um único cabelo da vossa cabeça.");
    b->dados[LUCAS].capitulos[21].versos[19] = wxT("Pela vossa perseverança ganhareis as vossas almas.");
    b->dados[LUCAS].capitulos[21].versos[20] = wxT("Mas, quando virdes Jerusalém cercada de exércitos, sabei então que é chegada a sua desolação.");
    b->dados[LUCAS].capitulos[21].versos[21] = wxT("Então, os que estiverem na Judéia fujam para os montes; os que estiverem dentro da cidade, saiam; e os que estiverem nos campos não entrem nela.");
    b->dados[LUCAS].capitulos[21].versos[22] = wxT("Porque dias de vingança são estes, para que se cumpram todas as coisas que estão escritas.");
    b->dados[LUCAS].capitulos[21].versos[23] = wxT("Ai das que estiverem grávidas, e das que amamentarem naqueles dias! porque haverá grande angústia sobre a terra, e ira contra este povo.");
    b->dados[LUCAS].capitulos[21].versos[24] = wxT("E cairão ao fio da espada, e para todas as nações serão levados cativos; e Jerusalém será pisada pelos gentios, até que os tempos destes se completem.");
    b->dados[LUCAS].capitulos[21].versos[25] = wxT("E haverá sinais no sol, na lua e nas estrelas; e sobre a terra haverá angústia das nações em perplexidade pelo bramido do mar e das ondas.");
    b->dados[LUCAS].capitulos[21].versos[26] = wxT("os homens desfalecerão de terror, e pela expectação das coisas que sobrevirão ao mundo; porquanto os poderes do céu serão abalados.");
    b->dados[LUCAS].capitulos[21].versos[27] = wxT("Então verão vir o Filho do homem em uma nuvem, com poder e grande glória.");
    b->dados[LUCAS].capitulos[21].versos[28] = wxT("Ora, quando essas coisas começarem a acontecer, exultai e levantai as vossas cabeças, porque a vossa redenção se aproxima.");
    b->dados[LUCAS].capitulos[21].versos[29] = wxT("Propôs-lhes então uma parábola: Olhai para a figueira, e para todas as árvores;");
    b->dados[LUCAS].capitulos[21].versos[30] = wxT("quando começam a brotar, sabeis por vós mesmos, ao vê-las, que já está próximo o verão.");
    b->dados[LUCAS].capitulos[21].versos[31] = wxT("Assim também vós, quando virdes acontecerem estas coisas, sabei que o reino de Deus está próximo.");
    b->dados[LUCAS].capitulos[21].versos[32] = wxT("Em verdade vos digo que não passará esta geração até que tudo isso se cumpra.");
    b->dados[LUCAS].capitulos[21].versos[33] = wxT("Passará o céu e a terra, mas as minhas palavras jamais passarão.");
    b->dados[LUCAS].capitulos[21].versos[34] = wxT("Olhai por vós mesmos; não aconteça que os vossos corações se carreguem de glutonaria, de embriaguez, e dos cuidados da vida, e aquele dia vos sobrevenha de improviso como um laço.");
    b->dados[LUCAS].capitulos[21].versos[35] = wxT("Porque há de vir sobre todos os que habitam na face da terra.");
    b->dados[LUCAS].capitulos[21].versos[36] = wxT("Vigiai, pois, em todo o tempo, orando, para que possais escapar de todas estas coisas que hão de acontecer, e estar em pé na presença do Filho do homem.");
    b->dados[LUCAS].capitulos[21].versos[37] = wxT("Ora, de dia ensinava no templo, e à noite, saindo, pousava no monte chamado das Oliveiras.");
    b->dados[LUCAS].capitulos[21].versos[38] = wxT("E todo o povo ia ter com ele no templo, de manhã cedo, para o ouvir.");

    b->dados[LUCAS].capitulos[22].versos[1] = wxT("Aproximava-se a festa dos pães ázimos, que se chama a páscoa.");
    b->dados[LUCAS].capitulos[22].versos[2] = wxT("E os principais sacerdotes e os escribas andavam procurando um modo de o matar; pois temiam o povo.");
    b->dados[LUCAS].capitulos[22].versos[3] = wxT("Entrou então Satanás em Judas, que tinha por sobrenome Iscariotes, que era um dos doze;");
    b->dados[LUCAS].capitulos[22].versos[4] = wxT("e foi ele tratar com os principais sacerdotes e com os capitães de como lho entregaria.");
    b->dados[LUCAS].capitulos[22].versos[5] = wxT("Eles se alegraram com isso, e convieram em lhe dar dinheiro.");
    b->dados[LUCAS].capitulos[22].versos[6] = wxT("E ele concordou, e buscava ocasião para lho entregar sem alvoroço.");
    b->dados[LUCAS].capitulos[22].versos[7] = wxT("Ora, chegou o dia dos pães ázimos, em que se devia imolar a páscoa;");
    b->dados[LUCAS].capitulos[22].versos[8] = wxT("e Jesus enviou a Pedro e a João, dizendo: Ide, preparai-nos a páscoa, para que a comamos.");
    b->dados[LUCAS].capitulos[22].versos[9] = wxT("Perguntaram-lhe eles: Onde queres que a preparemos?");
    b->dados[LUCAS].capitulos[22].versos[10] = wxT("Respondeu-lhes: Quando entrardes na cidade, sair-vos-á ao encontro um homem, levando um cântaro de água; segui-o até a casa em que ele entrar.");
    b->dados[LUCAS].capitulos[22].versos[11] = wxT("E direis ao dono da casa: O Mestre manda perguntar-te: Onde está o aposento em que hei de comer a páscoa com os meus discípulos?");
    b->dados[LUCAS].capitulos[22].versos[12] = wxT("Então ele vos mostrará um grande cenáculo mobiliado; aí fazei os preparativos.");
    b->dados[LUCAS].capitulos[22].versos[13] = wxT("Foram, pois, e acharam tudo como lhes dissera e prepararam a páscoa.");
    b->dados[LUCAS].capitulos[22].versos[14] = wxT("E, chegada a hora, pôs-se Jesus à mesa, e com ele os apóstolos.");
    b->dados[LUCAS].capitulos[22].versos[15] = wxT("E disse-lhes: Tenho desejado ardentemente comer convosco esta páscoa, antes da minha paixão;");
    b->dados[LUCAS].capitulos[22].versos[16] = wxT("pois vos digo que não a comerei mais até que ela se cumpra no reino de Deus.");
    b->dados[LUCAS].capitulos[22].versos[17] = wxT("Então havendo recebido um cálice, e tendo dado graças, disse: Tomai-o, e reparti-o entre vós;");
    b->dados[LUCAS].capitulos[22].versos[18] = wxT("porque vos digo que desde agora não mais beberei do fruto da videira, até que venha o reino de Deus.");
    b->dados[LUCAS].capitulos[22].versos[19] = wxT("E tomando pão, e havendo dado graças, partiu-o e deu-lho, dizendo: Isto é o meu corpo, que é dado por vós; fazei isto em memória de mim.");
    b->dados[LUCAS].capitulos[22].versos[20] = wxT("Semelhantemente, depois da ceia, tomou o cálice, dizendo: Este cálice é o novo pacto em meu sangue, que é derramado por vós.");
    b->dados[LUCAS].capitulos[22].versos[21] = wxT("Mas eis que a mão do que me trai está comigo à mesa.");
    b->dados[LUCAS].capitulos[22].versos[22] = wxT("Porque, na verdade, o Filho do homem vai segundo o que está determinado; mas ai daquele homem por quem é traído!");
    b->dados[LUCAS].capitulos[22].versos[23] = wxT("Então eles começaram a perguntar entre si qual deles o que ia fazer isso.");
    b->dados[LUCAS].capitulos[22].versos[24] = wxT("Levantou-se também entre eles contenda, sobre qual deles parecia ser o maior.");
    b->dados[LUCAS].capitulos[22].versos[25] = wxT("Ao que Jesus lhes disse: Os reis dos gentios dominam sobre eles, e os que sobre eles exercem autoridade são chamados benfeitores.");
    b->dados[LUCAS].capitulos[22].versos[26] = wxT("Mas vós não sereis assim; antes o maior entre vós seja como o mais novo; e quem governa como quem serve.");
    b->dados[LUCAS].capitulos[22].versos[27] = wxT("Pois qual é maior, quem está à mesa, ou quem serve? porventura não é quem está à mesa? Eu, porém, estou entre vós como quem serve.");
    b->dados[LUCAS].capitulos[22].versos[28] = wxT("Mas vós sois os que tendes permanecido comigo nas minhas provações;");
    b->dados[LUCAS].capitulos[22].versos[29] = wxT("e assim como meu Pai me conferiu domínio, eu vo-lo confiro a vós;");
    b->dados[LUCAS].capitulos[22].versos[30] = wxT("para que comais e bebais à minha mesa no meu reino, e vos senteis sobre tronos, julgando as doze tribos de Israel.");
    b->dados[LUCAS].capitulos[22].versos[31] = wxT("Simão, Simão, eis que Satanás vos pediu para vos cirandar como trigo;");
    b->dados[LUCAS].capitulos[22].versos[32] = wxT("mas eu roguei por ti, para que a tua fé não desfaleça; e tu, quando te converteres, fortalece teus irmãos.");
    b->dados[LUCAS].capitulos[22].versos[33] = wxT("Respondeu-lhe Pedro: Senhor, estou pronto a ir contigo tanto para a prisão como para a morte.");
    b->dados[LUCAS].capitulos[22].versos[34] = wxT("Tornou-lhe Jesus: Digo-te, Pedro, que não cantará hoje o galo antes que três vezes tenhas negado que me conheces.");
    b->dados[LUCAS].capitulos[22].versos[35] = wxT("E perguntou-lhes: Quando vos mandei sem bolsa, alforje, ou alparcas, faltou-vos porventura alguma coisa? Eles responderam: Nada.");
    b->dados[LUCAS].capitulos[22].versos[36] = wxT("Disse-lhes pois: Mas agora, quem tiver bolsa, tome-a, como também o alforje; e quem não tiver espada, venda o seu manto e compre-a.");
    b->dados[LUCAS].capitulos[22].versos[37] = wxT("Porquanto vos digo que importa que se cumpra em mim isto que está escrito: E com os malfeitores foi contado. Pois o que me diz respeito tem seu cumprimento.");
    b->dados[LUCAS].capitulos[22].versos[38] = wxT("Disseram eles: Senhor, eis aqui duas espadas. Respondeu-lhes: Basta.");
    b->dados[LUCAS].capitulos[22].versos[39] = wxT("Então saiu e, segundo o seu costume, foi para o Monte das Oliveiras; e os discípulos o seguiam.");
    b->dados[LUCAS].capitulos[22].versos[40] = wxT("Quando chegou àquele lugar, disse-lhes: Orai, para que não entreis em tentação.");
    b->dados[LUCAS].capitulos[22].versos[41] = wxT("E apartou-se deles cerca de um tiro de pedra; e pondo-se de joelhos, orava,");
    b->dados[LUCAS].capitulos[22].versos[42] = wxT("dizendo: Pai, se queres afasta de mim este cálice; todavia não se faça a minha vontade, mas a tua.");
    b->dados[LUCAS].capitulos[22].versos[43] = wxT("Então lhe apareceu um anjo do céu, que o confortava.");
    b->dados[LUCAS].capitulos[22].versos[44] = wxT("E, posto em agonia, orava mais intensamente; e o seu suor tornou-se como grandes gotas de sangue, que caíam sobre o chão.");
    b->dados[LUCAS].capitulos[22].versos[45] = wxT("Depois, levantando-se da oração, veio para os seus discípulos, e achou-os dormindo de tristeza;");
    b->dados[LUCAS].capitulos[22].versos[46] = wxT("e disse-lhes: Por que estais dormindo? Lenvantai-vos, e orai, para que não entreis em tentação.");
    b->dados[LUCAS].capitulos[22].versos[47] = wxT("E estando ele ainda a falar, eis que surgiu uma multidão; e aquele que se chamava Judas, um dos doze, ia adiante dela, e chegou-se a Jesus para o beijar.");
    b->dados[LUCAS].capitulos[22].versos[48] = wxT("Jesus, porém, lhe disse: Judas, com um beijo trais o Filho do homem?");
    b->dados[LUCAS].capitulos[22].versos[49] = wxT("Quando os que estavam com ele viram o que ia suceder, disseram: Senhor, feri-los-emos a espada?");
    b->dados[LUCAS].capitulos[22].versos[50] = wxT("Então um deles feriu o servo do sumo sacerdote, e cortou-lhe a orelha direita.");
    b->dados[LUCAS].capitulos[22].versos[51] = wxT("Mas Jesus disse: Deixei-os; basta. E tocando-lhe a orelha, o curou.");
    b->dados[LUCAS].capitulos[22].versos[52] = wxT("Então disse Jesus aos principais sacerdotes, oficiais do templo e anciãos, que tinham ido contra ele: Saístes, como a um salteador, com espadas e varapaus?");
    b->dados[LUCAS].capitulos[22].versos[53] = wxT("Todos os dias estava eu convosco no templo, e não estendestes as mãos contra mim; mas esta é a vossa hora e o poder das trevas.");
    b->dados[LUCAS].capitulos[22].versos[54] = wxT("Então, prendendo-o, o levaram e o introduziram na casa do sumo sacerdote; e Pedro seguia-o de longe.");
    b->dados[LUCAS].capitulos[22].versos[55] = wxT("E tendo eles acendido fogo no meio do pátio e havendo-se sentado à roda, sentou-se Pedro entre eles.");
    b->dados[LUCAS].capitulos[22].versos[56] = wxT("Mas Pedro o negou, dizendo: Mulher, não o conheço.");
    b->dados[LUCAS].capitulos[22].versos[57] = wxT("Daí a pouco, outro o viu, e disse: Tu também és um deles. Mas Pedro disse: Homem, não sou.");
    b->dados[LUCAS].capitulos[22].versos[58] = wxT("E, tendo passado quase uma hora, outro afirmava, dizendo: Certamente este também estava com ele, pois é galileu.");
    b->dados[LUCAS].capitulos[22].versos[59] = wxT("Mas Pedro respondeu: Homem, não sei o que dizes. E imediatamente estando ele ainda a falar, cantou o galo.");
    b->dados[LUCAS].capitulos[22].versos[60] = wxT("Virando-se o Senhor, olhou para Pedro; e Pedro lembrou-se da palavra do Senhor, como lhe havia dito: Hoje, antes que o galo cante, três vezes me negarás.");
    b->dados[LUCAS].capitulos[22].versos[61] = wxT("E, havendo saído, chorou amargamente.");
    b->dados[LUCAS].capitulos[22].versos[62] = wxT("Os homens que detinham Jesus zombavam dele, e feriam-no;");
    b->dados[LUCAS].capitulos[22].versos[63] = wxT("e, vendando-lhe os olhos, perguntavam, dizendo: Profetiza, quem foi que te bateu?");
    b->dados[LUCAS].capitulos[22].versos[64] = wxT("E, blasfemando, diziam muitas outras coisas contra ele.");
    b->dados[LUCAS].capitulos[22].versos[65] = wxT("Logo que amanheceu reuniu-se a assembléia dos anciãos do povo, tanto os principais sacerdotes como os escribas, e o conduziam ao sinédrio deles, onde lhe disseram:");
    b->dados[LUCAS].capitulos[22].versos[66] = wxT("Se tu és o Cristo, dize-no-lo. Replicou-lhes ele: Se eu vo-lo disser, não o crereis;");
    b->dados[LUCAS].capitulos[22].versos[67] = wxT("e se eu vos interrogar, de modo algum me respondereis.");
    b->dados[LUCAS].capitulos[22].versos[68] = wxT("Mas desde agora estará assentado o Filho do homem à mão direita do poder de Deus.");
    b->dados[LUCAS].capitulos[22].versos[69] = wxT("Ao que perguntaram todos: Logo, tu és o Filho de Deus? Respondeu-lhes: Vós dizeis que eu sou.");
    b->dados[LUCAS].capitulos[22].versos[70] = wxT("Então disseram: Por que ainda temos necessidade de testemunho? pois nós mesmos o ouvimos da sua própria boca.");

    b->dados[LUCAS].capitulos[23].versos[1] = wxT("E levantando-se toda a multidão deles, conduziram Jesus a Pilatos.");
    b->dados[LUCAS].capitulos[23].versos[2] = wxT("E começaram a acusá-lo, dizendo: Achamos este homem pervertendo a nossa nação, proibindo dar o tributo a César, e dizendo ser ele mesmo Cristo, rei.");
    b->dados[LUCAS].capitulos[23].versos[3] = wxT("Pilatos, pois, perguntou-lhe: És tu o rei dos judeus? Respondeu-lhe Jesus: É como dizes.");
    b->dados[LUCAS].capitulos[23].versos[4] = wxT("Então disse Pilatos aos principais sacerdotes, e às multidões: Não acho culpa alguma neste homem.");
    b->dados[LUCAS].capitulos[23].versos[5] = wxT("Eles, porém, insistiam ainda mais, dizendo: Alvoroça o povo ensinando por toda a Judéia, começando desde a Galiléia até aqui.");
    b->dados[LUCAS].capitulos[23].versos[6] = wxT("Então Pilatos, ouvindo isso, perguntou se o homem era galileu;");
    b->dados[LUCAS].capitulos[23].versos[7] = wxT("e, quando soube que era da jurisdição de Herodes, remeteu-o a Herodes, que também naqueles dias estava em Jerusalém.");
    b->dados[LUCAS].capitulos[23].versos[8] = wxT("Ora, quando Herodes viu a Jesus, alegrou-se muito; pois de longo tempo desejava vê-lo, por ter ouvido falar a seu respeito; e esperava ver algum sinal feito por ele;");
    b->dados[LUCAS].capitulos[23].versos[9] = wxT("e fazia-lhe muitas perguntas; mas ele nada lhe respondeu.");
    b->dados[LUCAS].capitulos[23].versos[10] = wxT("Estavam ali os principais sacerdotes, e os escribas, acusando-o com grande veemência.");
    b->dados[LUCAS].capitulos[23].versos[11] = wxT("Herodes, porém, com os seus soldados, desprezou-o e, escarnecendo dele, vestiu-o com uma roupa resplandecente e tornou a enviá-lo a Pilatos.");
    b->dados[LUCAS].capitulos[23].versos[12] = wxT("Nesse mesmo dia Pilatos e Herodes tornaram-se amigos; pois antes andavam em inimizade um com o outro.");
    b->dados[LUCAS].capitulos[23].versos[13] = wxT("Então Pilatos convocou os principais sacerdotes, as autoridades e o povo,");
    b->dados[LUCAS].capitulos[23].versos[14] = wxT("e disse-lhes: Apresentastes-me este homem como pervertedor do povo; e eis que, interrogando-o diante de vós, não achei nele nenhuma culpa, das de que o acusais;");
    b->dados[LUCAS].capitulos[23].versos[15] = wxT("nem tampouco Herodes, pois no-lo tornou a enviar; e eis que não tem feito ele coisa alguma digna de morte.");
    b->dados[LUCAS].capitulos[23].versos[16] = wxT("Castigá-lo-ei, pois, e o soltarei.");
    b->dados[LUCAS].capitulos[23].versos[17] = wxT("{E era-lhe necessário soltar-lhes um pela festa.}");
    b->dados[LUCAS].capitulos[23].versos[18] = wxT("Mas todos clamaram à uma, dizendo: Fora com este, e solta-nos Barrabás!");
    b->dados[LUCAS].capitulos[23].versos[19] = wxT("Ora, Barrabás fora lançado na prisão por causa de uma sedição feita na cidade, e de um homicídio.");
    b->dados[LUCAS].capitulos[23].versos[20] = wxT("Mais uma vez, pois, falou-lhes Pilatos, querendo soltar a Jesus.");
    b->dados[LUCAS].capitulos[23].versos[21] = wxT("Eles, porém, bradavam, dizendo: Crucifica-o! crucifica-o!");
    b->dados[LUCAS].capitulos[23].versos[22] = wxT("Falou-lhes, então, pela terceira vez: Pois, que mal fez ele? Não achei nele nenhuma culpa digna de morte. Castigá-lo-ei, pois, e o soltarei.");
    b->dados[LUCAS].capitulos[23].versos[23] = wxT("Mas eles instavam com grandes brados, pedindo que fosse crucificado. E prevaleceram os seus clamores.");
    b->dados[LUCAS].capitulos[23].versos[24] = wxT("Então Pilatos resolveu atender-lhes o pedido;");
    b->dados[LUCAS].capitulos[23].versos[25] = wxT("e soltou-lhes o que fora lançado na prisão por causa de sedição e de homicídio, que era o que eles pediam; mas entregou Jesus à vontade deles.");
    b->dados[LUCAS].capitulos[23].versos[26] = wxT("Quando o levaram dali tomaram um certo Simão, cireneu, que vinha do campo, e puseram-lhe a cruz às costas, para que a levasse após Jesus.");
    b->dados[LUCAS].capitulos[23].versos[27] = wxT("Seguia-o grande multidão de povo e de mulheres, as quais o pranteavam e lamentavam.");
    b->dados[LUCAS].capitulos[23].versos[28] = wxT("Jesus, porém, voltando-se para elas, disse: Filhas de Jerusalém, não choreis por mim; chorai antes por vós mesmas, e por vossos filhos.");
    b->dados[LUCAS].capitulos[23].versos[29] = wxT("Porque dias hão de vir em que se dirá: Bem-aventuradas as estéreis, e os ventres que não geraram, e os peitos que não amamentaram!");
    b->dados[LUCAS].capitulos[23].versos[30] = wxT("Então começarão a dizer aos montes: Caí sobre nós; e aos outeiros: Cobri-nos.");
    b->dados[LUCAS].capitulos[23].versos[31] = wxT("Porque, se isto se faz no lenho verde, que se fará no seco?");
    b->dados[LUCAS].capitulos[23].versos[32] = wxT("E levavam também com ele outros dois, que eram malfeitores, para serem mortos.");
    b->dados[LUCAS].capitulos[23].versos[33] = wxT("Quando chegaram ao lugar chamado Caveira, ali o crucificaram, a ele e também aos malfeitores, um à direita e outro à esquerda.");
    b->dados[LUCAS].capitulos[23].versos[34] = wxT("Jesus, porém, dizia: Pai, perdoa-lhes; porque não sabem o que fazem. Então repartiram as vestes dele, deitando sortes sobre elas.");
    b->dados[LUCAS].capitulos[23].versos[35] = wxT("E o povo estava ali a olhar. E as próprias autoridades zombavam dele, dizendo: Aos outros salvou; salve-se a si mesmo, se é o Cristo, o escolhido de Deus.");
    b->dados[LUCAS].capitulos[23].versos[36] = wxT("Os soldados também o escarneciam, chegando-se a ele, oferecendo-lhe vinagre,");
    b->dados[LUCAS].capitulos[23].versos[37] = wxT("e dizendo: Se tu és o rei dos judeus, salva-te a ti mesmo.");
    b->dados[LUCAS].capitulos[23].versos[38] = wxT("Por cima dele estava esta inscrição {em letras gregas, romanas e hebraicas:} ESTE É O REI DOS JUDEUS.");
    b->dados[LUCAS].capitulos[23].versos[39] = wxT("Então um dos malfeitores que estavam pendurados, blasfemava dele, dizendo: Não és tu o Cristo? salva-te a ti mesmo e a nós.");
    b->dados[LUCAS].capitulos[23].versos[40] = wxT("Respondendo, porém, o outro, repreendia-o, dizendo: Nem ao menos temes a Deus, estando na mesma condenação?");
    b->dados[LUCAS].capitulos[23].versos[41] = wxT("E nós, na verdade, com justiça; porque recebemos o que os nossos feitos merecem; mas este nenhum mal fez.");
    b->dados[LUCAS].capitulos[23].versos[42] = wxT("Então disse: Jesus, lembra-te de mim, quando entrares no teu reino.");
    b->dados[LUCAS].capitulos[23].versos[43] = wxT("Respondeu-lhe Jesus: Em verdade te digo que hoje estarás comigo no paraíso.");
    b->dados[LUCAS].capitulos[23].versos[44] = wxT("Era já quase a hora sexta, e houve trevas em toda a terra até a hora nona, pois o sol se escurecera;");
    b->dados[LUCAS].capitulos[23].versos[45] = wxT("e rasgou-se ao meio o véu do santuário.");
    b->dados[LUCAS].capitulos[23].versos[46] = wxT("Jesus, clamando com grande voz, disse: Pai, nas tuas mãos entrego o meu espírito. E, havendo dito isso, expirou.");
    b->dados[LUCAS].capitulos[23].versos[47] = wxT("Quando o centurião viu o que acontecera, deu glória a Deus, dizendo: Na verdade, este homem era justo.");
    b->dados[LUCAS].capitulos[23].versos[48] = wxT("E todas as multidões que presenciaram este espetáculo, vendo o que havia acontecido, voltaram batendo no peito.");
    b->dados[LUCAS].capitulos[23].versos[49] = wxT("Entretanto, todos os conhecidos de Jesus, e as mulheres que o haviam seguido desde a Galiléia, estavam de longe vendo estas coisas.");
    b->dados[LUCAS].capitulos[23].versos[50] = wxT("Então um homem chamado José, natural de Arimatéia, cidade dos judeus, membro do sinédrio, homem bom e justo,");
    b->dados[LUCAS].capitulos[23].versos[51] = wxT("o qual não tinha consentido no conselho e nos atos dos outros, e que esperava o reino de Deus,");
    b->dados[LUCAS].capitulos[23].versos[52] = wxT("chegando a Pilatos, pediu-lhe o corpo de Jesus;");
    b->dados[LUCAS].capitulos[23].versos[53] = wxT("e tirando-o da cruz, envolveu-o num pano de linho, e pô-lo num sepulcro escavado em rocha, onde ninguém ainda havia sido posto.");
    b->dados[LUCAS].capitulos[23].versos[54] = wxT("Era o dia da preparação, e ia começar o sábado.");
    b->dados[LUCAS].capitulos[23].versos[55] = wxT("E as mulheres que tinham vindo com ele da Galiléia, seguindo a José, viram o sepulcro, e como o corpo foi ali depositado.");
    b->dados[LUCAS].capitulos[23].versos[56] = wxT("Então voltaram e prepararam especiarias e ungüentos. E no sábado repousaram, conforme o mandamento.");

    b->dados[LUCAS].capitulos[24].versos[1] = wxT("Mas já no primeiro dia da semana, bem de madrugada, foram elas ao sepulcro, levando as especiarias que tinham preparado.");
    b->dados[LUCAS].capitulos[24].versos[2] = wxT("E acharam a pedra revolvida do sepulcro.");
    b->dados[LUCAS].capitulos[24].versos[3] = wxT("Entrando, porém, não acharam o corpo do Senhor Jesus.");
    b->dados[LUCAS].capitulos[24].versos[4] = wxT("E, estando elas perplexas a esse respeito, eis que lhes apareceram dois varões em vestes resplandecentes;");
    b->dados[LUCAS].capitulos[24].versos[5] = wxT("e ficando elas atemorizadas e abaixando o rosto para o chão, eles lhes disseram: Por que buscais entre os mortos aquele que vive?");
    b->dados[LUCAS].capitulos[24].versos[6] = wxT("Ele não está aqui, mas ressurgiu. Lembrai-vos de como vos falou, estando ainda na Galiléia.");
    b->dados[LUCAS].capitulos[24].versos[7] = wxT("dizendo: Importa que o Filho do homem seja entregue nas mãos de homens pecadores, e seja crucificado, e ao terceiro dia ressurja.");
    b->dados[LUCAS].capitulos[24].versos[8] = wxT("Lembraram-se, então, das suas palavras;");
    b->dados[LUCAS].capitulos[24].versos[9] = wxT("e, voltando do sepulcro, anunciaram todas estas coisas aos onze e a todos os demais.");
    b->dados[LUCAS].capitulos[24].versos[10] = wxT("E eram Maria Madalena, e Joana, e Maria, mãe de Tiago; também as outras que estavam com elas relataram estas coisas aos apóstolos.");
    b->dados[LUCAS].capitulos[24].versos[11] = wxT("E pareceram-lhes como um delírio as palavras das mulheres e não lhes deram crédito.");
    b->dados[LUCAS].capitulos[24].versos[12] = wxT("Mas Pedro, levantando-se, correu ao sepulcro; e, abaixando-se, viu somente os panos de linho; e retirou-se, admirando consigo o que havia acontecido.");
    b->dados[LUCAS].capitulos[24].versos[13] = wxT("Nesse mesmo dia, iam dois deles para uma aldeia chamada Emaús, que distava de Jerusalém sessenta estádios;");
    b->dados[LUCAS].capitulos[24].versos[14] = wxT("e iam comentando entre si tudo aquilo que havia sucedido.");
    b->dados[LUCAS].capitulos[24].versos[15] = wxT("Enquanto assim comentavam e discutiam, o próprio Jesus se aproximou, e ia com eles;");
    b->dados[LUCAS].capitulos[24].versos[16] = wxT("mas os olhos deles estavam como que fechados, de sorte que não o reconheceram.");
    b->dados[LUCAS].capitulos[24].versos[17] = wxT("Então ele lhes perguntou: Que palavras são essas que, caminhando, trocais entre vós? Eles então pararam tristes.");
    b->dados[LUCAS].capitulos[24].versos[18] = wxT("E um deles, chamado Cleopas, respondeu-lhe: És tu o único peregrino em Jerusalém que não soube das coisas que nela têm sucedido nestes dias?");
    b->dados[LUCAS].capitulos[24].versos[19] = wxT("Ao que ele lhes perguntou: Quais? Disseram-lhe: As que dizem respeito a Jesus, o nazareno, que foi profeta, poderoso em obras e palavras diante de Deus e de todo o povo.");
    b->dados[LUCAS].capitulos[24].versos[20] = wxT("e como os principais sacerdotes e as nossas autoridades e entregaram para ser condenado à morte, e o crucificaram.");
    b->dados[LUCAS].capitulos[24].versos[21] = wxT("Ora, nós esperávamos que fosse ele quem havia de remir Israel; e, além de tudo isso, é já hoje o terceiro dia desde que essas coisas aconteceram.");
    b->dados[LUCAS].capitulos[24].versos[22] = wxT("Verdade é, também, que algumas mulheres do nosso meio nos encheram de espanto; pois foram de madrugada ao sepulcro");
    b->dados[LUCAS].capitulos[24].versos[23] = wxT("e, não achando o corpo dele voltaram, declarando que tinham tido uma visão de anjos que diziam estar ele vivo.");
    b->dados[LUCAS].capitulos[24].versos[24] = wxT("Além disso, alguns dos que estavam conosco foram ao sepulcro, e acharam ser assim como as mulheres haviam dito; a ele, porém, não o viram.");
    b->dados[LUCAS].capitulos[24].versos[25] = wxT("Então ele lhes disse: ó néscios, e tardos de coração para crerdes tudo o que os profetas disseram!");
    b->dados[LUCAS].capitulos[24].versos[26] = wxT("Porventura não importa que o Cristo padecesse essas coisas e entrasse na sua glória?");
    b->dados[LUCAS].capitulos[24].versos[27] = wxT("E, começando por Moisés, e por todos os profetas, explicou-lhes o que dele se achava em todas as Escrituras.");
    b->dados[LUCAS].capitulos[24].versos[28] = wxT("Quando se aproximaram da aldeia para onde iam, ele fez como quem ia para mais longe.");
    b->dados[LUCAS].capitulos[24].versos[29] = wxT("Eles, porém, o constrangeram, dizendo: Fica conosco; porque é tarde, e já declinou o dia. E entrou para ficar com eles.");
    b->dados[LUCAS].capitulos[24].versos[30] = wxT("Estando com eles à mesa, tomou o pão e o abençoou; e, partindo-o, lho dava.");
    b->dados[LUCAS].capitulos[24].versos[31] = wxT("Abriram-se-lhes então os olhos, e o reconheceram; nisto ele desapareceu de diante deles.");
    b->dados[LUCAS].capitulos[24].versos[32] = wxT("E disseram um para o outro: Porventura não se nos abrasava o coração, quando pelo caminho nos falava, e quando nos abria as Escrituras?");
    b->dados[LUCAS].capitulos[24].versos[33] = wxT("E na mesma hora levantaram-se e voltaram para Jerusalém, e encontraram reunidos os onze e os que estavam com eles,");
    b->dados[LUCAS].capitulos[24].versos[34] = wxT("os quais diziam: Realmente o Senhor ressurgiu, e apareceu a Simão.");
    b->dados[LUCAS].capitulos[24].versos[35] = wxT("Então os dois contaram o que acontecera no caminho, e como se lhes fizera conhecer no partir do pão.");
    b->dados[LUCAS].capitulos[24].versos[36] = wxT("Enquanto ainda falavam nisso, o próprio Jesus se apresentou no meio deles, e disse-lhes: Paz seja convosco.");
    b->dados[LUCAS].capitulos[24].versos[37] = wxT("Mas eles, espantados e atemorizados, pensavam que viam algum espírito.");
    b->dados[LUCAS].capitulos[24].versos[38] = wxT("Ele, porém, lhes disse: Por que estais perturbados? e por que surgem dúvidas em vossos corações?");
    b->dados[LUCAS].capitulos[24].versos[39] = wxT("Olhai as minhas mãos e os meus pés, que sou eu mesmo; apalpai-me e vede; porque um espírito não tem carne nem ossos, como percebeis que eu tenho.");
    b->dados[LUCAS].capitulos[24].versos[40] = wxT("E, dizendo isso, mostrou-lhes as mãos e os pés.");
    b->dados[LUCAS].capitulos[24].versos[41] = wxT("Não acreditando eles ainda por causa da alegria, e estando admirados, perguntou-lhes Jesus: Tendes aqui alguma coisa que comer?");
    b->dados[LUCAS].capitulos[24].versos[42] = wxT("Então lhe deram um pedaço de peixe assado,");
    b->dados[LUCAS].capitulos[24].versos[43] = wxT("o qual ele tomou e comeu diante deles.");
    b->dados[LUCAS].capitulos[24].versos[44] = wxT("Depois lhe disse: São estas as palavras que vos falei, estando ainda convosco, que importava que se cumprisse tudo o que de mim estava escrito na Lei de Moisés, nos Profetas e nos Salmos.");
    b->dados[LUCAS].capitulos[24].versos[45] = wxT("Então lhes abriu o entendimento para compreenderem as Escrituras;");
    b->dados[LUCAS].capitulos[24].versos[46] = wxT("e disse-lhes: Assim está escrito que o Cristo padecesse, e ao terceiro dia ressurgisse dentre os mortos;");
    b->dados[LUCAS].capitulos[24].versos[47] = wxT("e que em seu nome se pregasse o arrependimento para remissão dos pecados, a todas as nações, começando por Jerusalém.");
    b->dados[LUCAS].capitulos[24].versos[48] = wxT("Vós sois testemunhas destas coisas.");
    b->dados[LUCAS].capitulos[24].versos[49] = wxT("E eis que sobre vós envio a promessa de meu Pai; ficai porém, na cidade, até que do alto sejais revestidos de poder.");
    b->dados[LUCAS].capitulos[24].versos[50] = wxT("Então os levou fora, até Betânia; e levantando as mãos, os abençoou.");
    b->dados[LUCAS].capitulos[24].versos[51] = wxT("E aconteceu que, enquanto os abençoava, apartou-se deles; e foi elevado ao céu.");
    b->dados[LUCAS].capitulos[24].versos[52] = wxT("E, depois de o adorarem, voltaram com grande júbilo para Jerusalém;");
    b->dados[LUCAS].capitulos[24].versos[53] = wxT("e estavam continuamente no templo, bendizendo a Deus.");

}
